import type { CareerQuestion } from "./rrt-questions";

export const ptaQuestions: CareerQuestion[] = [
  { id: "pta-001", stem: "A patient is 3 days post posterior approach total hip replacement. Which position must be AVOIDED?", options: ["Hip abduction with pillow between legs", "Hip flexion to 70° during seated activities", "Hip flexion >90° with internal rotation and adduction", "Ankle dorsiflexion exercises in supine"], correctIndex: 2, rationale: "Posterior approach THR precautions: no hip flexion >90°, no adduction past midline, no internal rotation. These combined movements risk posterior dislocation of the prosthesis.", difficulty: 2, category: "Clinical Scenarios", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-002", stem: "A patient is non-weight-bearing on the left lower extremity. Which gait pattern with axillary crutches is appropriate?", options: ["4-point alternating gait", "2-point alternating gait", "3-point gait pattern", "Swing-to pattern without crutches"], correctIndex: 2, rationale: "The 3-point gait pattern is used for NWB: both crutches advance with the affected limb (no weight on it), then the unaffected limb steps through independently.", difficulty: 2, category: "Clinical Scenarios", topic: "Assistive Devices" },
  { id: "pta-003", stem: "Using the DeLorme PRE protocol, a patient's 10RM is 30 pounds. What resistance is used for Set 2?", options: ["10 pounds", "15 pounds", "22.5 pounds (75% of 10RM)", "30 pounds"], correctIndex: 2, rationale: "DeLorme PRE: Set 1 = 50% of 10RM (15 lbs), Set 2 = 75% of 10RM (22.5 lbs), Set 3 = 100% of 10RM (30 lbs). The protocol uses ascending resistance.", difficulty: 2, category: "Therapeutic Intervention", topic: "Therapeutic Exercise" },
  { id: "pta-004", stem: "A patient with T6 SCI suddenly develops severe headache, hypertension (BP 220/130), and flushing above the injury level. What should the PTA do FIRST?", options: ["Continue treatment to maintain cardiovascular fitness", "Position the patient supine and elevate legs", "Sit the patient upright immediately and check for noxious stimuli", "Administer prescribed antihypertensive medication"], correctIndex: 2, rationale: "These symptoms indicate autonomic dysreflexia — a life-threatening emergency. Sit the patient upright (lowers BP), check for noxious stimuli (kinked catheter, tight clothing), and notify medical team.", difficulty: 3, category: "Safety", topic: "Neurological Rehabilitation" },
  { id: "pta-005", stem: "A patient scores 38 on the Berg Balance Scale. What does this score indicate?", options: ["Normal balance with no intervention needed", "Fall risk — patient requires assistive device and balance intervention", "Wheelchair-bound — unable to ambulate", "Superior balance function"], correctIndex: 1, rationale: "BBS <45 indicates fall risk; <36 indicates high fall risk. A score of 38 suggests the patient needs an assistive device and a balance training program.", difficulty: 2, category: "Clinical Scenarios", topic: "Geriatric Rehabilitation" },
  { id: "pta-006", stem: "Where should the axillary crutch pad be positioned relative to the axilla?", options: ["Firmly pressed into the axilla for support", "2-3 finger widths below the axilla", "At the level of the shoulder", "4-5 inches below the axilla"], correctIndex: 1, rationale: "The pad should be 2-3 finger widths below the axilla. Weight is borne through the hands, not the axillary pads, to prevent radial nerve compression (crutch palsy).", difficulty: 1, category: "Safety", topic: "Assistive Devices" },
  { id: "pta-007", stem: "A patient with right hemiplegia needs to transfer from wheelchair to bed. Where should the wheelchair be positioned?", options: ["On the patient's right (affected) side", "On the patient's left (unaffected) side", "Directly facing the bed", "At the foot of the bed"], correctIndex: 1, rationale: "Position the wheelchair on the unaffected (left) side. The patient leads the stand-pivot transfer with the stronger left leg, providing stability during the pivot.", difficulty: 2, category: "Patient Care Planning", topic: "Patient Mobility Techniques" },
  { id: "pta-008", stem: "A patient reports an RPE of 17 on the Borg scale during aerobic exercise. What is the appropriate PTA action?", options: ["Increase intensity for greater training effect", "Maintain current intensity as this is appropriate", "Decrease intensity — RPE 17 exceeds the moderate training zone", "Stop exercise immediately and call emergency services"], correctIndex: 2, rationale: "RPE 17 ('very hard') exceeds the target moderate intensity range (12-14). The PTA should reduce intensity to return the patient to the prescribed exertion level.", difficulty: 2, category: "Safety", topic: "Therapeutic Exercise" },
  { id: "pta-009", stem: "Which orthopedic special test assesses the integrity of the ACL?", options: ["McMurray test", "Phalen test", "Lachman test", "Thompson test"], correctIndex: 2, rationale: "The Lachman test assesses ACL integrity by applying anterior tibial force at 20-30° knee flexion. A positive test shows excessive anterior translation with a soft/absent endpoint.", difficulty: 1, category: "Clinical Scenarios", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-010", stem: "A patient is 6 weeks post-ACL reconstruction. Which exercise is CONTRAINDICATED?", options: ["Closed kinetic chain squats to 60°", "Stationary cycling", "Open kinetic chain knee extension from 45° to 0°", "Straight leg raises"], correctIndex: 2, rationale: "OKC knee extension through 45-0° places excessive anterior shear force on the healing ACL graft. CKC exercises are preferred because they create protective posterior tibial translation.", difficulty: 3, category: "Safety", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-011", stem: "A 13-month-old child has not yet started walking. Is this a concern?", options: ["Yes, walking should begin by 9 months", "No, independent walking typically develops between 12-15 months", "Yes, the child needs immediate surgical intervention", "No, walking is not expected until age 3"], correctIndex: 1, rationale: "Independent walking typically develops between 12-15 months. At 13 months, the child is within the normal developmental window and may not yet be developmentally ready.", difficulty: 1, category: "Clinical Scenarios", topic: "Pediatric Rehabilitation" },
  { id: "pta-012", stem: "A patient using a cane for right knee pain should hold the cane in which hand?", options: ["Right hand (same side as pain)", "Left hand (opposite side of pain)", "Either hand based on personal preference", "Alternating hands every 10 steps"], correctIndex: 1, rationale: "The cane is held on the opposite side of the affected LE. This creates a wider base of support and counterbalances forces to reduce load on the painful side.", difficulty: 1, category: "Patient Care Planning", topic: "Assistive Devices" },
  { id: "pta-013", stem: "During gait observation, a patient demonstrates lateral trunk lean over the right leg during right stance phase. Which muscle is likely weak?", options: ["Right quadriceps", "Right gluteus medius", "Right hamstrings", "Right tibialis anterior"], correctIndex: 1, rationale: "Lateral trunk lean toward the stance leg (compensated Trendelenburg) indicates gluteus medius weakness. The trunk lean shifts the center of gravity over the stance leg to compensate.", difficulty: 2, category: "Clinical Scenarios", topic: "Neurological Rehabilitation" },
  { id: "pta-014", stem: "Which type of muscle contraction generates force WITHOUT joint movement?", options: ["Concentric isotonic", "Eccentric isotonic", "Isometric", "Isokinetic"], correctIndex: 2, rationale: "Isometric contraction produces muscle force without joint movement or change in muscle length. It is used when joint motion is contraindicated, such as during immobilization.", difficulty: 1, category: "Therapeutic Intervention", topic: "Therapeutic Exercise" },
  { id: "pta-015", stem: "A patient has a Timed Up and Go (TUG) score of 22 seconds. What does this indicate?", options: ["Normal mobility for all ages", "Freely mobile without limitations", "Variable mobility with increased fall risk", "Complete independence in all mobility tasks"], correctIndex: 2, rationale: "TUG 20-30 seconds indicates variable mobility. The patient may require an assistive device and has increased fall risk. Further balance and gait assessment is warranted.", difficulty: 2, category: "Clinical Scenarios", topic: "Geriatric Rehabilitation" },
  { id: "pta-016", stem: "A patient is performing a sliding board transfer. What is the MOST important safety check before the transfer?", options: ["Check that the patient is wearing proper footwear", "Lock wheelchair brakes, remove armrest, and position the board correctly", "Ensure the room temperature is comfortable", "Check that the bed is made properly"], correctIndex: 1, rationale: "Before a sliding board transfer, wheelchair brakes must be locked, the near armrest removed, and the board properly positioned bridging both surfaces to prevent falls.", difficulty: 1, category: "Safety", topic: "Patient Mobility Techniques" },
  { id: "pta-017", stem: "Which PNF diagonal pattern involves upper extremity flexion, adduction, and external rotation?", options: ["D1 flexion", "D1 extension", "D2 flexion", "D2 extension"], correctIndex: 0, rationale: "D1 flexion: flexion, adduction, external rotation with forearm supination. This mimics reaching across the body to the opposite shoulder.", difficulty: 3, category: "Therapeutic Intervention", topic: "Neurological Rehabilitation" },
  { id: "pta-018", stem: "A 75-year-old patient with osteoporosis asks about safe exercises. Which should the PTA AVOID recommending?", options: ["Walking program", "Standing hip extension exercises", "Seated trunk flexion (crunches/sit-ups)", "Standing posture exercises emphasizing extension"], correctIndex: 2, rationale: "Spinal flexion exercises increase compressive forces on anterior vertebral bodies, increasing fracture risk in osteoporosis. Weight-bearing and extension exercises are preferred.", difficulty: 2, category: "Safety", topic: "Geriatric Rehabilitation" },
  { id: "pta-019", stem: "What is the PRIMARY role of the PTA in patient care?", options: ["Perform initial evaluations and establish physical therapy diagnoses", "Implement interventions within the PT-established plan of care", "Independently modify the plan of care and discharge patients", "Prescribe medications for pain management"], correctIndex: 1, rationale: "The PTA implements interventions within the plan of care established by the supervising PT. Initial evaluation, diagnosis, prognosis, and discharge decisions are PT responsibilities.", difficulty: 1, category: "Patient Care Planning", topic: "Rehabilitation Principles" },
  { id: "pta-020", stem: "A patient is performing static stretching of the hamstrings. How long should the stretch be held for optimal gains?", options: ["5 seconds", "10 seconds", "30 seconds", "5 minutes"], correctIndex: 2, rationale: "Research supports holding static stretches for 30 seconds for optimal flexibility gains. No significant additional benefit has been shown beyond 30-second holds in most populations.", difficulty: 1, category: "Therapeutic Intervention", topic: "Therapeutic Exercise" },
  { id: "pta-021", stem: "A patient with spastic diplegic cerebral palsy is classified as GMFCS Level III. What does this indicate?", options: ["Walks without limitations", "Walks with limitations but no device needed", "Walks using a handheld mobility device", "Requires powered wheelchair for all mobility"], correctIndex: 2, rationale: "GMFCS Level III: walks using a handheld mobility device (walker, crutches). May use wheeled mobility for longer distances or uneven terrain.", difficulty: 2, category: "Clinical Scenarios", topic: "Pediatric Rehabilitation" },
  { id: "pta-022", stem: "The PTA is measuring shoulder flexion ROM using a goniometer. The axis of the goniometer should be placed at which anatomical landmark?", options: ["Lateral epicondyle of the humerus", "Acromion process", "Olecranon process", "Coracoid process"], correctIndex: 1, rationale: "For shoulder flexion goniometry, the axis is placed at the acromion process, the stationary arm aligns with the midaxillary line, and the moving arm with the lateral humerus.", difficulty: 2, category: "Clinical Scenarios", topic: "Therapeutic Exercise" },
  { id: "pta-023", stem: "A patient's systolic blood pressure rises to 260 mmHg during exercise. What is the appropriate PTA action?", options: ["Continue exercise at a reduced pace", "Stop exercise immediately and monitor the patient", "Increase exercise intensity to improve cardiovascular fitness", "Have the patient perform relaxation breathing and continue"], correctIndex: 1, rationale: "Exercise should be stopped immediately if SBP exceeds 250 mmHg or DBP exceeds 115 mmHg. These values indicate dangerous hypertensive response requiring medical attention.", difficulty: 2, category: "Safety", topic: "Therapeutic Exercise" },
  { id: "pta-024", stem: "A patient with a 3-month-old right torticollis is referred for PT. Which muscle is tight?", options: ["Left sternocleidomastoid", "Right sternocleidomastoid", "Bilateral upper trapezius", "Left scalene"], correctIndex: 1, rationale: "In right torticollis, the right SCM is tight, causing head tilt toward the right and chin rotation toward the left. Treatment stretches the right SCM and strengthens the left.", difficulty: 2, category: "Clinical Scenarios", topic: "Pediatric Rehabilitation" },
  { id: "pta-025", stem: "Which gait pattern with crutches is the MOST stable?", options: ["Swing-through", "2-point alternating", "4-point alternating", "3-point"], correctIndex: 2, rationale: "The 4-point alternating gait (right crutch → left foot → left crutch → right foot) is the most stable because 3 points of contact are always on the ground.", difficulty: 1, category: "Patient Care Planning", topic: "Assistive Devices" },
  { id: "pta-026", stem: "During stair training, a patient with right knee injury using crutches should go UP stairs leading with which leg?", options: ["Right (affected) leg first", "Left (unaffected) leg first", "Both legs simultaneously", "Either leg — it doesn't matter"], correctIndex: 1, rationale: "'Up with the good' — the unaffected (left) leg leads going up stairs, pushing the body weight up with the stronger leg. Then the crutches and affected leg follow.", difficulty: 1, category: "Patient Care Planning", topic: "Assistive Devices" },
  { id: "pta-027", stem: "A patient recovering from stroke is in Brunnstrom Stage 4 of motor recovery. What characterizes this stage?", options: ["Complete flaccidity", "Movement only within synergy patterns", "Voluntary movement begins to emerge outside of synergy", "Near-normal motor control"], correctIndex: 2, rationale: "Brunnstrom Stage 4 marks the beginning of voluntary movement outside stereotypical synergy patterns. The patient can initiate some isolated movements with decreased synergy influence.", difficulty: 3, category: "Clinical Scenarios", topic: "Neurological Rehabilitation" },
  { id: "pta-028", stem: "A patient with moderate spasticity scores 2 on the Modified Ashworth Scale. What does this mean?", options: ["No increase in muscle tone", "Marked increase in tone through most of the ROM, but the limb is easily moved", "Considerable increase in tone; passive movement is difficult", "Limb is rigid in flexion or extension"], correctIndex: 1, rationale: "MAS 2: marked increase in muscle tone through most of the ROM, but the affected part is still easily moved passively. Higher scores (3-4) indicate greater resistance to passive movement.", difficulty: 2, category: "Clinical Scenarios", topic: "Neurological Rehabilitation" },
  { id: "pta-029", stem: "How should the PTA grasp the gait belt during an assisted transfer?", options: ["From the top with palms facing down", "From underneath with palms facing up", "By the buckle only", "By the patient's clothing instead of the belt"], correctIndex: 1, rationale: "The gait belt is grasped from underneath with palms up. This grip provides optimal control and leverage to safely guide the patient downward if they begin to fall.", difficulty: 1, category: "Safety", topic: "Patient Mobility Techniques" },
  { id: "pta-030", stem: "A patient is 2 weeks post-rotator cuff repair. Which exercise is appropriate?", options: ["Active shoulder elevation to 180°", "Passive ROM within surgeon's protocol", "Resistive shoulder strengthening with weights", "Overhead throwing exercises"], correctIndex: 1, rationale: "At 2 weeks post-rotator cuff repair, only passive ROM within the surgeon's protocol is appropriate. Active shoulder motion is typically restricted for 6 weeks to protect the repair.", difficulty: 2, category: "Therapeutic Intervention", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-031", stem: "The 30-second chair stand test result for an older adult is 6 repetitions. What does this indicate?", options: ["Excellent lower extremity strength", "Normal functional strength for older adults", "Below normal — indicates fall risk (fewer than 8 = fall risk)", "Superior performance requiring no intervention"], correctIndex: 2, rationale: "Fewer than 8 chair stands in 30 seconds indicates functional lower extremity weakness and increased fall risk in older adults. Strengthening intervention is warranted.", difficulty: 2, category: "Clinical Scenarios", topic: "Geriatric Rehabilitation" },
  { id: "pta-032", stem: "Which therapeutic modality uses sound waves to produce deep tissue heating?", options: ["TENS", "Cryotherapy", "Therapeutic ultrasound", "Moist hot packs"], correctIndex: 2, rationale: "Therapeutic ultrasound uses high-frequency sound waves to produce deep tissue heating (thermal effects at continuous mode) and promote tissue healing (non-thermal effects at pulsed mode).", difficulty: 1, category: "Therapeutic Intervention", topic: "Therapeutic Exercise" },
  { id: "pta-033", stem: "A patient with Parkinson's disease demonstrates a shuffling, festinating gait. Which intervention is MOST appropriate?", options: ["Leg weights to slow the gait speed", "External auditory cues (metronome) and visual cues (floor lines) to improve step length", "Walking backward exclusively", "Restricting all ambulation to prevent falls"], correctIndex: 1, rationale: "External cues (auditory rhythmic cues and visual targets) help patients with Parkinson's overcome akinesia and improve step length, cadence, and gait quality.", difficulty: 2, category: "Therapeutic Intervention", topic: "Neurological Rehabilitation" },
  { id: "pta-034", stem: "Which weight-bearing status means the patient can put ONLY the toe on the ground for balance, not for support?", options: ["Non-weight-bearing (NWB)", "Toe-touch weight-bearing (TTWB)", "Partial weight-bearing (PWB)", "Full weight-bearing (FWB)"], correctIndex: 1, rationale: "TTWB allows only toe contact with the floor for balance — no actual weight transfer through the affected extremity. It provides tactile feedback without structural loading.", difficulty: 1, category: "Patient Care Planning", topic: "Assistive Devices" },
  { id: "pta-035", stem: "A patient with SCI at C5 level can be expected to achieve which functional activity?", options: ["Independent ambulation", "Self-feeding with adaptive equipment and setup assistance", "Independent transfers without equipment", "Independent wheelchair propulsion on all surfaces"], correctIndex: 1, rationale: "C5 SCI preserves deltoid and biceps. With mobile arm supports and adaptive equipment (universal cuff), the patient can self-feed with setup but requires assistance for most other activities.", difficulty: 2, category: "Patient Care Planning", topic: "Neurological Rehabilitation" },
  { id: "pta-036", stem: "During balance training, which progression sequence correctly increases challenge?", options: ["Dynamic → Static → Eyes closed → Unstable surface", "Stable surface/eyes open → Stable surface/eyes closed → Unstable surface/eyes open → Unstable surface/eyes closed", "Single-leg stance → Bilateral stance → Sitting balance", "Unstable surface first → Add support last"], correctIndex: 1, rationale: "Balance training progresses by systematically removing sensory input and reducing base stability: stable/eyes open → stable/eyes closed → unstable/eyes open → unstable/eyes closed.", difficulty: 2, category: "Therapeutic Intervention", topic: "Therapeutic Exercise" },
  { id: "pta-037", stem: "A child with cerebral palsy receives botulinum toxin injection to the gastrocnemius. What should the PTA do during the 'window' of reduced tone?", options: ["Rest the muscle completely for 3 months", "Intensify stretching, strengthening, and functional training while tone is reduced", "Discontinue physical therapy until the injection wears off", "Apply ice to the injection site daily"], correctIndex: 1, rationale: "Botox effects last 3-6 months. The PTA should capitalize on reduced spasticity by intensifying stretching, strengthening, and functional gait training during this therapeutic window.", difficulty: 3, category: "Therapeutic Intervention", topic: "Pediatric Rehabilitation" },
  { id: "pta-038", stem: "The Thompson test is used to assess the integrity of which structure?", options: ["Anterior cruciate ligament", "Meniscus", "Achilles tendon", "Rotator cuff"], correctIndex: 2, rationale: "The Thompson test (calf squeeze test) assesses Achilles tendon integrity. Squeezing the calf should produce plantar flexion; absence of plantar flexion indicates Achilles tendon rupture.", difficulty: 2, category: "Clinical Scenarios", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-039", stem: "A patient with COPD is performing aerobic exercise. Which monitoring tool should the PTA use to assess exertion intensity?", options: ["Glasgow Coma Scale", "Borg Rating of Perceived Exertion (RPE) scale", "Allen Cognitive Level Screen", "Modified Ashworth Scale"], correctIndex: 1, rationale: "The Borg RPE scale (6-20) allows patients to self-report exercise intensity. Target moderate intensity is RPE 12-14 ('somewhat hard'). It correlates approximately with HR ÷ 10.", difficulty: 1, category: "Patient Care Planning", topic: "Therapeutic Exercise" },
  { id: "pta-040", stem: "How often should a wheelchair-bound patient perform pressure-relieving weight shifts?", options: ["Once per hour", "Every 15-30 minutes", "Once per day", "Only when experiencing pain"], correctIndex: 1, rationale: "Weight shifts every 15-30 minutes redistribute pressure over bony prominences (ischial tuberosities) to prevent pressure injuries. Methods include forward lean, side lean, and push-ups.", difficulty: 1, category: "Safety", topic: "Patient Mobility Techniques" },
  { id: "pta-041", stem: "Which gait deviation indicates dorsiflexor weakness?", options: ["Trendelenburg gait", "Steppage gait (high stepping)", "Antalgic gait", "Vaulting gait"], correctIndex: 1, rationale: "Steppage gait involves excessive hip and knee flexion during swing phase to clear the foot from the floor. It results from dorsiflexor weakness (foot drop) — tibialis anterior dysfunction.", difficulty: 2, category: "Clinical Scenarios", topic: "Neurological Rehabilitation" },
  { id: "pta-042", stem: "A patient is performing closed kinetic chain exercises for knee rehabilitation. Which exercise is an example of CKC?", options: ["Seated knee extension with ankle weight", "Standing mini-squats", "Prone hamstring curls", "Supine leg lifts"], correctIndex: 1, rationale: "CKC exercises have the distal segment (foot) fixed. Standing mini-squats fix the foot on the ground, creating co-contraction and joint compression that protect the ACL graft.", difficulty: 1, category: "Therapeutic Intervention", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-043", stem: "A patient presents with positive Phalen's and Tinel's tests. Which condition do these tests suggest?", options: ["ACL tear", "Achilles tendon rupture", "Carpal tunnel syndrome", "Rotator cuff tear"], correctIndex: 2, rationale: "Phalen's (sustained wrist flexion reproduces symptoms) and Tinel's (tapping over carpal tunnel reproduces symptoms) are clinical tests for carpal tunnel syndrome (median nerve compression).", difficulty: 2, category: "Clinical Scenarios", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-044", stem: "The PTA is providing gait training to a patient using a standard walker. What is the correct gait sequence?", options: ["Step with both feet, then advance the walker", "Advance the walker, then step with one foot, then the other", "Run toward the walker after placing it", "Advance the walker and hop to it with both feet"], correctIndex: 1, rationale: "Standard walker gait: advance the walker forward, then step with one foot (typically affected foot first), then step with the other foot. The walker provides support during each step.", difficulty: 1, category: "Patient Care Planning", topic: "Assistive Devices" },
  { id: "pta-045", stem: "A patient with osteoporosis has a T-score of -3.0 on DEXA scan. What does this indicate?", options: ["Normal bone density", "Osteopenia", "Osteoporosis", "Above-average bone density"], correctIndex: 2, rationale: "DEXA T-scores: >-1.0 = normal; -1.0 to -2.5 = osteopenia; ≤-2.5 = osteoporosis. A T-score of -3.0 indicates established osteoporosis with significant fracture risk.", difficulty: 2, category: "Clinical Scenarios", topic: "Geriatric Rehabilitation" },
  { id: "pta-046", stem: "During manual muscle testing, a patient can move their knee through full ROM against gravity but cannot tolerate any manual resistance. What is the MMT grade?", options: ["2/5 (Poor)", "3/5 (Fair)", "4/5 (Good)", "5/5 (Normal)"], correctIndex: 1, rationale: "MMT 3/5 (Fair): the patient can move the joint through full available ROM against gravity but cannot hold against any additional manual resistance.", difficulty: 1, category: "Clinical Scenarios", topic: "Therapeutic Exercise" },
  { id: "pta-047", stem: "A patient with heart failure is beginning a cardiac rehabilitation program. Which MET level activity is appropriate for the initial phase?", options: ["1-2 METs (self-care, slow walking)", "5-6 METs (brisk walking, cycling)", "8-10 METs (running, competitive sports)", "12+ METs (sprint activities)"], correctIndex: 0, rationale: "Initial cardiac rehabilitation starts at 1-2 METs (self-care activities, slow walking). Intensity is gradually progressed based on patient tolerance, vital signs, and symptoms.", difficulty: 2, category: "Therapeutic Intervention", topic: "Therapeutic Exercise" },
  { id: "pta-048", stem: "What is the primary advantage of using a rolling walker compared to a standard pick-up walker?", options: ["It provides more stability", "It allows a reciprocal gait pattern with continuous forward motion", "It is less expensive", "It is lighter weight"], correctIndex: 1, rationale: "A rolling walker (wheeled walker) allows continuous forward motion and a more normal reciprocal gait pattern, whereas a standard walker requires stopping to lift and advance.", difficulty: 1, category: "Patient Care Planning", topic: "Assistive Devices" },
  { id: "pta-049", stem: "A patient is performing PNF contract-relax stretching for tight hamstrings. What is the correct sequence?", options: ["Passive stretch → Active contraction of tight muscle → Relax → Passive stretch into new range", "Contract agonist → Stretch agonist → Contract antagonist", "Ballistic bouncing into end range", "Forceful passive stretch without contraction"], correctIndex: 0, rationale: "Contract-relax PNF: passive stretch to end range → patient contracts the tight muscle (hamstring) isometrically → relax → therapist moves the limb into new gained range.", difficulty: 3, category: "Therapeutic Intervention", topic: "Therapeutic Exercise" },
  { id: "pta-050", stem: "A patient demonstrates circumduction gait pattern on the right side during swing phase. What is the likely underlying cause?", options: ["Right hamstring weakness", "Right hip flexor and/or dorsiflexor weakness with spasticity", "Left gluteus medius weakness", "Bilateral ankle plantarflexion contracture"], correctIndex: 1, rationale: "Circumduction gait (leg swings outward in a semicircle during swing) is commonly caused by hip flexor weakness, spasticity, or inability to adequately flex the hip and dorsiflex the ankle.", difficulty: 3, category: "Clinical Scenarios", topic: "Neurological Rehabilitation" },
  { id: "pta-051", stem: "The PTA is assessing wound healing. A wound with red, beefy granulation tissue indicates which healing phase?", options: ["Inflammatory phase", "Proliferative phase", "Hemostasis phase", "Maturation/remodeling phase"], correctIndex: 1, rationale: "Red, beefy granulation tissue is characteristic of the proliferative phase, indicating good blood supply and active tissue formation. This is a sign of healthy wound healing.", difficulty: 2, category: "Clinical Scenarios", topic: "Rehabilitation Principles" },
  { id: "pta-052", stem: "Therapeutic ultrasound is CONTRAINDICATED over which area?", options: ["Quadriceps muscle belly", "Lateral epicondyle of the elbow", "Epiphyseal growth plates in children", "Gastrocnemius-soleus complex"], correctIndex: 2, rationale: "Ultrasound is contraindicated over active epiphyseal growth plates in children because the thermal and mechanical effects may damage the growth plate and affect bone development.", difficulty: 2, category: "Safety", topic: "Therapeutic Exercise" },
  { id: "pta-053", stem: "A patient with stroke has difficulty initiating movement on the affected side. Which neurological treatment approach uses handling techniques to normalize tone and facilitate movement?", options: ["McKenzie method", "Williams flexion exercises", "Neurodevelopmental treatment (NDT/Bobath)", "Maitland joint mobilization"], correctIndex: 2, rationale: "NDT/Bobath uses therapeutic handling techniques to inhibit abnormal tone/postures and facilitate normal movement patterns and postural reactions in neurological patients.", difficulty: 2, category: "Therapeutic Intervention", topic: "Neurological Rehabilitation" },
  { id: "pta-054", stem: "At what age do most children begin to crawl?", options: ["2-3 months", "4-5 months", "8-10 months", "14-16 months"], correctIndex: 2, rationale: "Crawling typically develops between 8-10 months. This milestone requires adequate UE strength, trunk stability, and reciprocal limb coordination.", difficulty: 1, category: "Clinical Scenarios", topic: "Pediatric Rehabilitation" },
  { id: "pta-055", stem: "A patient has a Stage III pressure injury over the sacrum. What depth of tissue damage does this represent?", options: ["Intact skin with non-blanchable redness", "Partial thickness involving epidermis and dermis", "Full thickness with subcutaneous tissue visible", "Full thickness extending into muscle or bone"], correctIndex: 2, rationale: "Stage III pressure injury: full-thickness skin loss with subcutaneous fat visible. Bone, tendon, and muscle are not exposed (that would be Stage IV).", difficulty: 2, category: "Clinical Scenarios", topic: "Rehabilitation Principles" },
  { id: "pta-056", stem: "A patient is performing isokinetic exercise on a Biodex machine. What is unique about isokinetic exercise?", options: ["It only allows isometric contractions", "It provides accommodating resistance at a constant speed throughout the ROM", "It uses only body weight for resistance", "It does not involve muscle contraction"], correctIndex: 1, rationale: "Isokinetic exercise provides accommodating resistance at a fixed, pre-set speed. The machine matches resistance to the patient's force output throughout the entire ROM.", difficulty: 2, category: "Therapeutic Intervention", topic: "Therapeutic Exercise" },
  { id: "pta-057", stem: "A patient undergoes total knee replacement. What is the ROM goal for knee flexion?", options: ["0-60° flexion", "0-90° flexion", "0-120° flexion", "0-150° flexion"], correctIndex: 2, rationale: "The functional ROM goal after TKR is typically 0° extension to 120° flexion. This allows stair climbing (≈110°), sitting/rising from a chair (≈90°), and most daily activities.", difficulty: 2, category: "Patient Care Planning", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-058", stem: "Which type of electrical stimulation is used to manage acute and chronic pain by modulating the pain gate mechanism?", options: ["NMES (Neuromuscular Electrical Stimulation)", "TENS (Transcutaneous Electrical Nerve Stimulation)", "IFC (Interferential Current)", "Russian Stimulation"], correctIndex: 1, rationale: "TENS uses low-level electrical current to stimulate sensory nerves, activating the pain gate mechanism (gate control theory) to reduce pain perception.", difficulty: 1, category: "Therapeutic Intervention", topic: "Therapeutic Exercise" },
  { id: "pta-059", stem: "A patient has been on bedrest for 2 weeks. Upon standing for the first time, their blood pressure drops from 130/80 to 90/60 mmHg with dizziness. What is this condition?", options: ["Hypertensive crisis", "Orthostatic hypotension", "Cardiac arrest", "Vasovagal response"], correctIndex: 1, rationale: "Orthostatic hypotension is a drop in SBP ≥20 mmHg or DBP ≥10 mmHg when moving from supine/sitting to standing. It is common after prolonged bedrest due to deconditioning of baroreceptor reflexes.", difficulty: 1, category: "Clinical Scenarios", topic: "Rehabilitation Principles" },
  { id: "pta-060", stem: "Which aquatic therapy principle explains why a patient feels lighter in the pool?", options: ["Viscosity", "Hydrostatic pressure", "Buoyancy", "Specific gravity"], correctIndex: 2, rationale: "Buoyancy (Archimedes' principle) creates an upward force that counteracts gravity, reducing apparent body weight. At waist depth, a patient bears approximately 50% of body weight.", difficulty: 1, category: "Therapeutic Intervention", topic: "Therapeutic Exercise" },
  { id: "pta-061", stem: "A patient with peripheral neuropathy in the feet has decreased sensation. What is the PRIMARY safety concern?", options: ["Difficulty with fine motor tasks", "Risk of undetected skin injuries and burns", "Increased appetite", "Excessive sweating"], correctIndex: 1, rationale: "Decreased sensation increases risk of undetected injuries, burns, and skin breakdown. The PTA should educate the patient to visually inspect feet daily and avoid extreme temperatures.", difficulty: 1, category: "Safety", topic: "Neurological Rehabilitation" },
  { id: "pta-062", stem: "A patient with McKenzie extension preference for low back pain. What exercise is indicated?", options: ["Williams flexion exercises (posterior pelvic tilt, knee to chest)", "Prone press-ups and standing extension", "Sit-ups and crunches", "Prolonged sitting in flexed posture"], correctIndex: 1, rationale: "McKenzie extension preference indicates symptoms are reduced or centralized with extension. Prone press-ups and standing extension are indicated to reduce symptoms and centralize pain.", difficulty: 2, category: "Therapeutic Intervention", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-063", stem: "The PTA notices a patient's gait shows excessive knee hyperextension during stance phase. Which muscle group is likely weak?", options: ["Hip abductors", "Quadriceps", "Ankle plantarflexors", "Trunk extensors"], correctIndex: 1, rationale: "Knee hyperextension (genu recurvatum) during stance often compensates for quadriceps weakness. The patient locks the knee in hyperextension for stability instead of using quad control.", difficulty: 2, category: "Clinical Scenarios", topic: "Neurological Rehabilitation" },
  { id: "pta-064", stem: "During wound care, which type of debridement involves the use of wet-to-dry dressings?", options: ["Surgical/sharp debridement", "Mechanical debridement", "Enzymatic debridement", "Autolytic debridement"], correctIndex: 1, rationale: "Wet-to-dry dressings are a form of mechanical debridement. The moist gauze adheres to necrotic tissue as it dries; removal pulls off the necrotic tissue with the dressing.", difficulty: 2, category: "Therapeutic Intervention", topic: "Rehabilitation Principles" },
  { id: "pta-065", stem: "A patient is performing a 6-Minute Walk Test (6MWT). What does this test assess?", options: ["Maximum sprint speed", "Functional aerobic/cardiovascular endurance", "Unilateral lower extremity strength", "Upper extremity coordination"], correctIndex: 1, rationale: "The 6MWT measures functional cardiovascular endurance by recording the distance walked in 6 minutes at a self-selected pace. It is a reliable measure of submaximal exercise capacity.", difficulty: 1, category: "Clinical Scenarios", topic: "Geriatric Rehabilitation" },
  { id: "pta-066", stem: "A patient with MS experiences worsening symptoms when body temperature increases. What is this called?", options: ["Babinski sign", "Uhthoff's phenomenon", "Lhermitte's sign", "Romberg sign"], correctIndex: 1, rationale: "Uhthoff's phenomenon is the temporary worsening of MS symptoms with increased body temperature (exercise, hot baths, fever). The PTA should use cooling strategies and avoid overheating.", difficulty: 3, category: "Clinical Scenarios", topic: "Neurological Rehabilitation" },
  { id: "pta-067", stem: "Which ankle-foot orthosis (AFO) holds the ankle at 90° to prevent foot drop during gait?", options: ["Knee-ankle-foot orthosis (KAFO)", "Solid/rigid AFO", "Reciprocal gait orthosis (RGO)", "Hip-knee-ankle-foot orthosis (HKAFO)"], correctIndex: 1, rationale: "A solid/rigid AFO maintains the ankle at 90° (neutral dorsiflexion), preventing toe drag during swing phase and providing stability during stance in patients with dorsiflexor weakness.", difficulty: 1, category: "Patient Care Planning", topic: "Assistive Devices" },
  { id: "pta-068", stem: "A patient is performing body-weight-supported treadmill training (BWSTT) for gait retraining after stroke. What is the primary benefit?", options: ["It eliminates the need for physical therapy", "It allows repetitive practice of the gait cycle with reduced weight-bearing demands", "It replaces all other forms of exercise", "It only works for upper extremity rehabilitation"], correctIndex: 1, rationale: "BWSTT reduces gravitational demands through a harness system, enabling repetitive, task-specific gait practice that promotes motor learning and neural plasticity after stroke.", difficulty: 2, category: "Therapeutic Intervention", topic: "Neurological Rehabilitation" },
  { id: "pta-069", stem: "What is the McMurray test used to assess?", options: ["ACL integrity", "Meniscal tear", "Achilles tendon rupture", "Patellar tendon integrity"], correctIndex: 1, rationale: "The McMurray test assesses meniscal integrity. The examiner flexes the knee, applies rotational force, and extends — a palpable click or pain suggests meniscal damage.", difficulty: 1, category: "Clinical Scenarios", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-070", stem: "A patient is performing eccentric quadriceps exercise. What type of contraction occurs?", options: ["The muscle shortens while producing force", "The muscle lengthens while producing force", "The muscle produces force without changing length", "No muscle contraction occurs"], correctIndex: 1, rationale: "Eccentric contraction: the muscle lengthens while producing force. For quadriceps, this occurs during the lowering phase of a squat (controlling knee flexion against gravity).", difficulty: 1, category: "Therapeutic Intervention", topic: "Therapeutic Exercise" },
  { id: "pta-071", stem: "A patient with lower extremity lymphedema. Which intervention is part of complete decongestive therapy (CDT)?", options: ["Application of hot packs to increase blood flow", "Manual lymphatic drainage, compression bandaging, exercise, and skin care", "Vigorous deep tissue massage", "Immersion in hot whirlpool"], correctIndex: 1, rationale: "CDT for lymphedema includes: manual lymphatic drainage, multi-layer compression bandaging, decongestive exercises, skin care, and patient education in self-management.", difficulty: 2, category: "Therapeutic Intervention", topic: "Rehabilitation Principles" },
  { id: "pta-072", stem: "What does a positive Trendelenburg test indicate?", options: ["ACL deficiency", "Gluteus medius weakness on the stance leg side", "Hamstring tightness", "Quadriceps weakness"], correctIndex: 1, rationale: "A positive Trendelenburg: the pelvis drops on the unsupported side during single-leg stance, indicating gluteus medius weakness on the stance leg side.", difficulty: 2, category: "Clinical Scenarios", topic: "Neurological Rehabilitation" },
  { id: "pta-073", stem: "A patient is being discharged home with crutches. Which surface should the PTA train the patient on BEFORE discharge?", options: ["Only flat indoor surfaces", "Level surfaces, stairs, ramps, and uneven terrain", "Only carpet surfaces", "Escalators and elevators only"], correctIndex: 1, rationale: "Before discharge, the patient must demonstrate safe ambulation on all surfaces they will encounter: level surfaces, stairs (up and down), ramps, and outdoor uneven terrain.", difficulty: 1, category: "Patient Care Planning", topic: "Assistive Devices" },
  { id: "pta-074", stem: "A newborn demonstrates the Moro reflex. This is an example of which type of reflex?", options: ["Postural reflex", "Primitive reflex", "Equilibrium reaction", "Protective extension response"], correctIndex: 1, rationale: "The Moro (startle) reflex is a primitive reflex present at birth that typically integrates by 4-6 months. Persistence beyond this age may indicate neurological dysfunction.", difficulty: 1, category: "Clinical Scenarios", topic: "Pediatric Rehabilitation" },
  { id: "pta-075", stem: "Which vital sign change should cause the PTA to STOP exercise immediately?", options: ["Heart rate increase from 72 to 90 bpm during moderate exercise", "Mild perspiration and warmth", "Drop in systolic BP >20 mmHg during exercise (exertional hypotension)", "Slight increase in respiratory rate with exercise"], correctIndex: 2, rationale: "A drop in SBP >20 mmHg during exercise (exertional hypotension) is an indication to stop exercise. It may indicate cardiac dysfunction or inability to maintain adequate cardiac output.", difficulty: 2, category: "Safety", topic: "Therapeutic Exercise" },
  { id: "pta-076", stem: "A patient recovering from TBI is at Rancho Level VI. What does this level indicate?", options: ["No response", "Confused-agitated", "Confused-appropriate — goal-directed behavior with moderate assist", "Purposeful-appropriate — independent"], correctIndex: 2, rationale: "Rancho VI: confused but appropriate. The patient shows goal-directed behavior with external direction, follows simple commands consistently, and demonstrates improved awareness.", difficulty: 3, category: "Clinical Scenarios", topic: "Neurological Rehabilitation" },
  { id: "pta-077", stem: "A patient is performing therapeutic exercises in the pool. At waist-depth immersion, approximately what percentage of body weight is supported by buoyancy?", options: ["10%", "25%", "50%", "90%"], correctIndex: 2, rationale: "At waist depth (approximately xiphoid process), buoyancy supports about 50% of body weight. At neck depth, approximately 90% is supported.", difficulty: 2, category: "Therapeutic Intervention", topic: "Therapeutic Exercise" },
  { id: "pta-078", stem: "Which documentation format is MOST commonly used by PTAs for treatment notes?", options: ["Narrative essay format", "SOAP note format (Subjective, Objective, Assessment, Plan)", "Social media post format", "Informal email format"], correctIndex: 1, rationale: "SOAP notes are the standard documentation format: Subjective (patient report), Objective (measurable data), Assessment (clinical interpretation), Plan (future treatment direction).", difficulty: 1, category: "Patient Care Planning", topic: "Rehabilitation Principles" },
  { id: "pta-079", stem: "A patient with shoulder impingement is performing strengthening exercises. Which exercise targets the rotator cuff muscles?", options: ["Bench press", "Side-lying external rotation with resistance band", "Bicep curls", "Lat pulldowns"], correctIndex: 1, rationale: "Side-lying external rotation specifically targets the infraspinatus and teres minor (external rotators of the rotator cuff). This is a key strengthening exercise for impingement rehabilitation.", difficulty: 2, category: "Therapeutic Intervention", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-080", stem: "A 6-month-old infant is unable to roll from supine to prone. Is this a developmental concern?", options: ["No, rolling is not expected until 12 months", "Yes, rolling typically develops by 4-6 months and should be assessed", "No, rolling is never expected in infants", "Yes, but intervention should wait until age 3"], correctIndex: 1, rationale: "Rolling from supine to prone typically develops by 4-6 months. A 6-month-old who cannot roll warrants further developmental assessment for potential delays.", difficulty: 2, category: "Clinical Scenarios", topic: "Pediatric Rehabilitation" },
  { id: "pta-081", stem: "When applying a moist hot pack, how many layers of toweling should be between the hot pack and the patient's skin?", options: ["No toweling needed", "1-2 layers", "6-8 layers of commercial hot pack covers or equivalent", "15-20 layers"], correctIndex: 2, rationale: "6-8 layers of commercial hot pack covers or equivalent toweling protect the skin from burns while allowing therapeutic heat transmission. Always check skin after 5 minutes.", difficulty: 1, category: "Safety", topic: "Therapeutic Exercise" },
  { id: "pta-082", stem: "A patient had an ACL reconstruction. At what timeframe is return to pivoting sports typically allowed?", options: ["2-4 weeks post-surgery", "6-8 weeks post-surgery", "6-9 months post-surgery with functional testing clearance", "2 years post-surgery minimum"], correctIndex: 2, rationale: "Return to pivoting sports after ACL reconstruction typically occurs at 6-9 months, contingent on passing functional testing criteria (hop tests, strength symmetry, proprioception).", difficulty: 2, category: "Patient Care Planning", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-083", stem: "During cryotherapy application, what is the typical duration for ice pack application?", options: ["2-3 minutes", "10-20 minutes", "45-60 minutes", "2 hours continuously"], correctIndex: 1, rationale: "Standard cryotherapy application is 10-20 minutes. This duration achieves therapeutic tissue cooling without risking cold-related tissue damage or frostbite.", difficulty: 1, category: "Therapeutic Intervention", topic: "Therapeutic Exercise" },
  { id: "pta-084", stem: "A patient with bilateral above-knee amputations is learning wheelchair mobility. What is an important consideration?", options: ["Standard wheelchair with no modifications", "Anti-tipping wheelchair with rearward-extended axle to prevent backward tipping", "Wheelchair with forward-extended axle", "No wheelchair needed — ambulation with prosthetics only"], correctIndex: 1, rationale: "Bilateral AKA shifts the center of gravity posteriorly. The wheelchair requires a rearward-extended axle and/or anti-tipping devices to prevent backward tipping.", difficulty: 3, category: "Safety", topic: "Patient Mobility Techniques" },
  { id: "pta-085", stem: "Which balance assessment tool rates 14 items on a 0-4 scale with a maximum score of 56?", options: ["Timed Up and Go", "Berg Balance Scale", "Tinetti Assessment Tool", "30-Second Chair Stand"], correctIndex: 1, rationale: "The Berg Balance Scale assesses 14 balance tasks scored 0-4 each, maximum score 56. Scores <45 indicate fall risk; <36 indicate high fall risk.", difficulty: 1, category: "Clinical Scenarios", topic: "Geriatric Rehabilitation" },
  { id: "pta-086", stem: "A patient is referred for cardiac rehabilitation Phase II. What characterizes this phase?", options: ["Inpatient acute care rehabilitation", "Outpatient supervised exercise program with ECG monitoring", "Independent unsupervised home exercise", "Pre-surgical conditioning only"], correctIndex: 1, rationale: "Phase II cardiac rehab is a supervised outpatient program with ECG monitoring, typically lasting 6-12 weeks. It progresses exercise intensity while monitoring cardiac response.", difficulty: 2, category: "Patient Care Planning", topic: "Rehabilitation Principles" },
  { id: "pta-087", stem: "The PTA is treating a patient with adhesive capsulitis (frozen shoulder). Which intervention is MOST appropriate?", options: ["Aggressive passive ROM to end range on first visit", "Gradual ROM exercises, joint mobilization, and modalities for pain management", "Complete immobilization for 6 months", "Strengthening exercises only without ROM work"], correctIndex: 1, rationale: "Adhesive capsulitis treatment combines gradual ROM progression, joint mobilization techniques, modalities for pain management, and progressive strengthening as ROM improves.", difficulty: 2, category: "Therapeutic Intervention", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-088", stem: "A patient with spinal cord injury at T10 level. What functional mobility is expected?", options: ["Independent wheelchair mobility and some functional ambulation with orthotics", "Total dependence for all mobility", "Independent ambulation without devices", "Sip-and-puff wheelchair operation only"], correctIndex: 0, rationale: "T10 SCI preserves full UE function and some trunk stability. The patient can achieve independent wheelchair mobility and may achieve limited community ambulation with KAFOs and crutches.", difficulty: 2, category: "Patient Care Planning", topic: "Neurological Rehabilitation" },
  { id: "pta-089", stem: "Which stretching technique involves a rapid bouncing motion at end range?", options: ["Static stretching", "PNF stretching", "Ballistic stretching", "Dynamic stretching"], correctIndex: 2, rationale: "Ballistic stretching uses rapid bouncing motions at end range. It is generally NOT recommended due to increased risk of muscle injury from activating the stretch reflex.", difficulty: 1, category: "Therapeutic Intervention", topic: "Therapeutic Exercise" },
  { id: "pta-090", stem: "A patient with left CVA is most likely to exhibit which motor deficit?", options: ["Left hemiparesis", "Right hemiparesis", "Bilateral upper extremity weakness only", "Lower extremity weakness only"], correctIndex: 1, rationale: "Left hemisphere stroke causes contralateral (right-sided) motor deficits due to the decussation of motor fibers in the medullary pyramids.", difficulty: 1, category: "Clinical Scenarios", topic: "Neurological Rehabilitation" },
  { id: "pta-091", stem: "When fitting a patient for a cane, the handle height should be at which anatomical landmark?", options: ["Iliac crest", "Greater trochanter of the femur", "Knee joint line", "Ankle malleolus"], correctIndex: 1, rationale: "Cane handle height is measured at the greater trochanter with the patient standing upright. This results in approximately 20-30° elbow flexion for optimal biomechanics.", difficulty: 1, category: "Patient Care Planning", topic: "Assistive Devices" },
  { id: "pta-092", stem: "A patient with COPD demonstrates pursed-lip breathing. What is the physiological benefit?", options: ["Increases inspiratory volume", "Creates back pressure to keep airways open during exhalation, reducing air trapping", "Strengthens the diaphragm", "Increases oxygen consumption"], correctIndex: 1, rationale: "Pursed-lip breathing creates positive back pressure that keeps small airways open during exhalation, reducing air trapping and dynamic hyperinflation in COPD.", difficulty: 2, category: "Therapeutic Intervention", topic: "Rehabilitation Principles" },
  { id: "pta-093", stem: "The Empty Can test is used to assess which structure?", options: ["ACL", "Supraspinatus tendon/muscle", "Biceps tendon", "Median nerve"], correctIndex: 1, rationale: "The Empty Can (Jobe) test assesses the supraspinatus muscle/tendon. The arm is abducted to 90° in the scapular plane with internal rotation (thumb down); pain or weakness indicates pathology.", difficulty: 2, category: "Clinical Scenarios", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-094", stem: "Log rolling technique is used post-operatively for which type of surgery?", options: ["Total knee replacement", "Carpal tunnel release", "Spinal surgery to maintain spinal alignment", "Rotator cuff repair"], correctIndex: 2, rationale: "Log rolling maintains spinal alignment during position changes after spinal surgery. The patient rolls as a unit (shoulders and hips together) to prevent spinal rotation.", difficulty: 1, category: "Safety", topic: "Patient Mobility Techniques" },
  { id: "pta-095", stem: "A patient presents with foot drop. Which assistive device is indicated?", options: ["Knee brace", "Ankle-foot orthosis (AFO)", "Hip abduction brace", "Wrist splint"], correctIndex: 1, rationale: "An AFO holds the ankle in neutral dorsiflexion (90°), preventing the foot from dropping during swing phase and providing stability during stance in patients with dorsiflexor weakness.", difficulty: 1, category: "Patient Care Planning", topic: "Assistive Devices" },
  { id: "pta-096", stem: "A patient is scheduled for NMES (neuromuscular electrical stimulation) to the quadriceps after ACL surgery. What is the primary goal?", options: ["Pain management", "Reducing spasticity", "Facilitating quadriceps contraction and preventing atrophy", "Increasing bone density"], correctIndex: 2, rationale: "NMES after ACL surgery targets the quadriceps to facilitate muscle contraction, prevent disuse atrophy, and improve voluntary muscle recruitment when arthrogenic inhibition is present.", difficulty: 2, category: "Therapeutic Intervention", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-097", stem: "When should the PTA communicate a change in patient status to the supervising PT?", options: ["Only at the next scheduled meeting", "Immediately when a significant change in patient status is observed", "Only if the patient requests it", "At the end of the billing period"], correctIndex: 1, rationale: "The PTA must communicate significant changes in patient status to the supervising PT immediately. This includes new symptoms, functional decline, adverse responses, or safety concerns.", difficulty: 1, category: "Safety", topic: "Rehabilitation Principles" },
  { id: "pta-098", stem: "A 2-year-old child is unable to jump with both feet off the ground. Is this concerning?", options: ["Yes, jumping should develop by 12 months", "No, jumping with both feet typically develops by 24-36 months", "Yes, the child needs surgery", "No, jumping is not expected until age 6"], correctIndex: 1, rationale: "Jumping with both feet off the ground typically develops between 24-36 months. At 2 years (24 months), the child is at the beginning of the expected range and may not yet have this skill.", difficulty: 1, category: "Clinical Scenarios", topic: "Pediatric Rehabilitation" },
  { id: "pta-099", stem: "Which intervention is CONTRAINDICATED for a patient with deep vein thrombosis (DVT) in the left calf?", options: ["Ankle pumps of the right (unaffected) extremity", "Vigorous massage and exercise of the left (affected) calf", "Upper extremity exercises", "Deep breathing exercises"], correctIndex: 1, rationale: "Vigorous massage and exercise of the affected extremity in DVT is contraindicated due to the risk of dislodging the clot, causing a potentially fatal pulmonary embolism.", difficulty: 2, category: "Safety", topic: "Rehabilitation Principles" },
  { id: "pta-100", stem: "A patient completing PT asks the PTA when their next appointment should be. Who determines the frequency and duration of PT visits?", options: ["The PTA independently decides frequency", "The supervising PT establishes visit frequency as part of the plan of care", "The patient decides their own schedule", "The insurance company solely determines frequency"], correctIndex: 1, rationale: "The supervising PT establishes the frequency, duration, and intensity of physical therapy services as part of the plan of care. The PTA implements treatment within these parameters.", difficulty: 1, category: "Patient Care Planning", topic: "Rehabilitation Principles" },
  { id: "pta-201", stem: "A patient is 4 weeks post-ACL reconstruction and reports anterior knee pain during open kinetic chain quad sets. What should the PTA do?", options: ["Continue the exercise to strengthen the quadriceps", "Modify to closed kinetic chain exercises within safe ROM and report the pain to the supervising PT", "Stop all quad exercises permanently", "Increase resistance to overcome the pain"], correctIndex: 1, rationale: "Anterior knee pain during OKC exercises post-ACL may indicate excessive patellofemoral stress. CKC exercises provide protective co-contraction and reduce anterior shear. The PT should be notified of the symptom change.", difficulty: 2, category: "Safety", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-202", stem: "A patient with a T10 SCI is expected to achieve which level of functional mobility?", options: ["Independent ambulation without assistive devices", "Wheelchair independence with potential for limited household ambulation with bilateral KAFOs and crutches", "Complete dependence for all mobility", "Running and jumping independently"], correctIndex: 1, rationale: "T10 SCI preserves full upper extremity function and upper trunk muscles. Patients achieve wheelchair independence and may ambulate short distances with bilateral KAFOs, although this is energy-intensive.", difficulty: 2, category: "Patient Care Planning", topic: "Neurological Rehabilitation" },
  { id: "pta-203", stem: "During iontophoresis treatment for inflammation, which medication is commonly delivered using a negative electrode?", options: ["Lidocaine (positive polarity)", "Dexamethasone (negative polarity)", "Calcium chloride (positive polarity)", "Zinc oxide (positive polarity)"], correctIndex: 1, rationale: "Dexamethasone (a corticosteroid for inflammation) carries a negative charge and is delivered from the negative electrode (cathode) during iontophoresis. Like charges repel, driving the medication into tissue.", difficulty: 3, category: "Therapeutic Intervention", topic: "Therapeutic Exercise" },
  { id: "pta-204", stem: "A patient with a grade II MCL sprain is 3 weeks post-injury. Which intervention is appropriate?", options: ["Aggressive valgus stress testing daily", "Gentle AROM, isometric quad and hamstring exercises, and protected weight-bearing with a hinged knee brace", "Unrestricted return to sport", "Complete immobilization for 12 more weeks"], correctIndex: 1, rationale: "Grade II MCL sprains involve partial ligament tear. At 3 weeks, gentle AROM, isometrics, and protected weight-bearing with a hinged brace support healing while preventing stiffness and atrophy.", difficulty: 2, category: "Therapeutic Intervention", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-205", stem: "A patient demonstrates a positive Ober test on the right side. Which structure is tight?", options: ["Right hamstrings", "Right iliotibial band/tensor fascia latae", "Right hip adductors", "Right hip flexors"], correctIndex: 1, rationale: "A positive Ober test indicates tightness of the iliotibial band (ITB) and/or tensor fascia latae. The thigh remains abducted when released in sidelying, unable to adduct to neutral.", difficulty: 2, category: "Clinical Scenarios", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-206", stem: "A PTA is performing chest physiotherapy on a patient with cystic fibrosis. What is the primary goal of postural drainage with percussion?", options: ["Strengthening the respiratory muscles", "Mobilizing secretions from specific lung segments for easier expectoration", "Increasing lung volume", "Reducing pain in the chest wall"], correctIndex: 1, rationale: "Postural drainage with percussion uses gravity-assisted positioning and rhythmic clapping to mobilize secretions from specific bronchopulmonary segments into larger airways for expectoration.", difficulty: 2, category: "Therapeutic Intervention", topic: "Rehabilitation Principles" },
  { id: "pta-207", stem: "A patient with plantar fasciitis reports worst pain with the first steps in the morning. Which intervention is MOST appropriate?", options: ["Walking barefoot on hard surfaces", "Night splint to maintain ankle dorsiflexion, gastrocnemius/soleus stretching, and arch support", "Running to loosen the fascia", "Ice application only without stretching"], correctIndex: 1, rationale: "Plantar fasciitis causes worst pain with first steps (fascial re-tearing after overnight shortening). Night splints maintain dorsiflexion, calf stretching reduces tension, and arch supports redistribute load.", difficulty: 2, category: "Therapeutic Intervention", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-208", stem: "A patient is performing aquatic therapy exercises. What physiological effect does hydrostatic pressure have on the body during immersion?", options: ["Increases heart rate significantly", "Decreases venous return to the heart", "Increases venous return and reduces peripheral edema due to hydrostatic pressure", "Dehydrates the skin and tissues"], correctIndex: 2, rationale: "Hydrostatic pressure during water immersion compresses tissues, increasing venous return to the heart, reducing peripheral edema, and lowering heart rate at a given workload.", difficulty: 2, category: "Therapeutic Intervention", topic: "Therapeutic Exercise" },
  { id: "pta-209", stem: "A patient with a frozen shoulder (adhesive capsulitis) is in the 'frozen' stage. What is the primary treatment focus?", options: ["Aggressive manipulation under anesthesia", "Gentle ROM within pain tolerance, joint mobilization, and modalities for pain management", "Maximum resistance strengthening", "Complete immobilization"], correctIndex: 1, rationale: "The frozen stage of adhesive capsulitis features significant ROM restriction and pain. Treatment focuses on gentle ROM within tolerance, joint mobilization (grades I-II), and pain management.", difficulty: 2, category: "Therapeutic Intervention", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-210", stem: "A patient's blood glucose reads 55 mg/dL before exercise. What should the PTA do?", options: ["Proceed with high-intensity exercise to raise glucose", "Do not exercise — have the patient eat a carbohydrate snack and recheck glucose before starting", "Administer insulin to the patient", "Ignore the reading and begin exercise"], correctIndex: 1, rationale: "Blood glucose <70 mg/dL indicates hypoglycemia. Exercise should not be performed as it would further lower glucose. The patient should eat a carbohydrate snack and recheck before exercising.", difficulty: 2, category: "Safety", topic: "Therapeutic Exercise" },
  { id: "pta-211", stem: "A patient with an L4-L5 disc herniation reports pain radiating down the posterior thigh and lateral leg. Which nerve root is likely involved?", options: ["L2", "L3", "L5", "S3"], correctIndex: 2, rationale: "L4-L5 disc herniation typically compresses the L5 nerve root, causing pain radiation along the posterior thigh, lateral leg, and dorsum of the foot, with potential dorsiflexion weakness.", difficulty: 2, category: "Clinical Scenarios", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-212", stem: "A patient is performing proprioceptive neuromuscular facilitation (PNF) hold-relax technique. What is the correct sequence?", options: ["Patient contracts the agonist → therapist stretches → repeat", "Therapist passively stretches to end range → patient isometrically contracts the tight muscle → relax → therapist moves to new range", "Therapist bounces the limb at end range repeatedly", "Patient actively moves through full range without therapist assistance"], correctIndex: 1, rationale: "Hold-relax PNF: passive stretch to limitation → patient performs isometric contraction of the tight (antagonist) muscle → relax → therapist moves limb to new end range utilizing autogenic inhibition.", difficulty: 3, category: "Therapeutic Intervention", topic: "Therapeutic Exercise" },
  { id: "pta-213", stem: "A patient with MS experiences an Uhthoff phenomenon during exercise. What does this mean?", options: ["The patient has a seizure during exercise", "Temporary worsening of neurological symptoms with increased body temperature", "The patient develops a new lesion during exercise", "The patient loses consciousness"], correctIndex: 1, rationale: "Uhthoff phenomenon is a temporary worsening of MS neurological symptoms (blurred vision, weakness) triggered by increased body temperature. Symptoms resolve when temperature normalizes.", difficulty: 3, category: "Clinical Scenarios", topic: "Neurological Rehabilitation" },
  { id: "pta-214", stem: "A PTA is applying TENS for pain management. Which setting provides the BEST conventional (high-rate) TENS for acute pain?", options: ["Low frequency (2-4 Hz), high intensity, long pulse duration", "High frequency (80-150 Hz), low intensity (sensory level), short pulse duration", "Burst mode at maximum intensity", "Random frequency with no specific pattern"], correctIndex: 1, rationale: "Conventional TENS uses high frequency (80-150 Hz), low intensity (comfortable sensory level), and short pulse duration. It activates the gate control mechanism for acute pain relief.", difficulty: 2, category: "Therapeutic Intervention", topic: "Therapeutic Exercise" },
  { id: "pta-215", stem: "A patient with Parkinson's disease demonstrates festinating gait with progressively increasing speed and shortening steps. What is the PRIMARY fall risk?", options: ["Tripping over objects", "The forward-propelling momentum exceeds the ability to stop, causing forward falls", "Lateral balance loss", "Backward falls from retropulsion"], correctIndex: 1, rationale: "Festinating gait involves involuntary acceleration with shortened steps. The patient's center of gravity shifts forward faster than steps can accommodate, creating high risk for forward falls.", difficulty: 2, category: "Clinical Scenarios", topic: "Neurological Rehabilitation" },
  { id: "pta-216", stem: "A patient has a prosthetic below-knee (transtibial) amputation. During gait observation, the patient demonstrates excessive lateral trunk lean during stance on the prosthetic side. What is the likely cause?", options: ["The prosthetic foot is too flexible", "The prosthetic socket is too loose or the patient has weak hip abductors on the prosthetic side", "The prosthetic limb is too short", "The patient is walking too fast"], correctIndex: 1, rationale: "Lateral trunk lean during prosthetic stance can result from a loose socket (inadequate support) or weak hip abductors. Both cause compensatory trunk shift to maintain balance over the prosthetic limb.", difficulty: 3, category: "Clinical Scenarios", topic: "Assistive Devices" },
  { id: "pta-217", stem: "A patient with cervical radiculopathy has a positive Spurling test. What does this indicate?", options: ["Carpal tunnel syndrome", "Compression of a cervical nerve root — symptoms reproduced by cervical extension, lateral flexion, and axial compression", "Thoracic outlet syndrome", "Lumbar disc herniation"], correctIndex: 1, rationale: "Spurling test: cervical extension + lateral flexion toward the affected side + axial compression narrows the intervertebral foramen. A positive test reproduces radicular symptoms (pain, numbness, tingling).", difficulty: 2, category: "Clinical Scenarios", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-218", stem: "A patient is using a front-wheeled walker. During which phase of gait does the walker provide support?", options: ["Only during swing phase", "During stance phase when the patient bears weight through the arms onto the walker", "Only during initial contact", "The walker provides no weight-bearing support"], correctIndex: 1, rationale: "The walker provides support during stance phase when the patient bears weight through the upper extremities onto the walker frame, reducing lower extremity load and providing stability.", difficulty: 1, category: "Patient Care Planning", topic: "Assistive Devices" },
  { id: "pta-219", stem: "A patient with rotator cuff tendinopathy demonstrates a painful arc between 60-120° of shoulder abduction. What structure is likely impinged?", options: ["Biceps brachii", "Supraspinatus tendon impinging under the coracoacromial arch", "Subscapularis", "Latissimus dorsi"], correctIndex: 1, rationale: "A painful arc between 60-120° of abduction suggests supraspinatus impingement under the coracoacromial arch. The greater tuberosity and supraspinatus tendon compress against the acromion in this range.", difficulty: 2, category: "Clinical Scenarios", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-220", stem: "A patient with congestive heart failure is performing exercises. Which sign indicates the PTA should STOP the exercise immediately?", options: ["Patient reports slight breathlessness that resolves with rest", "Patient develops crackles (rales) in lung bases, increased dyspnea, and S3 heart sound", "Patient's heart rate increases by 10 bpm during exercise", "Patient perspires mildly during activity"], correctIndex: 1, rationale: "Crackles in lung bases, worsening dyspnea, and S3 heart sound indicate fluid overload/decompensation in CHF. Exercise must be stopped immediately and medical staff notified.", difficulty: 3, category: "Safety", topic: "Therapeutic Exercise" },
  { id: "pta-221", stem: "A patient post-total knee replacement is having difficulty achieving full knee extension. Which intervention addresses this?", options: ["Place a pillow under the knee for comfort", "Low-load long-duration stretching with the heel propped on a towel roll for terminal knee extension", "Avoid knee extension exercises for 6 weeks", "Aggressive manual manipulation into full extension"], correctIndex: 1, rationale: "Low-load long-duration stretching (heel prop on a towel roll) provides sustained stretch to the posterior capsule and hamstrings, promoting terminal knee extension after TKR.", difficulty: 2, category: "Therapeutic Intervention", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-222", stem: "A patient with vestibular hypofunction reports dizziness with head movements. Which rehabilitation exercise is appropriate?", options: ["Strict bed rest with eyes closed", "Gaze stabilization exercises (VOR adaptation) — maintaining visual focus during head movements", "Avoiding all head movements", "Rapid spinning to habituate the vestibular system"], correctIndex: 1, rationale: "Gaze stabilization exercises (VOR x1 and x2) train the vestibulo-ocular reflex by having the patient maintain focus on a stationary target during active head movements, promoting vestibular compensation.", difficulty: 2, category: "Therapeutic Intervention", topic: "Neurological Rehabilitation" },
  { id: "pta-223", stem: "A patient has a stage III pressure ulcer over the sacrum. During which position should the PTA AVOID placing the patient?", options: ["Side-lying with pillows between knees", "Supine with the head of bed at 30° with pressure-relieving mattress", "Directly on the sacral wound", "Prone if medically appropriate"], correctIndex: 2, rationale: "A patient with a sacral pressure ulcer must NOT be positioned directly on the wound. Side-lying, prone, or supine with appropriate pressure-relief devices and frequent repositioning are alternatives.", difficulty: 1, category: "Safety", topic: "Patient Mobility Techniques" },
  { id: "pta-224", stem: "A patient demonstrates a positive Thomas test on the right side. Which muscle is tight?", options: ["Right hamstrings", "Right iliopsoas (hip flexor)", "Right gluteus maximus", "Right quadratus lumborum"], correctIndex: 1, rationale: "A positive Thomas test indicates hip flexor contracture (iliopsoas tightness). The tested thigh remains elevated off the table when the opposite hip is fully flexed to flatten the lumbar spine.", difficulty: 2, category: "Clinical Scenarios", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-225", stem: "A PTA is applying therapeutic ultrasound over the anterior knee. Which area must be AVOIDED?", options: ["The lateral retinaculum", "The epiphyseal (growth) plate in a skeletally immature patient", "The quadriceps tendon", "The medial joint line"], correctIndex: 1, rationale: "Therapeutic ultrasound over epiphyseal plates in skeletally immature patients is contraindicated as it may damage the growth plate and affect normal bone development.", difficulty: 2, category: "Safety", topic: "Therapeutic Exercise" },
  { id: "pta-226", stem: "A patient is performing Williams flexion exercises for lumbar stenosis. What is the rationale?", options: ["Flexion exercises increase lordosis", "Lumbar flexion opens the intervertebral foramina and spinal canal, reducing nerve compression", "Flexion strengthens the erector spinae", "Flexion exercises are designed for cervical disc herniation"], correctIndex: 1, rationale: "Williams flexion exercises flex the lumbar spine, opening the intervertebral foramina and spinal canal. This reduces compression on neural structures in patients with lumbar stenosis.", difficulty: 2, category: "Therapeutic Intervention", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-227", stem: "A patient recovering from a stroke demonstrates pusher syndrome. How does this present?", options: ["The patient pushes toward the unaffected side", "The patient actively pushes toward the hemiplegic side and resists correction to midline", "The patient cannot push at all", "The patient pushes backward only"], correctIndex: 1, rationale: "Pusher syndrome (lateropulsion) involves the patient actively pushing toward the hemiplegic side using the intact extremities and resisting passive correction to midline, due to altered perception of vertical.", difficulty: 3, category: "Clinical Scenarios", topic: "Neurological Rehabilitation" },
  { id: "pta-228", stem: "A patient with peripheral arterial disease reports intermittent claudication. At what point during a walking program should the patient rest?", options: ["Before any symptoms appear", "When claudication pain reaches moderate intensity (3-4/5 on pain scale)", "Only when the pain becomes maximal and unbearable", "Walking should be completely avoided"], correctIndex: 1, rationale: "Claudication-based walking programs: walk until moderate claudication pain (3-4/5), rest until pain subsides, then resume. This progressive approach improves walking distance through collateral circulation development.", difficulty: 2, category: "Therapeutic Intervention", topic: "Therapeutic Exercise" },
  { id: "pta-229", stem: "A patient with a below-knee amputation is wrapping the residual limb with elastic bandage. What is the correct wrapping pattern?", options: ["Circular wrapping from proximal to distal", "Figure-eight pattern from distal to proximal with greater pressure distally", "Spiral wrapping from distal to proximal with uniform pressure", "Random wrapping as long as the limb is covered"], correctIndex: 1, rationale: "Residual limb wrapping uses a figure-eight pattern from distal to proximal with greater pressure distally. This conical shaping facilitates edema reduction and prosthetic socket fitting.", difficulty: 2, category: "Patient Care Planning", topic: "Assistive Devices" },
  { id: "pta-230", stem: "A patient is performing McKenzie extension exercises for a posterior lumbar disc herniation. What is the therapeutic rationale?", options: ["Extension exercises increase posterior disc pressure", "Lumbar extension centralizes nuclear material anteriorly, reducing posterior nerve root compression", "Extension exercises stretch the hip flexors only", "Extension exercises have no effect on disc herniation"], correctIndex: 1, rationale: "McKenzie extension exercises create anterior migration of nuclear material, reducing posterior bulging against neural structures. Centralization of symptoms (distal to proximal) indicates a positive response.", difficulty: 2, category: "Therapeutic Intervention", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-231", stem: "A patient taking beta-blockers begins an exercise program. How does this medication affect exercise monitoring?", options: ["Heart rate response is exaggerated", "Heart rate response is blunted — RPE should be used instead of heart rate to monitor intensity", "Blood pressure drops dangerously during exercise", "There is no effect on exercise response"], correctIndex: 1, rationale: "Beta-blockers blunt the heart rate response to exercise, making target heart rate an unreliable intensity measure. RPE (Borg scale) should be used as the primary intensity monitoring tool.", difficulty: 2, category: "Safety", topic: "Therapeutic Exercise" },
  { id: "pta-232", stem: "A patient with a recent total hip replacement complains of sudden onset calf pain and swelling. What should the PTA suspect and do?", options: ["Muscle strain — apply ice and continue therapy", "Possible deep vein thrombosis — stop exercise, avoid calf massage, and notify the medical team immediately", "Normal post-surgical swelling — continue as planned", "Delayed onset muscle soreness — increase stretching"], correctIndex: 1, rationale: "Sudden calf pain and swelling post-total hip replacement are classic signs of DVT. The PTA must stop exercise, avoid calf massage (risk of embolism), and immediately notify the medical team.", difficulty: 2, category: "Safety", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-233", stem: "A patient with a C4 SCI requires which type of assistance for respiratory function?", options: ["No respiratory assistance needed", "Mechanical ventilation or phrenic nerve pacer, as the diaphragm is partially or fully denervated", "Only supplemental oxygen", "Incentive spirometry alone"], correctIndex: 1, rationale: "C4 SCI may partially or fully denervate the diaphragm (C3-C5 innervation). Patients often require mechanical ventilation or phrenic nerve pacers for breathing, especially initially.", difficulty: 2, category: "Clinical Scenarios", topic: "Neurological Rehabilitation" },
  { id: "pta-234", stem: "A patient demonstrates a Trendelenburg sign during right single-leg stance. What does this indicate?", options: ["Right quadriceps weakness", "Right gluteus medius weakness — the pelvis drops on the unsupported (left) side", "Left hip adductor weakness", "Right hamstring tightness"], correctIndex: 1, rationale: "A positive Trendelenburg sign during right single-leg stance indicates right gluteus medius weakness. The pelvis drops on the contralateral (left/unsupported) side due to inadequate hip abductor support.", difficulty: 2, category: "Clinical Scenarios", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-235", stem: "A patient is performing active-assistive shoulder flexion using an overhead pulley system. What is the primary benefit?", options: ["Building maximum shoulder strength", "Using the uninvolved arm to assist the involved arm through available ROM to maintain or increase motion", "Providing resistance training", "Stretching the shoulder capsule aggressively"], correctIndex: 1, rationale: "Overhead pulleys allow the uninvolved arm to assist the involved arm through shoulder flexion ROM. This is an active-assistive exercise that maintains motion while protecting healing tissues.", difficulty: 1, category: "Therapeutic Intervention", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-236", stem: "A patient with stroke has shoulder subluxation on the hemiplegic side. Which intervention is appropriate?", options: ["Aggressive overhead stretching of the affected arm", "Arm support (sling or lap tray), NMES to supraspinatus and deltoid, and proper positioning", "Ignoring the subluxation as it will self-correct", "Forceful manual traction to reduce the subluxation"], correctIndex: 1, rationale: "Hemiplegic shoulder subluxation requires support (sling, lap tray, armrest), NMES to re-educate supraspinatus/posterior deltoid, and proper positioning to prevent further subluxation and pain.", difficulty: 2, category: "Therapeutic Intervention", topic: "Neurological Rehabilitation" },
  { id: "pta-237", stem: "A patient recovering from a Colles fracture at 8 weeks has wrist stiffness. Which mobilization grade is appropriate to increase ROM?", options: ["Grade I (small amplitude at beginning of range)", "Grade III-IV (large amplitude at end range to increase mobility)", "Grade V (high-velocity thrust)", "No mobilization should ever be performed after fracture"], correctIndex: 1, rationale: "At 8 weeks post-Colles fracture with wrist stiffness, Grade III (large amplitude at end range) and Grade IV (small amplitude at end range) mobilizations are appropriate to increase restricted joint mobility.", difficulty: 3, category: "Therapeutic Intervention", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-238", stem: "A premature infant demonstrates physiological flexion at 40 weeks corrected gestational age. Is this expected?", options: ["No — the infant should be in full extension", "Yes — physiological flexion is the normal resting posture at full-term equivalent age", "No — this indicates hypertonicity", "Yes — but only if the infant was born at term"], correctIndex: 1, rationale: "Physiological flexion is the expected resting posture at 40 weeks gestational age, whether born at term or reaching this age post-prematurity. It reflects normal CNS maturation.", difficulty: 2, category: "Clinical Scenarios", topic: "Pediatric Rehabilitation" },
  { id: "pta-239", stem: "A patient with lateral ankle sprain is progressing through rehabilitation. What is the correct exercise progression?", options: ["AROM → RROM → proprioception → sport-specific → return to play", "Immobilization for 12 weeks → return to full activity", "Maximum plyometrics immediately after swelling resolves", "Stretching only without strengthening"], correctIndex: 0, rationale: "Lateral ankle sprain rehabilitation progresses through: AROM/PROM → progressive strengthening (isometric → isotonic) → proprioception/balance → sport-specific training → return to play criteria.", difficulty: 2, category: "Therapeutic Intervention", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-240", stem: "A patient undergoing dialysis asks to exercise on dialysis days. What should the PTA recommend?", options: ["Exercise immediately after dialysis for best results", "Exercise before dialysis or on non-dialysis days, as post-dialysis fluid shifts can cause hypotension", "Avoid all exercise on dialysis days", "Perform maximum-intensity exercise right after dialysis"], correctIndex: 1, rationale: "Post-dialysis fluid shifts can cause hypotension and fatigue. Exercise is best performed before dialysis or on non-dialysis days. If exercising after, wait adequate time and monitor vitals carefully.", difficulty: 2, category: "Safety", topic: "Therapeutic Exercise" },
  { id: "pta-241", stem: "A patient with anterior cruciate ligament tear demonstrates a positive pivot shift test. What does this test assess?", options: ["MCL integrity", "Rotatory instability of the knee associated with ACL insufficiency", "Meniscal tear", "Posterior cruciate ligament integrity"], correctIndex: 1, rationale: "The pivot shift test assesses anterolateral rotatory instability caused by ACL insufficiency. A positive test produces a palpable shift as the tibia subluxes and reduces during combined valgus and internal rotation.", difficulty: 3, category: "Clinical Scenarios", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-242", stem: "A PTA is treating a patient with Bell's palsy. Which exercise is appropriate for facial retraining?", options: ["Aggressive resistance exercises to all facial muscles", "Gentle, selective facial movements (smile, pucker, eye closure) with mirror feedback for neuromuscular re-education", "Electrical stimulation at maximum intensity to all facial muscles", "No intervention — Bell's palsy always resolves spontaneously"], correctIndex: 1, rationale: "Bell's palsy facial retraining uses gentle, selective movements with mirror feedback for neuromuscular re-education. Aggressive exercises or excessive electrical stimulation may promote synkinesis.", difficulty: 2, category: "Therapeutic Intervention", topic: "Neurological Rehabilitation" },
  { id: "pta-243", stem: "A patient presents with a positive Neer test. What condition does this suggest?", options: ["ACL tear", "Shoulder impingement syndrome — subacromial structures compressed during passive forward flexion", "Carpal tunnel syndrome", "Lumbar disc herniation"], correctIndex: 1, rationale: "Neer impingement test: passive shoulder forward flexion with scapula stabilized compresses subacromial structures against the anterior acromion. Pain indicates subacromial impingement.", difficulty: 2, category: "Clinical Scenarios", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-244", stem: "A patient recovering from a stroke demonstrates spastic catch in the biceps during passive elbow extension. How should the PTA manage this during ROM exercises?", options: ["Force through the spasticity with quick stretching", "Use slow, sustained stretching with the limb supported, allowing the spasticity to release", "Avoid all ROM exercises to prevent triggering spasticity", "Apply ice and discontinue all upper extremity exercises"], correctIndex: 1, rationale: "Spasticity is velocity-dependent. Slow, sustained stretching allows the muscle spindle reflex to accommodate, reducing spastic resistance. Quick stretching triggers increased spasticity.", difficulty: 2, category: "Therapeutic Intervention", topic: "Neurological Rehabilitation" },
  { id: "pta-245", stem: "A 3-year-old child with cerebral palsy is classified as GMFCS Level V. What does this indicate about mobility?", options: ["The child walks independently", "The child walks with an assistive device", "The child is transported in a manual wheelchair with extensive physical assistance, lacking antigravity head and trunk control", "The child uses a power wheelchair independently"], correctIndex: 2, rationale: "GMFCS Level V indicates severely limited voluntary movement. The child lacks antigravity head and trunk control and is transported in a wheelchair requiring caregiver propulsion and extensive body support.", difficulty: 2, category: "Clinical Scenarios", topic: "Pediatric Rehabilitation" },
  { id: "pta-246", stem: "During a balance assessment, a patient can maintain standing on a foam surface with eyes open but falls with eyes closed. Which system is most likely impaired?", options: ["Visual system", "Vestibular system — cannot compensate when visual and somatosensory inputs are altered", "Only the musculoskeletal system", "Cardiovascular system"], correctIndex: 1, rationale: "Foam eliminates accurate somatosensory input, and eyes closed removes vision. Falling in this condition indicates vestibular dysfunction — the vestibular system cannot independently maintain balance.", difficulty: 3, category: "Clinical Scenarios", topic: "Neurological Rehabilitation" },
  { id: "pta-247", stem: "A patient with hip osteoarthritis demonstrates an antalgic gait pattern. What characterizes this gait?", options: ["Increased stance time on the affected side", "Decreased stance time on the affected side to minimize weight-bearing duration and pain", "Circumduction of the affected leg", "Excessive hip hiking"], correctIndex: 1, rationale: "Antalgic gait is characterized by decreased stance time on the painful (affected) side. The patient quickly shifts weight off the painful limb, resulting in an uneven gait cadence.", difficulty: 1, category: "Clinical Scenarios", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-248", stem: "A patient is performing scapular stabilization exercises. Which exercise targets the lower trapezius?", options: ["Shoulder shrugs", "Prone I's (arm elevation in line with lower trapezius fibers) and prone Y's", "Bicep curls", "Wrist curls"], correctIndex: 1, rationale: "Prone I's (arm raised inline with body) and prone Y's target the lower trapezius, which depresses, retracts, and upwardly rotates the scapula — essential for shoulder stability and function.", difficulty: 2, category: "Therapeutic Intervention", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-249", stem: "A PTA observes a patient's wound has bright red granulation tissue filling the wound bed. What does this indicate?", options: ["Infection requiring immediate intervention", "Healthy wound healing with good vascular supply", "Necrotic tissue requiring debridement", "The wound is not healing"], correctIndex: 1, rationale: "Bright red, beefy granulation tissue indicates healthy wound healing with good vascular supply. This tissue fills the wound from the base and should be protected during treatment.", difficulty: 1, category: "Clinical Scenarios", topic: "Rehabilitation Principles" },
  { id: "pta-250", stem: "A patient with Down syndrome is 14 months old and not yet walking. When should the PTA expect independent walking for children with Down syndrome?", options: ["By 9 months, same as typically developing children", "Typically between 24-36 months, later than typically developing children", "By 12 months", "Walking is not achievable for children with Down syndrome"], correctIndex: 1, rationale: "Children with Down syndrome typically achieve independent walking between 24-36 months due to hypotonia, ligamentous laxity, and motor planning challenges. This is later than the typical 12-15 months.", difficulty: 2, category: "Patient Care Planning", topic: "Pediatric Rehabilitation" },
  { id: "pta-251", stem: "A patient with chronic low back pain demonstrates fear-avoidance beliefs. Which assessment tool specifically measures this?", options: ["Visual Analog Scale (VAS)", "Fear-Avoidance Beliefs Questionnaire (FABQ)", "Berg Balance Scale", "Functional Independence Measure (FIM)"], correctIndex: 1, rationale: "The FABQ measures fear-avoidance beliefs about physical activity and work in patients with low back pain. High scores indicate strong avoidance beliefs that predict prolonged disability.", difficulty: 2, category: "Clinical Scenarios", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-252", stem: "A patient post-stroke is performing constraint-induced movement therapy. What is the minimum amount of daily training typically required?", options: ["15 minutes per day", "At least 6 hours of intensive task practice per day with the affected extremity", "1 hour every other day", "No specific time requirement"], correctIndex: 1, rationale: "CIMT protocols typically require 6+ hours daily of intensive, structured task practice with the affected extremity while the unaffected arm is restrained for 90% of waking hours for 2-3 weeks.", difficulty: 3, category: "Therapeutic Intervention", topic: "Neurological Rehabilitation" },
  { id: "pta-253", stem: "A patient is being fitted for a knee-ankle-foot orthosis (KAFO). When is this device indicated?", options: ["Isolated ankle weakness only", "Weakness of both the knee extensors and ankle dorsiflexors, requiring support at both the knee and ankle", "Upper extremity weakness", "Trunk instability without lower extremity involvement"], correctIndex: 1, rationale: "KAFOs are indicated when both knee extensors and ankle musculature are weak, requiring joint support at both the knee and ankle for safe ambulation (e.g., polio, SCI, post-stroke).", difficulty: 1, category: "Patient Care Planning", topic: "Assistive Devices" },
  { id: "pta-254", stem: "A patient with chronic obstructive pulmonary disease is learning diaphragmatic breathing. What instruction should the PTA give?", options: ["Breathe rapidly and shallowly using chest muscles", "Place one hand on the chest and one on the abdomen; inhale through the nose expanding the abdomen, exhale slowly through pursed lips", "Hold the breath for as long as possible between breaths", "Breathe only through the mouth at all times"], correctIndex: 1, rationale: "Diaphragmatic breathing: inhale through nose with abdominal expansion (diaphragm descent), exhale slowly through pursed lips. The chest should remain relatively still while the abdomen rises.", difficulty: 1, category: "Therapeutic Intervention", topic: "Rehabilitation Principles" },
  { id: "pta-255", stem: "A patient with a transfemoral (above-knee) amputation is learning to use a prosthesis. Which gait deviation is common due to weak hip extensors?", options: ["Lateral trunk lean", "Excessive trunk forward lean during initial contact to compensate for weak hip extensors", "Circumduction of the prosthetic limb", "Vaulting on the sound limb"], correctIndex: 1, rationale: "Weak hip extensors on the prosthetic side cause excessive forward trunk lean during initial contact as the patient compensates to maintain the prosthetic knee in extension during stance.", difficulty: 3, category: "Clinical Scenarios", topic: "Assistive Devices" },
  { id: "pta-256", stem: "A patient is performing eccentric strengthening of the Achilles tendon for chronic Achilles tendinopathy. What does the exercise involve?", options: ["Concentric heel raises on a flat surface", "Slow lowering of the heel off a step edge (eccentric loading) with gradual resistance progression", "Passive stretching of the Achilles tendon only", "Rapid bouncing on the forefoot"], correctIndex: 1, rationale: "Eccentric Achilles loading (Alfredson protocol): slow heel lowering off a step edge loads the tendon eccentrically, promoting tendon remodeling and collagen reorganization in chronic tendinopathy.", difficulty: 2, category: "Therapeutic Intervention", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-257", stem: "A patient with a complete T6 SCI wants to participate in wheelchair sports. What precaution related to their injury level must be considered?", options: ["No special precautions are needed", "Risk of autonomic dysreflexia during intense physical activity — monitor for symptoms and educate the patient", "The patient cannot participate in any sports", "Only upper extremity exercises are safe"], correctIndex: 1, rationale: "T6 SCI (above T6 splanchnic outflow) places the patient at risk for autonomic dysreflexia during intense exercise. The patient and team must recognize symptoms and manage triggers promptly.", difficulty: 2, category: "Safety", topic: "Neurological Rehabilitation" },
  { id: "pta-258", stem: "A patient demonstrates positive Hawkins-Kennedy test at the shoulder. What does this indicate?", options: ["Labral tear", "Subacromial impingement — internal rotation at 90° flexion compresses subacromial structures", "ACL insufficiency", "Cervical radiculopathy"], correctIndex: 1, rationale: "Hawkins-Kennedy test: shoulder flexed to 90° then internally rotated, compressing the supraspinatus tendon and bursa against the coracoacromial ligament. Pain indicates subacromial impingement.", difficulty: 2, category: "Clinical Scenarios", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-259", stem: "A patient with type 1 diabetes begins to sweat profusely and becomes confused during exercise. What should the PTA do?", options: ["Increase exercise intensity to stimulate alertness", "Stop exercise immediately — this indicates hypoglycemia. Provide fast-acting glucose and monitor", "Continue exercise at reduced intensity", "Have the patient perform relaxation breathing"], correctIndex: 1, rationale: "Sweating, confusion, tremor, and anxiety during exercise in a diabetic patient indicate hypoglycemia. Stop exercise, provide fast-acting glucose (juice, glucose tablets), and monitor until symptoms resolve.", difficulty: 2, category: "Safety", topic: "Therapeutic Exercise" },
  { id: "pta-260", stem: "A patient with shoulder adhesive capsulitis demonstrates a capsular pattern of restriction. What is the capsular pattern of the glenohumeral joint?", options: ["Internal rotation most limited, then flexion, then abduction", "External rotation most limited, then abduction, then internal rotation", "Flexion most limited, then extension", "All motions equally restricted"], correctIndex: 1, rationale: "The glenohumeral capsular pattern: external rotation is most limited, followed by abduction, then internal rotation. This pattern reflects capsular tightening and helps differentiate capsular from non-capsular pathology.", difficulty: 3, category: "Clinical Scenarios", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-261", stem: "A patient with Parkinson's disease is learning to turn while walking. What technique reduces freezing during turns?", options: ["Quick pivot turns", "Wide-arc turns using deliberate large steps with external cues rather than pivot turns", "Shuffling in a tight circle", "Crossing one leg over the other while turning"], correctIndex: 1, rationale: "Patients with Parkinson's should use wide-arc turns with deliberate large steps and external cues (visual markers, counting) rather than pivot turns, which trigger freezing and increase fall risk.", difficulty: 2, category: "Therapeutic Intervention", topic: "Neurological Rehabilitation" },
  { id: "pta-262", stem: "A patient is performing isokinetic exercises on a Biodex dynamometer. What unique feature does isokinetic exercise provide?", options: ["Variable speed throughout the range", "Accommodating resistance at a preset constant velocity throughout the entire range of motion", "Resistance only at end range", "No resistance at any point in the range"], correctIndex: 1, rationale: "Isokinetic exercise provides accommodating resistance that matches the patient's force output at a preset constant angular velocity, providing maximal loading throughout the entire ROM.", difficulty: 2, category: "Therapeutic Intervention", topic: "Therapeutic Exercise" },
  { id: "pta-263", stem: "A patient with a femoral neck fracture has been placed on non-weight-bearing status. How should the PTA assess upper extremity strength for crutch ambulation?", options: ["No assessment is needed before crutch use", "Assess bilateral shoulder depressor, elbow extensor, and grip strength to ensure safe crutch ambulation", "Only assess hand grip strength", "Only assess shoulder flexion"], correctIndex: 1, rationale: "Crutch ambulation requires adequate shoulder depressor (latissimus dorsi), elbow extensor (triceps), and grip strength. Assessment ensures the patient can safely support body weight during NWB gait.", difficulty: 1, category: "Patient Care Planning", topic: "Assistive Devices" },
  { id: "pta-264", stem: "A patient with spina bifida at the L3-L4 level has functional use of which muscles?", options: ["All lower extremity muscles", "Quadriceps and hip flexors, but weak or absent ankle dorsiflexors and plantarflexors", "No lower extremity muscles", "Only hip extensors and knee flexors"], correctIndex: 1, rationale: "L3-L4 level spina bifida preserves hip flexor (L1-L3) and quadriceps (L2-L4) function. Ankle dorsiflexors (L4-L5) are weak, and plantarflexors (S1-S2) and hip extensors are absent or weak.", difficulty: 2, category: "Clinical Scenarios", topic: "Pediatric Rehabilitation" },
  { id: "pta-265", stem: "A PTA is applying moist heat to a patient's low back. What is the recommended treatment duration?", options: ["5 minutes", "15-20 minutes", "45 minutes", "2 hours"], correctIndex: 1, rationale: "Moist hot packs are typically applied for 15-20 minutes. Longer application may cause burns or rebound vasoconstriction. Adequate layers (6-8 towel layers) must separate the pack from the skin.", difficulty: 1, category: "Therapeutic Intervention", topic: "Therapeutic Exercise" },
  { id: "pta-266", stem: "A patient with right middle cerebral artery (MCA) stroke presents with which combination of deficits?", options: ["Right hemiplegia and expressive aphasia", "Left hemiplegia, left neglect, impulsive behavior, and spatial-perceptual deficits", "Bilateral lower extremity weakness", "Pure sensory loss without motor involvement"], correctIndex: 1, rationale: "Right MCA stroke causes left hemiplegia (contralateral motor loss), left unilateral neglect, impulsive behavior, poor safety awareness, and spatial-perceptual deficits characteristic of right hemisphere damage.", difficulty: 2, category: "Clinical Scenarios", topic: "Neurological Rehabilitation" },
  { id: "pta-267", stem: "A patient has been immobilized in a cast for 6 weeks after a distal radius fracture. What changes should the PTA expect in the immobilized tissues?", options: ["Increased muscle strength and joint flexibility", "Muscle atrophy, joint stiffness, cartilage changes, and decreased bone density in the immobilized area", "No tissue changes from 6 weeks of immobilization", "Increased bone density"], correctIndex: 1, rationale: "Six weeks of immobilization causes muscle atrophy, joint capsule contracture, articular cartilage degeneration, decreased bone density (Wolff's law), and connective tissue shortening.", difficulty: 1, category: "Clinical Scenarios", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-268", stem: "A patient with L1 SCI is performing mat exercises for functional mobility. Which transfer technique should the PTA train?", options: ["Stand-pivot transfer", "Depression transfer using upper extremities to lift buttocks and swing toward the target surface", "Walk-and-sit transfer", "Independent stepping transfer"], correctIndex: 1, rationale: "L1 SCI results in paraplegia with intact upper extremities. Depression transfers use latissimus dorsi and triceps to lift the buttocks off the surface and swing toward the target — the primary transfer method.", difficulty: 2, category: "Patient Care Planning", topic: "Patient Mobility Techniques" },
  { id: "pta-269", stem: "A PTA notices a patient's skin under a rigid ankle-foot orthosis is red and does not blanch. What does this indicate?", options: ["Normal skin response to orthotic wear", "A stage I pressure injury — the orthosis needs modification and the area should be monitored", "The patient wore the orthosis correctly", "Improved circulation from the orthosis"], correctIndex: 1, rationale: "Non-blanchable redness (erythema) indicates a stage I pressure injury from excessive pressure. The orthosis requires modification (padding, relief) and the area needs monitoring and protection.", difficulty: 2, category: "Safety", topic: "Assistive Devices" },
  { id: "pta-270", stem: "A patient is performing body weight supported treadmill training (BWSTT) after an incomplete SCI. What is the primary benefit of this approach?", options: ["It eliminates the need for any therapist assistance", "It allows repetitive, task-specific locomotor practice with reduced gravitational demand to promote neural recovery", "It is only for cardiovascular fitness", "It replaces all other forms of therapy"], correctIndex: 1, rationale: "BWSTT provides repetitive, task-specific (stepping) practice with body weight support to reduce gravitational demand, promoting locomotor neural circuitry activation and recovery after incomplete SCI.", difficulty: 2, category: "Therapeutic Intervention", topic: "Neurological Rehabilitation" },
  { id: "pta-271", stem: "A patient with carpal tunnel syndrome is performing nerve gliding exercises. What is the purpose of these exercises?", options: ["Strengthening the median nerve", "Facilitating median nerve excursion through the carpal tunnel to reduce adhesion and compression", "Stretching the ulnar nerve", "Building muscle bulk in the thenar eminence"], correctIndex: 1, rationale: "Nerve gliding (neurodynamic) exercises promote median nerve excursion through the carpal tunnel, reducing adhesion formation, decreasing intra-tunnel pressure, and improving nerve mobility.", difficulty: 2, category: "Therapeutic Intervention", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-272", stem: "A patient is performing plyometric exercises as part of a return-to-sport program. What is the physiological basis of plyometrics?", options: ["Isometric muscle contraction only", "The stretch-shortening cycle — a rapid eccentric contraction followed by a powerful concentric contraction", "Slow, controlled movements without impact", "Static stretching at end range"], correctIndex: 1, rationale: "Plyometrics utilize the stretch-shortening cycle: rapid eccentric loading stores elastic energy and activates the stretch reflex, immediately followed by a powerful concentric contraction for explosive force production.", difficulty: 2, category: "Therapeutic Intervention", topic: "Therapeutic Exercise" },
  { id: "pta-273", stem: "A patient with left middle cerebral artery stroke presents with which language deficit?", options: ["No language deficits expected", "Aphasia (expressive, receptive, or global) due to left hemisphere language dominance", "Only right-sided neglect", "Impulsive behavior without language involvement"], correctIndex: 1, rationale: "Left MCA stroke affects the language-dominant hemisphere in most individuals, causing aphasia: Broca's (expressive), Wernicke's (receptive), or global aphasia depending on the extent and location of damage.", difficulty: 2, category: "Clinical Scenarios", topic: "Neurological Rehabilitation" },
  { id: "pta-274", stem: "A patient with ankle instability fails the single-leg stance test. Which intervention progression addresses proprioceptive deficits?", options: ["Only ankle strengthening without balance components", "Single-leg stance on stable surface → foam → wobble board → BOSU, with eyes open → eyes closed progression", "Walking on a treadmill only", "Ankle taping without exercise"], correctIndex: 1, rationale: "Proprioceptive training progresses from stable to unstable surfaces and from eyes-open to eyes-closed conditions, systematically challenging the somatosensory system to improve dynamic ankle stability.", difficulty: 2, category: "Therapeutic Intervention", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-275", stem: "A PTA is treating a burn patient in the acute phase. What is the correct positioning for an axillary burn?", options: ["Shoulder adduction and internal rotation", "Shoulder abduction to 90° with external rotation to prevent axillary contracture", "Shoulder flexion to 180°", "Arm in a sling at the side"], correctIndex: 1, rationale: "Axillary burns tend to contract into shoulder adduction and internal rotation. Anti-contracture positioning places the shoulder in 90° abduction with external rotation and elbow extension.", difficulty: 2, category: "Patient Care Planning", topic: "Rehabilitation Principles" },
  { id: "pta-276", stem: "A patient recovering from a meniscectomy is 6 weeks post-surgery. Which exercise progression is appropriate?", options: ["Return to full sport immediately", "Progress from CKC exercises (mini-squats, leg press) to sport-specific activities with continued strengthening", "Continue strict NWB status", "Only isometric exercises for 6 more months"], correctIndex: 1, rationale: "At 6 weeks post-meniscectomy, progress CKC exercises (mini-squats, leg press, step-ups), begin proprioception training, and gradually introduce sport-specific activities as strength and control improve.", difficulty: 2, category: "Therapeutic Intervention", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-277", stem: "A patient's resting heart rate is 110 bpm. What should the PTA do before initiating exercise?", options: ["Begin exercise at full intensity", "Notify the supervising PT — resting tachycardia (>100 bpm) requires medical clearance before exercise", "This is a normal resting heart rate", "Begin exercise but at reduced intensity"], correctIndex: 1, rationale: "Resting tachycardia (>100 bpm) is abnormal and may indicate cardiac, metabolic, or other medical conditions. The PTA should not exercise the patient without medical clearance and PT notification.", difficulty: 1, category: "Safety", topic: "Therapeutic Exercise" },
  { id: "pta-278", stem: "A patient with a rotator cuff tear demonstrates a positive drop arm test. What does this indicate?", options: ["Biceps tendon pathology", "Significant supraspinatus weakness or tear — the patient cannot maintain the arm in abduction against gravity", "Normal shoulder function", "Subscapularis tear"], correctIndex: 1, rationale: "A positive drop arm test: the patient cannot slowly lower the arm from 90° abduction; it drops suddenly. This indicates significant supraspinatus dysfunction or complete rotator cuff tear.", difficulty: 2, category: "Clinical Scenarios", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-279", stem: "A patient with an above-knee amputation is performing prone lying. What is the purpose of this positioning?", options: ["To increase hip flexion ROM", "To prevent hip flexion contracture by stretching the hip flexors in extension", "To strengthen the hip extensors", "To promote wound healing"], correctIndex: 1, rationale: "Prone lying stretches the hip flexors and prevents hip flexion contracture, which is common after transfemoral amputation due to prolonged sitting in the wheelchair.", difficulty: 1, category: "Patient Care Planning", topic: "Patient Mobility Techniques" },
  { id: "pta-280", stem: "A patient with complete T1 SCI has preserved upper extremity function. Which functional activities should be achievable?", options: ["Independent ambulation", "Independent wheelchair mobility, transfers, and most ADLs using upper extremities", "Only dependent mobility", "Independent running and jumping"], correctIndex: 1, rationale: "T1 SCI preserves all upper extremity muscles (including hand intrinsics). Patients achieve independent wheelchair mobility, depression transfers, upper body ADLs, and often independent self-care.", difficulty: 1, category: "Patient Care Planning", topic: "Neurological Rehabilitation" },
  { id: "pta-281", stem: "A PTA is performing joint mobilization of the tibiofemoral joint. To increase knee flexion, in which direction should the tibial glide be applied?", options: ["Anterior glide of the tibia", "Posterior glide of the tibia on the femur", "Medial glide of the tibia", "Lateral glide of the tibia"], correctIndex: 1, rationale: "The concave-convex rule: the tibia (concave) glides in the same direction as the bone movement. For knee flexion, the tibia glides posteriorly on the convex femoral condyles.", difficulty: 3, category: "Therapeutic Intervention", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-282", stem: "A patient with lower extremity edema is receiving intermittent pneumatic compression. What is a contraindication for this treatment?", options: ["Mild peripheral edema", "Known or suspected DVT in the affected extremity", "Post-mastectomy edema", "Venous insufficiency without DVT"], correctIndex: 1, rationale: "Intermittent pneumatic compression is contraindicated with known or suspected DVT due to the risk of dislodging a thrombus and causing pulmonary embolism.", difficulty: 2, category: "Safety", topic: "Therapeutic Exercise" },
  { id: "pta-283", stem: "A child with torticollis is 6 months old and has not responded to conservative treatment. What should the PTA communicate to the supervising PT?", options: ["Continue the same treatment indefinitely", "Report lack of progress to the PT for reassessment and possible referral for further diagnostic evaluation", "Discharge the child from therapy", "Double the stretching intensity"], correctIndex: 1, rationale: "Failure to respond to conservative torticollis treatment by 6 months warrants PT reassessment and possible referral for imaging or surgical consultation to rule out bony or other structural causes.", difficulty: 2, category: "Patient Care Planning", topic: "Pediatric Rehabilitation" },
  { id: "pta-284", stem: "A patient is performing Nordic hamstring curls. What type of contraction primarily strengthens the hamstrings during this exercise?", options: ["Concentric contraction", "Eccentric contraction — the hamstrings lengthen under load as the body lowers forward", "Isometric contraction", "Isokinetic contraction"], correctIndex: 1, rationale: "Nordic hamstring curls primarily load the hamstrings eccentrically as the body lowers forward under gravity control. This eccentric strengthening has been shown to reduce hamstring injury risk.", difficulty: 2, category: "Therapeutic Intervention", topic: "Therapeutic Exercise" },
  { id: "pta-285", stem: "A patient with shoulder impingement is learning scapular retraction exercises. Why is scapulohumeral rhythm important?", options: ["It has no relevance to shoulder function", "Proper scapular upward rotation and posterior tilt during arm elevation prevents subacromial impingement", "It only affects cervical spine function", "It only affects elbow movement"], correctIndex: 1, rationale: "Normal scapulohumeral rhythm requires scapular upward rotation and posterior tilt as the arm elevates. Poor scapular mechanics reduce subacromial space, contributing to impingement.", difficulty: 2, category: "Therapeutic Intervention", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-286", stem: "A patient is ambulating with a quad cane. On which surface does the quad cane provide the MOST stability?", options: ["Uneven outdoor terrain", "Level, flat indoor surfaces where all four legs can contact the ground simultaneously", "Stairs", "Gravel paths"], correctIndex: 1, rationale: "A quad cane requires all four legs to contact the ground simultaneously for maximum stability. Uneven surfaces may cause tipping if not all legs are grounded. Flat indoor surfaces are ideal.", difficulty: 1, category: "Patient Care Planning", topic: "Assistive Devices" },
  { id: "pta-287", stem: "A patient recovering from a TBI is at Rancho Level VI. What behavior characterizes this level?", options: ["Confused and agitated", "Automatic and appropriate — can perform familiar tasks but with decreased processing", "Purposeful and appropriate with standby assistance", "No response"], correctIndex: 1, rationale: "Rancho Level VI (Confused-Appropriate) features goal-directed behavior with familiar tasks, memory for routine, emerging awareness of deficits, but continued need for supervision and decreased processing speed.", difficulty: 2, category: "Clinical Scenarios", topic: "Neurological Rehabilitation" },
  { id: "pta-288", stem: "A patient with lateral epicondylitis is being treated with eccentric wrist extensor strengthening. What does the exercise involve?", options: ["Rapid wrist flexion movements", "Slowly lowering a weight from wrist extension to flexion (eccentric loading of wrist extensors)", "Isometric wrist extension holds only", "Passive wrist flexion stretching only"], correctIndex: 1, rationale: "Eccentric wrist extensor strengthening: the patient slowly lowers a weight from wrist extension to wrist flexion, eccentrically loading the extensor tendons. This promotes tendon remodeling in tendinopathy.", difficulty: 2, category: "Therapeutic Intervention", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-289", stem: "A PTA is instructing a patient in pelvic floor exercises (Kegels). What is the correct instruction?", options: ["Bear down and push like having a bowel movement", "Contract the pelvic floor muscles as if stopping urine flow, hold for 5-10 seconds, then relax", "Hold the breath tightly during contraction", "Contract the abdominal muscles as hard as possible"], correctIndex: 1, rationale: "Correct Kegel technique: contract the pelvic floor muscles (as if stopping urine flow or holding gas) for 5-10 seconds, then relax completely. Avoid Valsalva, abdominal bracing, or gluteal substitution.", difficulty: 1, category: "Therapeutic Intervention", topic: "Therapeutic Exercise" },
  { id: "pta-290", stem: "A patient is performing resisted cervical rotation to the right. Which muscle is the primary agonist?", options: ["Right sternocleidomastoid", "Left sternocleidomastoid", "Bilateral upper trapezius", "Right scalene"], correctIndex: 1, rationale: "The sternocleidomastoid rotates the head to the opposite side. Therefore, left SCM contraction produces right cervical rotation. The right SCM would produce left rotation.", difficulty: 2, category: "Clinical Scenarios", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-291", stem: "A patient with an acute lateral ankle sprain is in the acute inflammatory phase (first 48-72 hours). What is the appropriate intervention?", options: ["Aggressive stretching and strengthening", "RICE (Rest, Ice, Compression, Elevation) and protected weight-bearing with crutches", "Heat application and deep tissue massage", "Return to sport with ankle taping only"], correctIndex: 1, rationale: "Acute phase (0-72 hours) lateral ankle sprain management: RICE protocol (Rest/relative, Ice, Compression, Elevation) to control inflammation and edema, with protected weight-bearing.", difficulty: 1, category: "Therapeutic Intervention", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-292", stem: "A patient with bilateral transtibial amputations is learning wheelchair mobility. What modification is needed for the wheelchair?", options: ["No modifications needed", "Rear axle set back posteriorly to prevent tipping backward due to the altered center of gravity", "Front casters removed", "Standard wheelchair without modification"], correctIndex: 1, rationale: "Bilateral LE amputation shifts the center of gravity posteriorly. The rear axle must be set back to prevent backward tipping. Anti-tip casters should also be used initially.", difficulty: 2, category: "Safety", topic: "Assistive Devices" },
  { id: "pta-293", stem: "A patient demonstrates positive anterior drawer test at the ankle. Which structure is likely damaged?", options: ["Deltoid ligament", "Anterior talofibular ligament (ATFL)", "Posterior cruciate ligament", "Achilles tendon"], correctIndex: 1, rationale: "A positive anterior drawer test at the ankle indicates laxity of the anterior talofibular ligament (ATFL), the most commonly injured ligament in lateral ankle sprains.", difficulty: 2, category: "Clinical Scenarios", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-294", stem: "A PTA is performing trigger point dry needling on a patient with myofascial pain. What response indicates successful treatment?", options: ["No response from the patient", "A local twitch response in the taut band of muscle", "Severe, lasting pain after treatment", "Complete muscle paralysis"], correctIndex: 1, rationale: "A local twitch response (brief involuntary contraction of the taut band) during dry needling indicates accurate needle placement in the trigger point and is associated with improved treatment outcomes.", difficulty: 2, category: "Therapeutic Intervention", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-295", stem: "A patient with a hip fracture is performing bed mobility exercises. What is the correct log-rolling technique?", options: ["Roll shoulders first, then hips separately", "Cross the arms over the chest, bend the uninvolved knee, and roll as a unit (shoulders and hips together)", "Use only the arms to pull to the side", "Twist at the waist during the roll"], correctIndex: 1, rationale: "Log rolling maintains hip alignment during position changes. Arms crossed, uninvolved knee bent for leverage, and rolling shoulders/hips as a unit prevents unwanted rotation or hip motion.", difficulty: 1, category: "Patient Care Planning", topic: "Patient Mobility Techniques" },
  { id: "pta-296", stem: "A patient with multiple sclerosis is exercising in a pool. What water temperature is recommended for patients with MS?", options: ["Hot water (above 92°F/33°C)", "Cool to tepid water (80-84°F/27-29°C) to prevent Uhthoff phenomenon", "Cold water (below 70°F/21°C)", "Temperature does not matter"], correctIndex: 1, rationale: "Patients with MS should exercise in cool to tepid water (80-84°F) to prevent overheating and Uhthoff phenomenon. Warmer water temperatures can exacerbate neurological symptoms.", difficulty: 2, category: "Safety", topic: "Neurological Rehabilitation" },
  { id: "pta-297", stem: "A patient is performing the star excursion balance test (Y-balance test). What does this test assess?", options: ["Upper extremity strength", "Dynamic balance and neuromuscular control during single-leg stance with reaching in multiple directions", "Cardiovascular endurance", "Spinal flexibility"], correctIndex: 1, rationale: "The star excursion/Y-balance test assesses dynamic balance, neuromuscular control, and lower extremity function by measuring reach distances in multiple directions during single-leg stance.", difficulty: 2, category: "Clinical Scenarios", topic: "Therapeutic Exercise" },
  { id: "pta-298", stem: "A patient with chronic heart failure is classified as NYHA Class III. What does this mean for exercise?", options: ["No limitations during physical activity", "Comfortable at rest but ordinary physical activity results in symptoms; exercise should be carefully prescribed and monitored", "Unable to carry out any physical activity without discomfort", "The patient can perform vigorous exercise"], correctIndex: 1, rationale: "NYHA Class III: comfortable at rest, but less than ordinary physical activity causes fatigue, palpitation, or dyspnea. Exercise must be carefully prescribed, low-intensity, and closely monitored.", difficulty: 2, category: "Patient Care Planning", topic: "Therapeutic Exercise" },
  { id: "pta-299", stem: "A patient demonstrates a valgus collapse pattern of the knee during a single-leg squat. What does this indicate?", options: ["Normal knee mechanics", "Weakness of the hip abductors and external rotators leading to dynamic knee valgus and increased ACL injury risk", "Excessive hamstring strength", "Superior quadriceps control"], correctIndex: 1, rationale: "Dynamic knee valgus during single-leg squat indicates weak hip abductors/external rotators. The femur internally rotates and adducts, causing the knee to collapse medially, increasing ACL injury risk.", difficulty: 2, category: "Clinical Scenarios", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-300", stem: "A PTA is discharging a patient from outpatient PT. Who has the authority to make the discharge decision?", options: ["The PTA independently decides to discharge", "The supervising PT makes the discharge decision based on achievement of goals and clinical assessment", "The patient's family decides when to stop therapy", "The front desk staff determines discharge timing"], correctIndex: 1, rationale: "The supervising PT has the authority and responsibility to make discharge decisions based on goal achievement, functional progress, and clinical assessment. The PTA does not independently discharge patients.", difficulty: 1, category: "Patient Care Planning", topic: "Rehabilitation Principles" },
  { id: "pta-301", stem: "A patient is performing plyometric exercises during phase III ACL rehabilitation. Which exercise is an example of plyometric training?", options: ["Seated knee extension", "Box jumps with rapid deceleration and acceleration", "Stationary cycling at low resistance", "Passive hamstring stretching"], correctIndex: 1, rationale: "Plyometrics involve rapid eccentric loading followed by explosive concentric contraction (stretch-shortening cycle). Box jumps train power and neuromuscular control needed for sport return.", difficulty: 2, category: "Therapeutic Intervention", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-302", stem: "A patient with a T12 SCI is expected to achieve which level of functional mobility?", options: ["Dependent for all mobility", "Community ambulation with bilateral KAFOs and forearm crutches", "Independent wheelchair mobility only — ambulation is not possible", "Normal ambulation without any assistive device"], correctIndex: 1, rationale: "T12 SCI preserves hip flexors and some hip adductors. Community ambulation with bilateral KAFOs and forearm crutches is a realistic goal, along with independent wheelchair mobility.", difficulty: 2, category: "Patient Care Planning", topic: "Neurological Rehabilitation" },
  { id: "pta-303", stem: "A patient is receiving aquatic therapy for lumbar spinal stenosis. What is the PRIMARY benefit of aquatic exercise for this condition?", options: ["Increased spinal compression from water pressure", "Buoyancy-assisted exercise that reduces spinal loading while allowing functional movement", "Colder water temperature reduces inflammation", "Increased gravity forces improve bone density"], correctIndex: 1, rationale: "Buoyancy reduces axial loading on the spine, allowing pain-free exercise. Water provides resistance for strengthening while reducing compressive forces that exacerbate spinal stenosis symptoms.", difficulty: 2, category: "Therapeutic Intervention", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-304", stem: "A patient presents with a positive Ober test. Which structure is tight?", options: ["Hamstrings", "Iliotibial band (ITB) and tensor fascia latae", "Quadriceps", "Hip adductors"], correctIndex: 1, rationale: "The Ober test assesses ITB and TFL tightness. A positive test occurs when the leg cannot adduct past midline in side-lying, indicating ITB/TFL contracture.", difficulty: 2, category: "Clinical Scenarios", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-305", stem: "A patient has a resting heart rate of 110 bpm. Before beginning exercise, the PTA should do what?", options: ["Begin the exercise session as planned", "Withhold exercise and notify the supervising PT — resting tachycardia requires medical clearance", "Increase exercise intensity to improve cardiac conditioning", "Perform only upper extremity exercises"], correctIndex: 1, rationale: "Resting heart rate >100 bpm (tachycardia) is a contraindication to exercise initiation. The PTA should withhold exercise and notify the PT for further assessment and medical clearance.", difficulty: 2, category: "Safety", topic: "Therapeutic Exercise" },
  { id: "pta-306", stem: "A patient with multiple sclerosis is experiencing an exacerbation with new symptoms. What should the PTA do?", options: ["Increase exercise intensity to fight the exacerbation", "Reduce exercise intensity, focus on energy conservation, and notify the supervising PT", "Discharge the patient from physical therapy", "Continue the same exercise program without modification"], correctIndex: 1, rationale: "During MS exacerbation, exercise intensity should be reduced to prevent worsening fatigue and symptoms. Energy conservation is prioritized, and the PT must be notified for plan modification.", difficulty: 2, category: "Safety", topic: "Neurological Rehabilitation" },
  { id: "pta-307", stem: "A patient is performing eccentric quadriceps strengthening for patellar tendinopathy. What does eccentric exercise involve?", options: ["Shortening the muscle while generating force", "Lengthening the muscle while generating force against resistance", "Isometric hold at mid-range", "Passive stretch without muscle activation"], correctIndex: 1, rationale: "Eccentric exercise involves controlled muscle lengthening under load. For patellar tendinopathy, eccentric decline squats load the patellar tendon progressively to promote tendon healing.", difficulty: 2, category: "Therapeutic Intervention", topic: "Therapeutic Exercise" },
  { id: "pta-308", stem: "A patient has undergone a lumbar laminectomy 2 days ago. Which movement should be AVOIDED?", options: ["Walking with an assistive device", "Log-rolling technique for bed mobility", "Trunk flexion, twisting, and heavy lifting", "Ankle pumps in bed"], correctIndex: 2, rationale: "Post-laminectomy precautions include avoiding trunk flexion, rotation/twisting, and heavy lifting to protect the surgical site and prevent complications during early healing.", difficulty: 1, category: "Safety", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-309", stem: "A patient with vestibular hypofunction reports dizziness and imbalance. Which intervention is MOST appropriate?", options: ["Strict bed rest until symptoms resolve", "Vestibular rehabilitation including gaze stabilization exercises and balance training", "Cervical spine manipulation", "Only medication management without exercise"], correctIndex: 1, rationale: "Vestibular rehabilitation for hypofunction includes gaze stabilization (VOR exercises), habituation exercises to reduce dizziness, and balance training to improve postural stability.", difficulty: 2, category: "Therapeutic Intervention", topic: "Neurological Rehabilitation" },
  { id: "pta-310", stem: "A patient with a Colles' fracture has been immobilized for 6 weeks. The cast was just removed. What is the initial focus of PT?", options: ["Aggressive passive stretching to restore full ROM immediately", "Gentle active ROM, edema management, and scar care", "Maximum grip strengthening exercises", "Return to full unrestricted activity immediately"], correctIndex: 1, rationale: "After 6 weeks of immobilization, initial treatment focuses on gentle active ROM to restore mobility, edema management, scar care if surgical, and gradual progression of activities.", difficulty: 1, category: "Therapeutic Intervention", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-311", stem: "A patient performing a bench press exercise is holding their breath and bearing down. What is this called and why is it dangerous?", options: ["Pursed lip breathing — it is beneficial", "Valsalva maneuver — it causes dangerous spikes in blood pressure", "Diaphragmatic breathing — it is recommended", "Aerobic breathing — it is normal during exercise"], correctIndex: 1, rationale: "The Valsalva maneuver (breath holding during exertion) causes dangerous blood pressure spikes by increasing intrathoracic pressure. Patients should exhale during the exertion phase.", difficulty: 1, category: "Safety", topic: "Therapeutic Exercise" },
  { id: "pta-312", stem: "A child with spina bifida at the L3 level is expected to ambulate with which type of orthosis?", options: ["No orthosis needed", "Bilateral KAFOs with forearm crutches", "Bilateral AFOs only", "Reciprocating gait orthosis (RGO)"], correctIndex: 1, rationale: "L3 spina bifida preserves quadriceps function but lacks ankle and knee stabilization below L3. Bilateral KAFOs with forearm crutches provide the needed stability for community ambulation.", difficulty: 2, category: "Patient Care Planning", topic: "Pediatric Rehabilitation" },
  { id: "pta-313", stem: "A patient with a posterior cruciate ligament (PCL) injury should avoid which exercise?", options: ["Closed kinetic chain exercises", "Open kinetic chain hamstring curls with resistance", "Quadriceps strengthening in CKC", "Stationary cycling"], correctIndex: 1, rationale: "Resisted OKC hamstring curls create posterior tibial translation that stresses the healing PCL. CKC exercises are preferred because they create protective anterior tibial forces.", difficulty: 3, category: "Safety", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-314", stem: "A patient recovering from a stroke demonstrates extensor synergy in the lower extremity. Which components are present?", options: ["Hip flexion, knee flexion, ankle dorsiflexion", "Hip extension, adduction, internal rotation; knee extension; ankle plantar flexion with inversion", "Hip abduction, knee flexion, ankle dorsiflexion", "Isolated hip flexion only"], correctIndex: 1, rationale: "Lower extremity extensor synergy includes hip extension/adduction/internal rotation, knee extension, and ankle plantar flexion with inversion — a stereotypical pattern in stroke recovery.", difficulty: 3, category: "Clinical Scenarios", topic: "Neurological Rehabilitation" },
  { id: "pta-315", stem: "A patient is performing Williams flexion exercises for lumbar spondylolisthesis. What is the purpose of these exercises?", options: ["To increase lumbar extension ROM", "To strengthen abdominals and stretch hip flexors, reducing lumbar lordosis and posterior vertebral stress", "To increase spinal compression", "To strengthen the paraspinal extensors"], correctIndex: 1, rationale: "Williams flexion exercises reduce lumbar lordosis by strengthening abdominals and gluteals while stretching hip flexors. This reduces anterior shear force on the vertebrae in spondylolisthesis.", difficulty: 2, category: "Therapeutic Intervention", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-316", stem: "A patient with congestive heart failure (CHF) gains 3 pounds overnight. What should the PTA do?", options: ["Continue treatment as planned", "Withhold exercise and notify the supervising PT — rapid weight gain indicates fluid retention", "Increase exercise intensity to promote fluid loss", "Perform only stretching exercises"], correctIndex: 1, rationale: "Rapid weight gain (>2 lbs overnight or >5 lbs in a week) in CHF indicates fluid retention and worsening heart failure. Exercise should be withheld pending medical evaluation.", difficulty: 2, category: "Safety", topic: "Therapeutic Exercise" },
  { id: "pta-317", stem: "A patient with ankle instability is performing balance training on a BAPS (Biomechanical Ankle Platform System) board. What is this training targeting?", options: ["Cardiovascular endurance", "Proprioceptive and neuromuscular control of the ankle joint", "Upper extremity strengthening", "Lumbar spine flexibility"], correctIndex: 1, rationale: "BAPS board training targets ankle proprioception and neuromuscular control, retraining the mechanoreceptors and dynamic stabilizers to prevent recurrent ankle sprains.", difficulty: 1, category: "Therapeutic Intervention", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-318", stem: "A patient with COPD demonstrates pursed-lip breathing during exercise. Why is this technique beneficial?", options: ["It increases breathing rate", "It creates back pressure that prevents airway collapse and improves gas exchange", "It decreases oxygen intake", "It strengthens the diaphragm directly"], correctIndex: 1, rationale: "Pursed-lip breathing creates positive back pressure in the airways, preventing premature collapse of small airways during exhalation and improving ventilation and gas exchange in COPD.", difficulty: 2, category: "Clinical Scenarios", topic: "Therapeutic Exercise" },
  { id: "pta-319", stem: "A patient is 8 weeks post-Achilles tendon repair. Which activity progression is appropriate?", options: ["Full unrestricted running and jumping", "Progressive weight-bearing, gentle active plantar flexion, and beginning eccentric calf exercises", "Continue non-weight-bearing with no exercise", "Maximum resistance calf raises immediately"], correctIndex: 1, rationale: "At 8 weeks post-Achilles repair, progressive weight-bearing, gentle active motion, and beginning submaximal eccentric exercises are appropriate. Full activity is typically 4-6 months post-surgery.", difficulty: 2, category: "Therapeutic Intervention", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-320", stem: "A patient with peripheral arterial disease (PAD) reports calf pain during walking that resolves with rest. What is this symptom called?", options: ["Neuropathic pain", "Intermittent claudication", "Deep vein thrombosis", "Restless leg syndrome"], correctIndex: 1, rationale: "Intermittent claudication is exercise-induced muscle pain from insufficient arterial blood flow that resolves with rest. It is the hallmark symptom of peripheral arterial disease.", difficulty: 1, category: "Clinical Scenarios", topic: "Therapeutic Exercise" },
  { id: "pta-321", stem: "A patient with a femoral neck fracture fixed with internal fixation is given partial weight-bearing status. How should weight-bearing be measured?", options: ["By the patient's subjective feeling", "Using a bathroom scale to calibrate the allowed weight through the affected limb", "No measurement needed — the patient can bear full weight", "By measuring the patient's body weight only"], correctIndex: 1, rationale: "A bathroom scale helps the patient calibrate the prescribed weight-bearing limit. The patient practices stepping on the scale to feel the allowed amount of force through the affected limb.", difficulty: 1, category: "Patient Care Planning", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-322", stem: "A patient is performing the single-leg stance test and can maintain balance for 5 seconds with eyes open. What does this indicate for an older adult?", options: ["Normal balance — no intervention needed", "Increased fall risk — less than 10 seconds indicates balance impairment", "Excellent balance performance", "The test is not valid for older adults"], correctIndex: 1, rationale: "Single-leg stance <10 seconds with eyes open indicates balance impairment and increased fall risk in older adults. Balance training and fall prevention strategies should be implemented.", difficulty: 2, category: "Clinical Scenarios", topic: "Geriatric Rehabilitation" },
  { id: "pta-323", stem: "A patient with shoulder impingement syndrome demonstrates painful arc between 60° and 120° of abduction. Which structure is likely compressed?", options: ["Biceps tendon at the elbow", "Supraspinatus tendon under the acromion", "Infraspinatus at the posterior shoulder", "Teres major at the axilla"], correctIndex: 1, rationale: "Painful arc between 60-120° of shoulder abduction indicates supraspinatus tendon compression under the coracoacromial arch, characteristic of subacromial impingement syndrome.", difficulty: 2, category: "Clinical Scenarios", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-324", stem: "A patient with a transtibial (below-knee) amputation is wrapping the residual limb. What is the correct wrapping pattern?", options: ["Circular wrapping from proximal to distal", "Figure-of-eight pattern from distal to proximal with more pressure distally", "Random wrapping in any direction", "Tight circular bands at the distal end only"], correctIndex: 1, rationale: "Figure-of-eight wrapping from distal to proximal with greater pressure distally shapes the residual limb into a conical form for prosthetic fitting and prevents distal edema.", difficulty: 2, category: "Patient Care Planning", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-325", stem: "A patient with lumbar spinal stenosis reports increased symptoms with standing and walking but relief with sitting and forward bending. Why?", options: ["Sitting increases spinal loading", "Flexion opens the spinal canal and intervertebral foramina, reducing neural compression", "Extension stretches the nerve roots", "Sitting compresses the spinal cord"], correctIndex: 1, rationale: "Lumbar flexion increases the diameter of the spinal canal and intervertebral foramina, reducing compression of neural structures. Extension narrows these spaces, worsening stenosis symptoms.", difficulty: 2, category: "Clinical Scenarios", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-326", stem: "A patient is performing McKenzie extension exercises for a lumbar disc herniation with posterior/posterolateral protrusion. What is the expected response?", options: ["Pain centralizes and moves from the leg toward the midline back", "Pain worsens and spreads further into the leg", "No change in symptoms", "Pain moves from the back into the leg (peripheralization)"], correctIndex: 0, rationale: "A positive response to McKenzie extension is centralization — pain moving from the periphery (leg) toward the midline (back). This indicates the disc is reducing with extension.", difficulty: 2, category: "Therapeutic Intervention", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-327", stem: "A patient has a grade III lateral ankle sprain. What does grade III indicate?", options: ["Mild stretching with no tear", "Partial ligament tear", "Complete ligament rupture with significant joint instability", "Bone fracture only"], correctIndex: 2, rationale: "Grade III sprain indicates complete ligament rupture with significant joint laxity, swelling, and loss of function. It may require immobilization or surgical repair.", difficulty: 1, category: "Clinical Scenarios", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-328", stem: "A patient with Parkinson's disease has difficulty with bed mobility. Which strategy helps with rolling?", options: ["Sleeping in a recliner to avoid rolling", "Using a satin sheet to reduce friction and teaching rhythmic rocking before rolling", "Adding weighted blankets to increase resistance", "Avoiding all bed mobility practice"], correctIndex: 1, rationale: "Satin sheets reduce friction for easier rolling in Parkinson's disease. Rhythmic rocking generates momentum to overcome bradykinesia and rigidity during bed mobility tasks.", difficulty: 2, category: "Therapeutic Intervention", topic: "Neurological Rehabilitation" },
  { id: "pta-329", stem: "A patient is performing isokinetic exercise at 60°/second. What characterizes this speed?", options: ["Low resistance with high speed", "High resistance with slow speed — optimal for strength gains", "No resistance at any speed", "Variable resistance based on patient effort"], correctIndex: 1, rationale: "Isokinetic exercise at 60°/sec is a slow speed that generates high torque (resistance accommodates to effort). Slow speeds (30-60°/sec) target strength gains, while faster speeds target endurance.", difficulty: 2, category: "Therapeutic Intervention", topic: "Therapeutic Exercise" },
  { id: "pta-330", stem: "A patient with cervical radiculopathy at C6 would present with which motor and sensory deficit?", options: ["Deltoid weakness and lateral arm numbness", "Wrist extensor weakness and numbness of the thumb and index finger", "Triceps weakness and middle finger numbness", "Intrinsic hand muscle weakness and ulnar-sided numbness"], correctIndex: 1, rationale: "C6 radiculopathy affects wrist extensors (weakness), biceps reflex (diminished), and causes sensory changes in the thumb and index finger (lateral forearm and hand).", difficulty: 2, category: "Clinical Scenarios", topic: "Neurological Rehabilitation" },
  { id: "pta-331", stem: "A patient is performing the 6-Minute Walk Test (6MWT). What is this test measuring?", options: ["Maximum sprint speed", "Submaximal cardiovascular endurance and functional exercise capacity", "Lower extremity strength only", "Balance ability exclusively"], correctIndex: 1, rationale: "The 6MWT measures submaximal aerobic capacity and functional endurance. The total distance walked in 6 minutes correlates with cardiovascular fitness and overall functional status.", difficulty: 1, category: "Clinical Scenarios", topic: "Therapeutic Exercise" },
  { id: "pta-332", stem: "A patient with medial epicondylitis has pain with what movement?", options: ["Resisted wrist extension", "Resisted wrist flexion and pronation", "Shoulder abduction", "Knee flexion"], correctIndex: 1, rationale: "Medial epicondylitis (golfer's elbow) involves the wrist flexor/pronator group at the medial epicondyle. Pain is reproduced with resisted wrist flexion and forearm pronation.", difficulty: 2, category: "Clinical Scenarios", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-333", stem: "A patient is using TENS for chronic low back pain. Which setting is appropriate for chronic pain management?", options: ["High frequency (80-120 Hz) with short pulse duration for sensory-level stimulation", "Maximum intensity causing visible muscle contraction", "Single pulse every 10 seconds", "No frequency setting is needed for TENS"], correctIndex: 0, rationale: "Conventional TENS for chronic pain uses high frequency (80-120 Hz), short pulse duration, and sensory-level intensity (comfortable tingling). This activates the gate control mechanism.", difficulty: 2, category: "Therapeutic Intervention", topic: "Therapeutic Exercise" },
  { id: "pta-334", stem: "A patient with a total knee replacement is 4 weeks post-surgery and has 85° of knee flexion. What is the typical ROM goal at this stage?", options: ["Full extension to 130° flexion", "0° extension to 90° flexion or greater", "Only 45° of flexion is expected", "Full ROM is expected by 2 weeks"], correctIndex: 1, rationale: "At 4 weeks post-TKR, the target is 0° extension and at least 90° flexion. 90° is needed for basic functional activities like sitting, stair climbing, and car transfers.", difficulty: 2, category: "Patient Care Planning", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-335", stem: "A patient with a L4-L5 disc herniation has a positive straight leg raise test at 40°. What does this indicate?", options: ["Normal flexibility", "Sciatic nerve irritation or compression", "Hip joint pathology", "Quadriceps weakness"], correctIndex: 1, rationale: "A positive SLR test (reproduction of radicular symptoms at 30-70°) indicates sciatic nerve root irritation or compression, commonly from L4-L5 or L5-S1 disc herniation.", difficulty: 2, category: "Clinical Scenarios", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-336", stem: "A patient with hemiplegia demonstrates circumduction gait pattern on the affected side. What causes this compensatory pattern?", options: ["Strong hip flexors on the affected side", "Inability to flex the hip and knee adequately during swing phase due to spasticity or weakness", "Excessive ankle dorsiflexion", "Contralateral hip abductor weakness"], correctIndex: 1, rationale: "Circumduction gait occurs when the patient swings the stiff, extended affected leg in a semicircle to clear the foot. It compensates for inability to flex hip and knee during swing phase.", difficulty: 2, category: "Clinical Scenarios", topic: "Neurological Rehabilitation" },
  { id: "pta-337", stem: "A patient is being treated with ultrasound over the anterior thigh. Which parameter is CONTRAINDICATED?", options: ["Pulsed mode at 20% duty cycle", "Continuous mode directly over the femoral artery", "1 MHz frequency for deep heating", "Intensity of 1.0 W/cm²"], correctIndex: 1, rationale: "Continuous ultrasound directly over major blood vessels (femoral artery) is contraindicated due to risk of thrombus dislodgement and tissue damage from sustained thermal effects.", difficulty: 2, category: "Safety", topic: "Therapeutic Exercise" },
  { id: "pta-338", stem: "A child with torticollis demonstrates a flattened occiput on the preferred side. What is this associated condition called?", options: ["Craniosynostosis", "Positional plagiocephaly", "Hydrocephalus", "Microcephaly"], correctIndex: 1, rationale: "Positional plagiocephaly (flattened skull) commonly occurs with torticollis due to persistent head positioning on one side. PT addresses both torticollis and repositioning to correct plagiocephaly.", difficulty: 1, category: "Clinical Scenarios", topic: "Pediatric Rehabilitation" },
  { id: "pta-339", stem: "A patient with chronic obstructive pulmonary disease (COPD) is performing diaphragmatic breathing. Where should the PTA place their hands to facilitate this?", options: ["On the patient's shoulders", "One hand on the upper chest and one on the abdomen below the xiphoid process", "On the patient's back only", "On the patient's sides at rib level only"], correctIndex: 1, rationale: "Hands are placed on the upper chest (to monitor for excessive accessory muscle use) and on the abdomen (to feel the diaphragm descend during inhalation), facilitating proper technique.", difficulty: 1, category: "Therapeutic Intervention", topic: "Therapeutic Exercise" },
  { id: "pta-340", stem: "A patient with a grade II MCL sprain of the knee is how many weeks post-injury to begin controlled ROM exercises?", options: ["Immediately with no protection", "1-2 weeks with hinged knee brace protection", "8 weeks — no movement until fully healed", "Only after surgical repair"], correctIndex: 1, rationale: "Grade II MCL sprains are typically managed conservatively. Controlled ROM in a hinged brace begins at 1-2 weeks to prevent stiffness while protecting the healing ligament.", difficulty: 2, category: "Patient Care Planning", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-341", stem: "A patient with Guillain-Barré syndrome (GBS) is in the recovery phase. Which exercise approach is recommended?", options: ["High-intensity aerobic exercise to fatigue", "Gentle progressive strengthening avoiding fatigue, with frequent rest breaks", "No exercise until full recovery", "Only passive ROM for 6 months"], correctIndex: 1, rationale: "In GBS recovery, gentle progressive strengthening is key. Overwork weakness can occur if muscles are fatigued. Exercise should stay below fatigue levels with frequent rest periods.", difficulty: 2, category: "Therapeutic Intervention", topic: "Neurological Rehabilitation" },
  { id: "pta-342", stem: "A patient with adhesive capsulitis has a capsular pattern of restriction at the shoulder. What is this pattern?", options: ["Internal rotation most limited, then flexion, then external rotation", "External rotation most limited, then abduction, then internal rotation", "Flexion most limited with no rotation limitation", "Only extension is limited"], correctIndex: 1, rationale: "The glenohumeral capsular pattern limits external rotation most, then abduction, then internal rotation. This pattern distinguishes capsular restriction from other causes of limited ROM.", difficulty: 3, category: "Clinical Scenarios", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-343", stem: "A patient is performing body weight-supported treadmill training (BWSTT) after incomplete SCI. What is the primary goal?", options: ["Upper extremity strengthening", "Retraining the locomotor pattern through repetitive stepping with partial body weight support", "Improving sitting balance only", "Stretching the hip flexors"], correctIndex: 1, rationale: "BWSTT uses task-specific repetitive stepping to retrain locomotor neural circuits. Body weight support allows patients to practice walking patterns that they cannot perform at full body weight.", difficulty: 2, category: "Therapeutic Intervention", topic: "Neurological Rehabilitation" },
  { id: "pta-344", stem: "A patient with plantar fasciitis has morning heel pain that improves after walking. Which initial intervention is MOST appropriate?", options: ["High-impact running program", "Night splint to maintain ankle dorsiflexion, plantar fascia stretching, and ice massage", "Corticosteroid injection by the PTA", "Immediate surgical referral"], correctIndex: 1, rationale: "Night splints maintain the plantar fascia in a lengthened position, reducing morning pain. Combined with stretching, ice massage, and activity modification, conservative treatment is first-line.", difficulty: 1, category: "Therapeutic Intervention", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-345", stem: "A patient with type 2 diabetes is exercising. Which sign indicates the PTA should stop exercise immediately?", options: ["Mild sweating", "Symptoms of hypoglycemia: shakiness, confusion, dizziness, and cold sweats", "Normal breathing rate", "Slight muscle fatigue"], correctIndex: 1, rationale: "Hypoglycemia (blood glucose <70 mg/dL) is a medical emergency during exercise. Symptoms include shakiness, confusion, dizziness, and sweating. Stop exercise and provide fast-acting glucose.", difficulty: 2, category: "Safety", topic: "Therapeutic Exercise" },
  { id: "pta-346", stem: "A patient is performing cervical stabilization exercises. What is the primary goal of these exercises?", options: ["Increasing cervical ROM to maximum", "Strengthening the deep cervical flexors and extensors to improve dynamic spinal stability", "Mobilizing the cervical vertebrae", "Stretching the cervical spine into end-range flexion"], correctIndex: 1, rationale: "Cervical stabilization targets the deep cervical flexors (longus colli, longus capitis) and extensors to improve segmental stability, reducing pain and preventing recurrence of cervical dysfunction.", difficulty: 2, category: "Therapeutic Intervention", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-347", stem: "A patient post-stroke demonstrates pusher syndrome. What characterizes this condition?", options: ["The patient pushes toward the unaffected side", "The patient actively pushes toward the affected/hemiplegic side, resisting correction to midline", "The patient pulls themselves forward with both arms", "The patient has no postural abnormalities"], correctIndex: 1, rationale: "Pusher syndrome involves the patient actively pushing toward the hemiplegic side with the unaffected extremities and resisting passive correction toward midline, complicating rehabilitation.", difficulty: 3, category: "Clinical Scenarios", topic: "Neurological Rehabilitation" },
  { id: "pta-348", stem: "A patient with a total hip replacement (posterior approach) is getting into a car. Which technique is safest?", options: ["Step into the car normally without precautions", "Back up to the car seat, sit first, then swing both legs in while maintaining hip precautions", "Climb in through the opposite side of the car", "Kneel on the seat first then turn around"], correctIndex: 1, rationale: "For posterior THR precautions, the patient backs up to the car, sits on the seat first (keeping the operated leg extended), then pivots and swings both legs into the car maintaining precautions.", difficulty: 2, category: "Patient Care Planning", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-349", stem: "A patient with a transfemoral (above-knee) amputation develops a hip flexion contracture. What is the BEST positioning strategy?", options: ["Sitting in a wheelchair with hip flexed at all times", "Prone lying for 20-30 minutes several times daily to stretch the hip flexors", "Elevating the residual limb on pillows", "Side-lying with the hip flexed"], correctIndex: 1, rationale: "Prone lying provides sustained hip extension stretch to prevent and correct hip flexion contractures, which impair prosthetic gait. Avoiding prolonged sitting is also essential.", difficulty: 2, category: "Patient Care Planning", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-350", stem: "A patient is performing resistive exercise and experiences sharp chest pain and shortness of breath. What should the PTA do?", options: ["Have the patient work through the pain", "Stop exercise immediately, monitor vital signs, activate emergency response if symptoms persist", "Reduce the resistance and continue", "Have the patient perform deep breathing and continue"], correctIndex: 1, rationale: "Chest pain during exercise is a medical emergency sign. The PTA must stop exercise immediately, monitor vital signs, keep the patient calm, and activate emergency medical services.", difficulty: 1, category: "Safety", topic: "Therapeutic Exercise" },
  { id: "pta-351", stem: "A patient with a rotator cuff tear is performing Codman's (pendulum) exercises. What is the purpose?", options: ["Strengthening the rotator cuff muscles", "Providing gentle passive/active-assisted joint distraction and ROM through gravity and momentum", "Increasing cardiovascular endurance", "Stretching the biceps tendon"], correctIndex: 1, rationale: "Pendulum exercises use gravity and gentle arm swinging to provide joint distraction and early ROM without active rotator cuff contraction, minimizing stress on the healing tissue.", difficulty: 1, category: "Therapeutic Intervention", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-352", stem: "A patient with an L5 nerve root lesion would present with weakness in which muscle?", options: ["Quadriceps (knee extension)", "Extensor hallucis longus (great toe extension)", "Gastrocnemius (plantar flexion)", "Hip adductors"], correctIndex: 1, rationale: "L5 nerve root innervates the extensor hallucis longus, tibialis anterior, and gluteus medius. Weakness of great toe extension is a key indicator of L5 radiculopathy.", difficulty: 2, category: "Clinical Scenarios", topic: "Neurological Rehabilitation" },
  { id: "pta-353", stem: "A patient is performing aquatic exercises in a therapy pool at 92°F. Which patient population should NOT exercise at this temperature?", options: ["Post-surgical orthopedic patients", "Patients with multiple sclerosis", "Patients with osteoarthritis", "Patients with muscle strains"], correctIndex: 1, rationale: "Patients with MS are heat-sensitive (Uhthoff's phenomenon). Warm water temperatures can worsen neurological symptoms. A cooler pool temperature (80-84°F) is recommended for MS patients.", difficulty: 2, category: "Safety", topic: "Neurological Rehabilitation" },
  { id: "pta-354", stem: "A patient with sacroiliac (SI) joint dysfunction presents with a positive FABER (Patrick's) test. What does this test assess?", options: ["ACL integrity", "Hip, SI joint, and sacroiliac pathology", "Ankle stability", "Cervical spine mobility"], correctIndex: 1, rationale: "The FABER test (Flexion, ABduction, External Rotation) stresses the hip and SI joint. A positive test (pain at the SI region) suggests SI joint dysfunction, hip pathology, or both.", difficulty: 2, category: "Clinical Scenarios", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-355", stem: "A patient with hemiplegia has developed shoulder-hand syndrome (complex regional pain syndrome). What are the typical findings?", options: ["Shoulder stiffness only", "Shoulder pain, hand edema, vasomotor changes, and eventual joint contractures if untreated", "Numbness without pain", "Isolated wrist pain only"], correctIndex: 1, rationale: "Shoulder-hand syndrome (CRPS Type I) post-stroke involves shoulder pain, diffuse hand edema, skin color/temperature changes, and can progress to joint contractures and skin atrophy.", difficulty: 3, category: "Clinical Scenarios", topic: "Neurological Rehabilitation" },
  { id: "pta-356", stem: "A patient with osteoarthritis of the knee has a varus deformity. Which compartment is primarily affected?", options: ["Lateral compartment", "Medial compartment", "Patellofemoral compartment", "Posterior compartment"], correctIndex: 1, rationale: "Varus (bow-legged) deformity in knee OA indicates medial compartment degeneration. The narrowing of the medial joint space increases varus angulation progressively.", difficulty: 2, category: "Clinical Scenarios", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-357", stem: "A patient is performing Nordic hamstring exercises as part of a hamstring injury prevention program. What type of contraction does this exercise emphasize?", options: ["Concentric quadriceps", "Eccentric hamstring contraction", "Isometric hip flexion", "Concentric calf"], correctIndex: 1, rationale: "Nordic hamstring exercises emphasize eccentric hamstring contraction, which has strong evidence for preventing hamstring strain injuries by strengthening the muscle during lengthening.", difficulty: 2, category: "Therapeutic Intervention", topic: "Therapeutic Exercise" },
  { id: "pta-358", stem: "A patient with a tibial plateau fracture is 6 weeks post-ORIF. Weight-bearing status has been progressed to WBAT. What does WBAT mean?", options: ["No weight on the affected leg", "Weight-bearing as tolerated — the patient can bear as much weight as comfort allows", "Toe-touch weight-bearing only", "Only 25% of body weight allowed"], correctIndex: 1, rationale: "WBAT (weight-bearing as tolerated) allows the patient to bear as much weight as they can comfortably tolerate through the affected extremity, using pain as a guide.", difficulty: 1, category: "Patient Care Planning", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-359", stem: "A patient with an upper motor neuron lesion demonstrates which type of bladder dysfunction?", options: ["Flaccid bladder with overflow incontinence", "Spastic (reflex) bladder with involuntary emptying", "Normal bladder function", "Stress incontinence only"], correctIndex: 1, rationale: "Upper motor neuron lesions cause spastic/reflex bladder — the bladder empties reflexively when full without voluntary control. The detrusor muscle contracts involuntarily.", difficulty: 3, category: "Clinical Scenarios", topic: "Neurological Rehabilitation" },
  { id: "pta-360", stem: "A patient is being treated with phonophoresis. What does this modality involve?", options: ["Using sound waves alone for deep heating", "Using ultrasound to drive topical medication (typically anti-inflammatory) into tissue", "Electrical stimulation to reduce pain", "Application of cold packs with ultrasound gel"], correctIndex: 1, rationale: "Phonophoresis uses therapeutic ultrasound to enhance transdermal delivery of topical medications (commonly anti-inflammatory agents) into deeper tissues for local treatment.", difficulty: 2, category: "Therapeutic Intervention", topic: "Therapeutic Exercise" },
  { id: "pta-361", stem: "A patient with bilateral lower extremity weakness is using a rolling walker. The PTA observes the patient leaning heavily on the walker with a flexed posture. What should the PTA address?", options: ["Encourage the patient to lean more on the walker for support", "Adjust walker height, cue upright posture, and consider if a different assistive device is needed", "Switch to crutches immediately", "Discontinue all ambulation training"], correctIndex: 1, rationale: "Excessive leaning and flexed posture indicate the walker height may be incorrect or the patient needs postural cueing. Proper walker height allows slight elbow flexion (20-30°) and upright posture.", difficulty: 1, category: "Patient Care Planning", topic: "Assistive Devices" },
  { id: "pta-362", stem: "A patient with chronic ankle instability has peroneal muscle weakness. Which exercise targets these muscles?", options: ["Ankle inversion with resistance", "Ankle eversion with resistance band", "Toe curls", "Knee extension"], correctIndex: 1, rationale: "The peroneal (fibularis) muscles produce ankle eversion. Resistive eversion exercises strengthen these lateral stabilizers, critical for preventing recurrent inversion ankle sprains.", difficulty: 1, category: "Therapeutic Intervention", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-363", stem: "A patient with a cerebellar lesion presents with which characteristic movement deficit?", options: ["Spasticity and clonus", "Ataxia, dysmetria, intention tremor, and dysdiadochokinesia", "Flaccid paralysis only", "Cogwheel rigidity"], correctIndex: 1, rationale: "Cerebellar lesions cause coordination deficits: ataxia (uncoordinated movement), dysmetria (past-pointing), intention tremor, and dysdiadochokinesia (inability to perform rapid alternating movements).", difficulty: 2, category: "Clinical Scenarios", topic: "Neurological Rehabilitation" },
  { id: "pta-364", stem: "A patient is performing a squat exercise and the PTA observes the knees moving medially past the toes (dynamic valgus). What does this indicate?", options: ["Excellent squat form", "Hip abductor and external rotator weakness contributing to poor lower extremity mechanics", "Ankle mobility restriction only", "Normal alignment that requires no correction"], correctIndex: 1, rationale: "Dynamic knee valgus during squatting indicates weakness of hip abductors and external rotators (gluteus medius/maximus), which is a risk factor for ACL injury and patellofemoral pain.", difficulty: 2, category: "Clinical Scenarios", topic: "Therapeutic Exercise" },
  { id: "pta-365", stem: "A patient with a C7 cervical radiculopathy has weakness in which muscle?", options: ["Deltoid", "Biceps", "Triceps", "Wrist flexors only"], correctIndex: 2, rationale: "C7 radiculopathy primarily affects the triceps (elbow extension), wrist flexors, and finger extensors. The triceps reflex is diminished, and numbness occurs in the middle finger.", difficulty: 2, category: "Clinical Scenarios", topic: "Neurological Rehabilitation" },
  { id: "pta-366", stem: "A patient with lymphedema of the upper extremity is receiving complete decongestive therapy (CDT). Which component is NOT part of CDT?", options: ["Manual lymphatic drainage", "Short-stretch compression bandaging", "Vigorous deep tissue massage of the affected limb", "Decongestive exercises"], correctIndex: 2, rationale: "CDT includes manual lymphatic drainage, short-stretch bandaging, decongestive exercises, and skin care. Vigorous deep tissue massage is contraindicated as it can damage lymphatic vessels.", difficulty: 2, category: "Safety", topic: "Therapeutic Exercise" },
  { id: "pta-367", stem: "A patient with a meniscal tear demonstrates a positive McMurray test. What maneuver produces a positive result?", options: ["Anterior drawer of the tibia", "Knee flexion/extension with tibial rotation producing a click or pain at the joint line", "Valgus stress at the knee", "Compression of the patella against the femur"], correctIndex: 1, rationale: "McMurray test involves flexing the knee, applying tibial rotation (internal for lateral meniscus, external for medial), and extending. A positive result is a palpable click or pain at the joint line.", difficulty: 2, category: "Clinical Scenarios", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-368", stem: "A child with developmental delay is unable to sit independently at 10 months. According to developmental milestones, when should independent sitting be achieved?", options: ["3 months", "6-8 months", "12 months", "18 months"], correctIndex: 1, rationale: "Independent sitting without support typically develops by 6-8 months. Inability to sit independently at 10 months suggests motor delay warranting further evaluation and intervention.", difficulty: 1, category: "Clinical Scenarios", topic: "Pediatric Rehabilitation" },
  { id: "pta-369", stem: "A patient with an S1 nerve root lesion would have a diminished or absent reflex at which location?", options: ["Patellar (L3-L4)", "Achilles (S1-S2)", "Biceps (C5-C6)", "Brachioradialis (C5-C6)"], correctIndex: 1, rationale: "The Achilles (ankle jerk) reflex is mediated by S1-S2 nerve roots. An S1 lesion diminishes or abolishes this reflex, along with causing gastrocnemius weakness and lateral foot numbness.", difficulty: 2, category: "Clinical Scenarios", topic: "Neurological Rehabilitation" },
  { id: "pta-370", stem: "A patient is performing blood flow restriction (BFR) training with low-load resistance. What is the physiological rationale?", options: ["BFR increases bone density directly", "Partial venous occlusion creates a local hypoxic environment that stimulates muscle hypertrophy at lower loads", "BFR eliminates the need for any resistance", "BFR only works for cardiovascular training"], correctIndex: 1, rationale: "BFR partially restricts venous return, creating local metabolic stress and hypoxia that promote muscle hypertrophy and strength gains at 20-30% 1RM — useful when high loads are contraindicated.", difficulty: 3, category: "Therapeutic Intervention", topic: "Therapeutic Exercise" },
  { id: "pta-371", stem: "A patient with a cervical spinal cord injury at C4 is being evaluated for respiratory function. What is the PRIMARY concern?", options: ["Lower extremity circulation", "Diaphragm function — C4 SCI may compromise phrenic nerve (C3-C5) innervation", "Upper extremity dexterity", "Bladder function"], correctIndex: 1, rationale: "The phrenic nerve (C3-C5) innervates the diaphragm. C4 SCI may partially or fully compromise diaphragmatic function, making respiratory insufficiency the primary life-threatening concern.", difficulty: 2, category: "Safety", topic: "Neurological Rehabilitation" },
  { id: "pta-372", stem: "A patient with thoracic outlet syndrome has symptoms that worsen with the Roos test (elevated arm stress test). What does a positive test indicate?", options: ["Carpal tunnel syndrome", "Compression of the neurovascular bundle in the thoracic outlet region", "Rotator cuff tear", "Cervical disc herniation"], correctIndex: 1, rationale: "A positive Roos test (reproduction of symptoms during 3 minutes of overhead arm opening/closing) indicates compression of the brachial plexus and/or subclavian vessels in the thoracic outlet.", difficulty: 2, category: "Clinical Scenarios", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-373", stem: "A patient with osteoporosis is beginning a weight-bearing exercise program. Which exercise is MOST appropriate?", options: ["Weighted trunk flexion exercises", "Weight-bearing walking program with standing resistance exercises", "Gymnastics and high-impact jumping", "Heavy deadlifts at maximum resistance"], correctIndex: 1, rationale: "Weight-bearing exercises like walking and standing resistance exercises promote bone formation through mechanical loading while avoiding high fracture risk activities and spinal flexion.", difficulty: 1, category: "Therapeutic Intervention", topic: "Geriatric Rehabilitation" },
  { id: "pta-374", stem: "A patient with a brachial plexus injury (Erb-Duchenne palsy, C5-C6) presents with the upper extremity in which position?", options: ["Elbow flexed, forearm supinated, wrist extended", "Shoulder internally rotated, elbow extended, forearm pronated — 'waiter's tip' position", "Claw hand with intrinsic muscle paralysis", "Wrist drop with finger extension paralysis"], correctIndex: 1, rationale: "Erb-Duchenne palsy (C5-C6) results in the 'waiter's tip' position: shoulder adducted and internally rotated, elbow extended, forearm pronated, with loss of deltoid, biceps, and rotator cuff function.", difficulty: 3, category: "Clinical Scenarios", topic: "Neurological Rehabilitation" },
  { id: "pta-375", stem: "A patient with a knee flexion contracture of 15° is having difficulty with gait. At what point in the gait cycle is this contracture MOST problematic?", options: ["Initial swing", "Mid-swing", "Terminal stance — the knee cannot fully extend for push-off", "Pre-swing"], correctIndex: 2, rationale: "A knee flexion contracture prevents full knee extension needed during terminal stance for efficient push-off. This reduces stride length and increases energy expenditure during gait.", difficulty: 2, category: "Clinical Scenarios", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-376", stem: "A patient is performing a wall slide exercise. Which muscles are being primarily targeted?", options: ["Biceps", "Quadriceps and gluteals in a closed kinetic chain", "Hamstrings only", "Abdominal muscles only"], correctIndex: 1, rationale: "Wall slides are a CKC exercise targeting the quadriceps and gluteals through a controlled squat motion with back support, providing a safe progressive strengthening exercise post-knee surgery.", difficulty: 1, category: "Therapeutic Intervention", topic: "Therapeutic Exercise" },
  { id: "pta-377", stem: "A patient with Down syndrome has atlantoaxial instability. Which precaution is essential during physical therapy?", options: ["No activity restrictions are needed", "Avoid cervical flexion, extension, and rotational activities that stress the atlantoaxial joint", "Only perform cervical manipulation", "Encourage gymnastics and contact sports"], correctIndex: 1, rationale: "Atlantoaxial instability in Down syndrome creates risk of spinal cord compression. Avoid activities requiring cervical flexion/extension/rotation (headstands, somersaults, contact sports).", difficulty: 2, category: "Safety", topic: "Pediatric Rehabilitation" },
  { id: "pta-378", stem: "A patient with lateral ankle sprain is progressing through rehabilitation. Which return-to-sport criterion should be met?", options: ["Absence of swelling only", "Full ROM, 90% strength compared to uninvolved side, successful completion of sport-specific agility tests, and functional brace if needed", "Ability to walk without pain", "Two weeks since the injury regardless of function"], correctIndex: 1, rationale: "Return-to-sport criteria include full ROM, near-normal strength (≥90% of uninvolved side), successful sport-specific functional testing, and confidence in the ankle during dynamic activities.", difficulty: 2, category: "Patient Care Planning", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-379", stem: "A patient with amyotrophic lateral sclerosis (ALS) is in early stages. Which exercise prescription is appropriate?", options: ["High-intensity resistance training to maximize strength", "Moderate submaximal exercise avoiding overwork weakness, with emphasis on functional mobility", "No exercise — only stretching", "Maximum endurance training"], correctIndex: 1, rationale: "Early ALS exercise should be moderate and submaximal to maintain function without causing overwork weakness. Excessive fatigue can accelerate motor neuron degeneration.", difficulty: 2, category: "Therapeutic Intervention", topic: "Neurological Rehabilitation" },
  { id: "pta-380", stem: "A patient is performing the Y-Balance Test as part of return-to-sport assessment after ACL reconstruction. What does this test measure?", options: ["Maximum jumping distance", "Dynamic balance and neuromuscular control comparing involved to uninvolved limbs", "Cardiovascular endurance", "Isolated muscle strength"], correctIndex: 1, rationale: "The Y-Balance Test assesses dynamic postural control by measuring reach distances in three directions while balancing on one leg, comparing symmetry between limbs.", difficulty: 2, category: "Clinical Scenarios", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-381", stem: "A patient is recovering from a burn injury to the dorsum of the hand. What is the anti-deformity position?", options: ["Wrist flexion, MCP extension, IP flexion", "Wrist extension, MCP flexion 70-90°, IP extension, thumb abduction — the intrinsic-plus position", "Full fist position", "All joints in neutral"], correctIndex: 1, rationale: "Dorsal hand burn anti-deformity position mirrors the safe position: wrist extension, MCPs flexed 70-90°, IPs extended, thumb abducted to prevent the typical claw hand burn contracture.", difficulty: 2, category: "Patient Care Planning", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-382", stem: "A patient with Parkinson's disease has postural instability. Which exercise is MOST evidence-based for improving balance?", options: ["Isolated bicep curls", "Tai chi or dance-based balance training programs", "Bed exercises only", "Passive stretching of the lower extremities"], correctIndex: 1, rationale: "Tai chi and dance-based programs have strong evidence for improving balance, reducing falls, and enhancing postural stability in Parkinson's disease through multidirectional weight shifting.", difficulty: 2, category: "Therapeutic Intervention", topic: "Neurological Rehabilitation" },
  { id: "pta-383", stem: "A patient receiving cryotherapy develops bright red skin, welts, and reports itching. What should the PTA do?", options: ["Continue the cold application", "Remove the cold immediately — these signs suggest cold hypersensitivity or cold urticaria", "Apply more ice to the area", "Wrap the area tighter"], correctIndex: 1, rationale: "Red skin, welts, and itching during cryotherapy indicate cold hypersensitivity or cold urticaria, an adverse reaction. Cold must be removed immediately and the PT notified.", difficulty: 1, category: "Safety", topic: "Therapeutic Exercise" },
  { id: "pta-384", stem: "A patient with a posterior hip dislocation (not surgical) should avoid which combined movement?", options: ["Hip abduction with external rotation", "Hip flexion, adduction, and internal rotation", "Hip extension in neutral", "Ankle dorsiflexion exercises"], correctIndex: 1, rationale: "Posterior hip dislocation occurs with flexion, adduction, and internal rotation. This combined position must be avoided during recovery to prevent recurrent dislocation.", difficulty: 2, category: "Safety", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-385", stem: "A patient with ankylosing spondylitis should perform which type of exercise to maintain spinal mobility?", options: ["Spinal flexion exercises exclusively", "Extension-based exercises and deep breathing to maintain chest expansion and upright posture", "High-impact aerobics", "No exercise — complete rest is recommended"], correctIndex: 1, rationale: "Ankylosing spondylitis causes spinal fusion in flexion. Extension exercises and deep breathing maintain chest expansion, upright posture, and delay the progressive kyphotic deformity.", difficulty: 2, category: "Therapeutic Intervention", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-386", stem: "A patient is being assessed with the Functional Reach Test. A forward reach of less than 6 inches indicates what?", options: ["Normal balance", "Very high fall risk requiring immediate intervention", "Excellent dynamic stability", "The test is not valid"], correctIndex: 1, rationale: "Functional Reach Test: <6 inches indicates significant fall risk, 6-10 inches indicates moderate fall risk, and >10 inches indicates low fall risk. Less than 6 inches warrants immediate intervention.", difficulty: 2, category: "Clinical Scenarios", topic: "Geriatric Rehabilitation" },
  { id: "pta-387", stem: "A patient with a transtibial amputation is learning prosthetic gait. What is a common gait deviation seen with poor socket fit?", options: ["Normal step length", "Lateral trunk lean toward the prosthetic side (abducted gait) indicating socket discomfort", "Increased speed of gait", "Excessive knee flexion on the sound side"], correctIndex: 1, rationale: "Lateral trunk lean and abducted gait on the prosthetic side often indicate poor socket fit (medial wall discomfort). Socket adjustment is needed before gait training can progress.", difficulty: 2, category: "Clinical Scenarios", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-388", stem: "A patient with a rotator cuff repair is performing scapular stabilization exercises. Why are these important?", options: ["They directly heal the rotator cuff", "Scapular stability provides the foundation for glenohumeral function and prevents impingement", "They increase cervical ROM", "They are only done for cosmetic reasons"], correctIndex: 1, rationale: "The scapula provides the stable base for rotator cuff function. Scapular stabilization (serratus anterior, lower trapezius) ensures proper glenohumeral mechanics and prevents impingement.", difficulty: 2, category: "Therapeutic Intervention", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-389", stem: "A patient with myofascial pain syndrome has a trigger point in the upper trapezius. Which finding is characteristic?", options: ["Joint hypermobility", "Taut band with a hypersensitive nodule that refers pain when compressed", "Complete muscle paralysis", "Excessive joint effusion"], correctIndex: 1, rationale: "Myofascial trigger points present as palpable taut bands with hypersensitive nodules that produce local tenderness and predictable referred pain patterns when compressed.", difficulty: 2, category: "Clinical Scenarios", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-390", stem: "A patient post-stroke is learning to transfer using a stand-pivot technique. What is the correct sequence?", options: ["Stand, then position feet, then pivot", "Scoot to edge of surface, position feet flat, lean forward ('nose over toes'), stand, pivot on the stronger leg, and sit controlled", "Jump up from the wheelchair quickly", "Roll off the surface onto feet"], correctIndex: 1, rationale: "Stand-pivot transfer sequence: scoot forward, feet flat and shoulder-width apart, lean trunk forward, push to standing, pivot on the stronger leg, reach for the target surface, and sit with control.", difficulty: 1, category: "Patient Care Planning", topic: "Patient Mobility Techniques" },
  { id: "pta-391", stem: "A patient with compartment syndrome in the anterior compartment of the leg shows which signs?", options: ["Pain with passive toe extension only", "Pain with passive toe flexion (stretching the anterior compartment), numbness between the first and second toes, and a tense swollen anterior leg", "Calf cramping only", "Isolated ankle swelling without pain"], correctIndex: 1, rationale: "Anterior compartment syndrome causes pain with passive toe/ankle plantar flexion (stretching dorsiflexors), first web space numbness (deep peroneal nerve), and a tense, swollen anterior leg.", difficulty: 3, category: "Clinical Scenarios", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-392", stem: "A patient with a right CVA has difficulty with spatial relationships and gets lost navigating the clinic. Which hemisphere is responsible for spatial processing?", options: ["Left hemisphere", "Right hemisphere — processing spatial awareness, depth perception, and navigation", "Brain stem", "Cerebellum"], correctIndex: 1, rationale: "The right hemisphere is dominant for spatial processing, visuospatial awareness, depth perception, and environmental navigation. Right CVA impairs these functions.", difficulty: 2, category: "Clinical Scenarios", topic: "Neurological Rehabilitation" },
  { id: "pta-393", stem: "A patient is performing neuromuscular re-education exercises after ankle sprain. Standing on one leg with eyes closed challenges which sensory system MOST?", options: ["Visual system", "Proprioceptive and somatosensory systems — removing vision forces reliance on proprioception", "Auditory system", "Gustatory system"], correctIndex: 1, rationale: "Closing eyes removes visual input for balance, forcing greater reliance on proprioceptive and somatosensory systems. This challenges and retrains the ankle mechanoreceptors.", difficulty: 1, category: "Therapeutic Intervention", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-394", stem: "A patient with knee osteoarthritis is considering total knee replacement. Which conservative measure should be exhausted first?", options: ["Immediate surgery without trying conservative treatment", "Weight management, quadriceps strengthening, activity modification, bracing, and anti-inflammatory medication", "Only medication without exercise", "Casting the knee for 6 weeks"], correctIndex: 1, rationale: "Conservative management for knee OA includes weight loss, exercise (especially quadriceps strengthening), activity modification, assistive devices, bracing, and appropriate pharmacologic management.", difficulty: 1, category: "Patient Care Planning", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-395", stem: "A patient is performing deep water running with a buoyancy belt. What is the advantage of this exercise for a patient with a stress fracture?", options: ["Increased impact loading on bones", "Non-weight-bearing cardiovascular exercise that maintains fitness without skeletal impact", "It strengthens bones faster than land exercise", "It is only for relaxation"], correctIndex: 1, rationale: "Deep water running eliminates impact while maintaining cardiovascular fitness, running mechanics, and muscle conditioning — ideal for stress fractures requiring non-weight-bearing activity.", difficulty: 1, category: "Therapeutic Intervention", topic: "Therapeutic Exercise" },
  { id: "pta-396", stem: "A patient with a prosthetic leg reports skin breakdown on the residual limb. What should the PTA do FIRST?", options: ["Apply additional socks over the area and continue training", "Stop prosthetic use, inspect the skin, document findings, and refer to the prosthetist and PT", "Ignore the issue as minor", "Continue gait training with modified technique"], correctIndex: 1, rationale: "Skin breakdown on the residual limb requires immediate prosthetic removal, skin inspection, documentation, and referral to the prosthetist for socket modification to prevent worsening.", difficulty: 1, category: "Safety", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-397", stem: "A patient with chronic low back pain scores high on the Fear-Avoidance Beliefs Questionnaire (FABQ). What does this indicate?", options: ["The patient is highly motivated for exercise", "The patient has excessive fear and avoidance beliefs about physical activity that may impede recovery", "The patient has excellent coping skills", "The patient requires no psychological intervention"], correctIndex: 1, rationale: "High FABQ scores indicate the patient fears physical activity will worsen pain, leading to avoidance behavior. This is a significant predictor of prolonged disability requiring a CBT approach.", difficulty: 2, category: "Clinical Scenarios", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-398", stem: "A patient with a recent pacemaker implantation is beginning cardiac rehabilitation. Which modality is CONTRAINDICATED?", options: ["Stationary cycling", "Diathermy or therapeutic ultrasound near the pacemaker", "Walking on a treadmill", "Light upper extremity exercises"], correctIndex: 1, rationale: "Diathermy and therapeutic ultrasound near a pacemaker are contraindicated because electromagnetic energy can interfere with pacemaker function, potentially causing dangerous cardiac arrhythmias.", difficulty: 2, category: "Safety", topic: "Therapeutic Exercise" },
  { id: "pta-399", stem: "A patient is performing the Tinetti Assessment Tool (Performance-Oriented Mobility Assessment). What does this test evaluate?", options: ["Upper extremity dexterity", "Gait and balance with a combined score predicting fall risk", "Cardiovascular endurance", "Cognitive function"], correctIndex: 1, rationale: "The Tinetti Assessment evaluates both gait (12 points) and balance (16 points) for a combined score of 28. Scores <19 indicate high fall risk, 19-24 moderate risk.", difficulty: 2, category: "Clinical Scenarios", topic: "Geriatric Rehabilitation" },
  { id: "pta-400", stem: "A patient has completed physical therapy and the PTA believes the patient has met all goals. Who makes the final discharge decision?", options: ["The PTA independently discharges the patient", "The supervising PT reviews progress and makes the discharge decision", "The patient decides when to stop therapy", "The insurance company determines discharge timing"], correctIndex: 1, rationale: "The supervising PT makes the final discharge decision based on goal achievement, functional outcomes, and clinical reasoning. The PTA provides input and data but cannot independently discharge.", difficulty: 1, category: "Patient Care Planning", topic: "Rehabilitation Principles" },
  { id: "pta-401", stem: "A PTA is treating a patient 4 weeks post-ACL reconstruction using a hamstring autograft. The surgeon's protocol allows closed-chain exercises. Which exercise is MOST appropriate at this stage?", options: ["Mini-squats to 45 degrees with bilateral weight-bearing on a stable surface","Full-depth single-leg squats on the operative leg","Plyometric box jumps for power development","Open-chain knee extension with heavy resistance from 0-90 degrees"], correctIndex: 0, rationale: "At 4 weeks post-ACL reconstruction with hamstring autograft, the graft is still in the early healing phase (avascular necrosis). Closed-chain exercises like mini-squats to 45 degrees limit anterior tibial shear force on the graft while strengthening the quadriceps. Bilateral weight-bearing distributes force. Full-depth single-leg squats are too demanding. Plyometrics are contraindicated at this early stage. Open-chain knee extension creates high anterior shear forces on the graft, especially near full extension.", difficulty: 2, category: "Therapeutic Intervention", topic: "Therapeutic Exercise" },
  { id: "pta-402", stem: "A PTA is designing an exercise program for a patient with grade II medial collateral ligament (MCL) sprain of the knee. The patient is 2 weeks post-injury with decreased range of motion and quadriceps inhibition. Which exercise progression is MOST appropriate?", options: ["Isometric quadriceps sets, progressing to active-assisted ROM, then gentle closed-chain strengthening as pain allows","Immediate aggressive passive stretching into full extension and flexion","Plyometric lateral drills to test ligament integrity","Maximum resistance open-chain exercises to rapidly restore strength"], correctIndex: 0, rationale: "A grade II MCL sprain involves partial ligament tearing. At 2 weeks, the ligament is in the proliferative phase of healing. Isometric exercises activate the quadriceps without stressing the healing ligament. Active-assisted ROM gently restores motion. Closed-chain exercises (when tolerated) provide controlled loading that promotes ligament healing through Wolff's law. Aggressive stretching risks further tearing. Lateral plyometrics stress the MCL with valgus force. Maximum resistance is premature for a partial tear.", difficulty: 2, category: "Patient Care Planning", topic: "Therapeutic Exercise" },
  { id: "pta-403", stem: "A patient with chronic low back pain is referred for core stabilization exercises. The PTA assesses that the patient cannot maintain a neutral spine during basic movements. Which exercise should be initiated FIRST?", options: ["Supine transverse abdominis activation with pelvic floor engagement (drawing-in maneuver)","Standing barbell deadlifts with progressive loading","Dynamic planks with alternating arm and leg lifts","Rapid sit-ups to strengthen the rectus abdominis"], correctIndex: 0, rationale: "Core stabilization follows a progression from local stabilizer activation to global stabilizer integration to dynamic functional training. The transverse abdominis and pelvic floor muscles are the deepest local stabilizers. The drawing-in maneuver in supine is the most basic starting point, eliminating gravity and allowing the patient to focus on isolating the deep stabilizers. Deadlifts require established stability. Dynamic planks are too advanced without basic activation. Rapid sit-ups primarily target superficial muscles and may exacerbate back pain.", difficulty: 2, category: "Clinical Scenarios", topic: "Therapeutic Exercise" },
  { id: "pta-404", stem: "A PTA is working with an elderly patient prescribed therapeutic exercise for osteoporosis. Which exercise type provides the BEST stimulus for bone density improvement?", options: ["Weight-bearing exercises such as walking, step-ups, and gentle impact activities with resistance training","Swimming and aquatic exercises exclusively","Prolonged bed rest with passive range of motion exercises","Isolated flexibility training without any resistance or weight-bearing"], correctIndex: 0, rationale: "Wolff's law states that bone adapts to the forces placed upon it. Weight-bearing exercises and impact activities stimulate osteoblast activity through mechanical loading. Resistance training adds compressive forces through muscle contraction. This combination provides the strongest stimulus for maintaining and improving bone density. Swimming, while excellent for cardiovascular fitness, does not provide the gravitational loading needed for bone stimulation. Bed rest accelerates bone loss. Flexibility training alone does not provide sufficient mechanical stress.", difficulty: 1, category: "Therapeutic Intervention", topic: "Therapeutic Exercise" },
  { id: "pta-405", stem: "A PTA is supervising a patient performing a quadriceps setting exercise. The patient cannot fully extend the knee actively, demonstrating a 10-degree extensor lag. What is the MOST likely cause?", options: ["Quadriceps muscle weakness or inhibition, particularly of the vastus medialis oblique (VMO)","Hamstring contracture preventing full extension","Posterior cruciate ligament laxity","Meniscal tear blocking full extension"], correctIndex: 0, rationale: "An extensor lag (ability to maintain full extension passively but inability to achieve it actively) specifically indicates quadriceps weakness or arthrogenic muscle inhibition, particularly of the VMO which provides the terminal 15 degrees of extension. This is distinct from a flexion contracture (which limits both active and passive extension). Hamstring contracture limits passive extension. PCL laxity causes posterior tibial translation. A meniscal tear causing a block limits both active and passive extension (mechanical block).", difficulty: 2, category: "Clinical Scenarios", topic: "Therapeutic Exercise" },
  { id: "pta-406", stem: "A PTA is applying therapeutic ultrasound to a patient's lateral epicondyle for chronic tendinopathy. Which parameters are MOST appropriate for thermal effects?", options: ["Continuous mode, 1 MHz, 1.5 W/cm² intensity for 5-8 minutes over a treatment area twice the ERA","Pulsed mode at 20% duty cycle, 3 MHz, 0.5 W/cm² for 15 minutes","Continuous mode, 3 MHz, 3.0 W/cm² for 20 minutes over a large surface area","Pulsed mode at 50% duty cycle, 1 MHz, 0.1 W/cm² for 3 minutes"], correctIndex: 0, rationale: "For thermal effects of ultrasound, continuous mode is required (pulsed mode is for non-thermal effects). The lateral epicondyle is a superficial structure, so both 1 MHz (deeper penetration) and 3 MHz (superficial) can be appropriate, but 1 MHz at 1.5 W/cm² provides effective thermal heating. Treatment time of 5-8 minutes is standard. The treatment area should be no larger than 2x the effective radiating area (ERA) to ensure adequate energy delivery. The 3 MHz at 3.0 W/cm² for 20 minutes risks tissue burns. Too-low intensity provides insufficient heating.", difficulty: 3, category: "Therapeutic Intervention", topic: "Physical Agents & Modalities" },
  { id: "pta-407", stem: "A PTA is considering the use of electrical stimulation for a patient with a recent deep vein thrombosis (DVT) in the left lower extremity. Which of the following is the correct course of action?", options: ["Electrical stimulation is contraindicated in the affected extremity due to risk of embolus dislodgement","Apply NMES to the calf muscles at maximum tolerable intensity","Use interferential current directly over the DVT site for pain relief","Apply TENS at high frequency over the calf to promote circulation"], correctIndex: 0, rationale: "Electrical stimulation is contraindicated in extremities with active DVT. Muscle contractions or increased blood flow from electrical stimulation could dislodge the thrombus, causing a potentially fatal pulmonary embolism. This is an absolute contraindication regardless of the type of electrical stimulation (NMES, interferential, TENS) or the stated goal of treatment. The risk of embolus dislodgement far outweighs any potential benefit.", difficulty: 2, category: "Safety", topic: "Physical Agents & Modalities" },
  { id: "pta-408", stem: "A PTA is applying cryotherapy to a patient's acutely inflamed knee following a sports injury. How long should the ice pack be applied to achieve optimal therapeutic benefit without tissue damage?", options: ["15-20 minutes with a barrier between the ice and skin, monitoring skin color and sensation","45-60 minutes of continuous direct ice application without interruption","5 minutes only, regardless of the size of the area or degree of inflammation","Until the patient reports complete numbness in the entire lower extremity"], correctIndex: 0, rationale: "Standard cryotherapy application is 15-20 minutes, which is sufficient to achieve therapeutic tissue temperature reduction (decrease of about 10°C in superficial tissues). A barrier (towel, pillowcase) prevents frostbite. Monitoring skin color and sensation detects adverse reactions early. Application beyond 25 minutes risks tissue damage and paradoxical vasodilation (hunting response). Direct prolonged application causes frostbite. Five minutes is insufficient for adequate cooling. Complete numbness of the entire limb indicates potential nerve damage.", difficulty: 1, category: "Clinical Scenarios", topic: "Physical Agents & Modalities" },
  { id: "pta-409", stem: "A PTA is treating a patient with chronic pain using transcutaneous electrical nerve stimulation (TENS). The patient reports the stimulation is comfortable but pain relief is only present during the treatment. Which modification would BEST extend the duration of pain relief?", options: ["Switch from conventional (high frequency, low intensity) TENS to acupuncture-like (low frequency, high intensity) TENS to stimulate endorphin release","Increase the frequency to maximum output","Decrease the pulse width to the narrowest setting","Apply the electrodes further from the pain site"], correctIndex: 0, rationale: "Conventional TENS (high frequency, low intensity) works primarily through the gate control mechanism, providing pain relief mainly during stimulation. Acupuncture-like TENS (low frequency 2-4 Hz, high intensity producing visible muscle contraction) stimulates the release of endogenous opioids (endorphins), which can provide longer-lasting pain relief (1-2 hours post-treatment). Maximum frequency at low intensity remains gate-control based. Narrowing pulse width may reduce comfort. Electrode placement far from the pain site reduces effectiveness.", difficulty: 3, category: "Therapeutic Intervention", topic: "Physical Agents & Modalities" },
  { id: "pta-410", stem: "A PTA is selecting a modality for a patient with adhesive capsulitis of the shoulder who has significant joint stiffness. The PT's plan of care indicates deep heating before stretching. Which modality provides the DEEPEST heating to the shoulder capsule?", options: ["Continuous ultrasound at 1 MHz to target the deep joint capsule tissue","Hot pack application for 20 minutes","Infrared lamp positioned 18 inches from the shoulder","Fluidotherapy at 110°F for the hand and wrist"], correctIndex: 0, rationale: "Continuous ultrasound at 1 MHz penetrates up to 5 cm deep, reaching the shoulder joint capsule to provide effective deep heating. This increases tissue extensibility before stretching, which is critical for adhesive capsulitis treatment. Hot packs are superficial heating (reaching only 1-2 cm depth). Infrared lamps heat only the skin surface. Fluidotherapy is for the extremities distal to the elbow and does not reach the shoulder capsule.", difficulty: 2, category: "Clinical Scenarios", topic: "Physical Agents & Modalities" },
  { id: "pta-411", stem: "A PTA is fitting a patient with a standard axillary crutch. When properly fitted, where should the top of the crutch rest?", options: ["Two to three finger widths (approximately 2 inches) below the axillary fold with elbows flexed 20-30 degrees","Pressing firmly into the axilla for maximum support","At the level of the greater trochanter of the hip","At the level of the iliac crest with arms fully extended"], correctIndex: 0, rationale: "Proper axillary crutch fitting requires the top of the crutch to be 2-3 finger widths (approximately 2 inches) below the axillary fold to prevent pressure on the brachial plexus and axillary vessels. Elbows should be flexed 20-30 degrees for effective push-off. Pressing into the axilla can cause crutch palsy (radial nerve compression) and vascular compromise. The greater trochanter and iliac crest positions are far too low for axillary crutches and are reference points for other assistive devices.", difficulty: 1, category: "Clinical Scenarios", topic: "Gait Training & Balance" },
  { id: "pta-412", stem: "A PTA observes a patient ambulating with a Trendelenburg gait pattern on the right side. The pelvis drops on the left during right stance phase. Which muscle weakness is MOST likely responsible?", options: ["Right hip abductor weakness (gluteus medius and minimus)","Left hip flexor weakness (iliopsoas)","Right hip extensor weakness (gluteus maximus)","Left knee extensor weakness (quadriceps)"], correctIndex: 0, rationale: "A Trendelenburg gait occurs when the hip abductors (primarily gluteus medius) on the stance leg are too weak to maintain a level pelvis. During right stance phase, the right gluteus medius must contract to prevent the pelvis from dropping on the unsupported left side. Weakness on the right causes the left pelvis to drop (positive Trendelenburg sign). The patient may compensate with a lateral trunk lean toward the weak side (compensated Trendelenburg or Duchenne gait).", difficulty: 2, category: "Clinical Scenarios", topic: "Gait Training & Balance" },
  { id: "pta-413", stem: "A patient with a right transfemoral amputation is learning to walk with a prosthesis. The PTA observes that the patient demonstrates circumduction of the prosthetic limb during swing phase. Which factor is MOST likely contributing to this gait deviation?", options: ["The prosthetic limb may be too long or the patient may have insufficient hip flexion to advance the limb","The prosthetic limb is too short","The patient has excessive hip flexor strength on the amputated side","The prosthetic foot is set in too much dorsiflexion"], correctIndex: 0, rationale: "Circumduction (swinging the leg out to the side during swing phase) in prosthetic gait typically results from a prosthesis that is too long or inadequate hip flexion to clear the foot during swing. When the limb is too long, the patient must swing it laterally to clear the floor. Insufficient hip flexion (from weakness, contracture, or inadequate prosthetic knee flexion) also prevents normal foot clearance. A short prosthesis would produce a gait asymmetry but not circumduction. Excessive hip flexor strength would not cause this pattern.", difficulty: 2, category: "Clinical Scenarios", topic: "Gait Training & Balance" },
  { id: "pta-414", stem: "A PTA is training a patient recovering from a stroke to use a quad cane on stairs. The patient has left hemiparesis. Which sequence should the PTA teach for ascending stairs?", options: ["Lead with the stronger (right) leg, then the weaker (left) leg, then the quad cane","Lead with the quad cane, then the weaker leg, then the stronger leg","Lead with the weaker (left) leg first, then the cane, then the stronger leg","Lead with both legs simultaneously while holding the railing"], correctIndex: 0, rationale: "The stair climbing pattern follows the principle 'up with the good, down with the bad.' When ascending, the stronger leg leads because it must lift the body weight against gravity. The sequence is: stronger leg up to the next step, then the weaker leg follows, then the cane moves up. This maximizes use of the stronger leg for the demanding lifting phase. Leading with the weaker leg places the recovery leg in the weight-bearing lifting role, risking instability. Simultaneous movement is unsafe.", difficulty: 1, category: "Patient Care Planning", topic: "Gait Training & Balance" },
  { id: "pta-415", stem: "A PTA is performing balance training with an elderly patient at high risk for falls. The patient can maintain static standing balance but loses balance during dynamic activities. Which exercise progression is MOST appropriate?", options: ["Progress from tandem stance to weight shifts, then gentle perturbation training with a gait belt for safety","Begin with single-leg hopping exercises on an unstable surface","Limit all activities to seated exercises to prevent falls","Practice only static standing on a flat floor indefinitely"], correctIndex: 0, rationale: "Balance training should progress from static to dynamic challenges. Since the patient can maintain static balance, the next step is narrowing the base of support (tandem stance), then introducing controlled dynamic challenges (weight shifts), then reactive balance training (perturbation training). A gait belt provides safety during challenging exercises. Single-leg hopping is far too advanced. Limiting to seated exercises does not progress dynamic balance. Continuing only static exercises does not address the identified dynamic balance deficit.", difficulty: 2, category: "Patient Care Planning", topic: "Gait Training & Balance" },
  { id: "pta-416", stem: "A PTA is treating a patient 3 days post total knee arthroplasty. The patient has significant knee swelling and a flexion ROM of 65 degrees. What is the MOST appropriate immediate intervention?", options: ["Ice and elevation for edema management combined with gentle active-assisted ROM exercises within the patient's tolerance","Aggressive passive stretching to achieve 90 degrees of flexion immediately","Deep tissue massage directly over the surgical incision","Maximum resistance quadriceps strengthening with ankle weights"], correctIndex: 0, rationale: "At 3 days post TKA, edema control is a priority as swelling limits ROM and increases pain. Ice and elevation reduce swelling. Gentle active-assisted ROM within tolerance promotes early motion without overstressing the surgical site. The goal is typically 90 degrees by discharge (7-10 days), not day 3. Aggressive stretching risks wound dehiscence and hemarthrosis. Deep tissue massage over a fresh incision is contraindicated. Resistive exercise with external weight is premature at 3 days.", difficulty: 2, category: "Clinical Scenarios", topic: "Musculoskeletal Interventions" },
  { id: "pta-417", stem: "A PTA is evaluating a patient with suspected rotator cuff pathology. The patient reports pain with overhead activities. A positive empty can test is found. Which rotator cuff muscle is MOST likely involved?", options: ["Supraspinatus","Infraspinatus","Teres minor","Subscapularis"], correctIndex: 0, rationale: "The empty can test (Jobe's test) specifically isolates the supraspinatus muscle. The patient holds the arm at 90 degrees of abduction in the scapular plane with the thumb pointing down (internal rotation) and resists downward pressure. Pain or weakness indicates supraspinatus pathology. The infraspinatus and teres minor are tested with external rotation resistance. The subscapularis is tested with the lift-off test or belly-press test (internal rotation resistance).", difficulty: 2, category: "Clinical Scenarios", topic: "Musculoskeletal Interventions" },
  { id: "pta-418", stem: "A patient with chronic adhesive capsulitis of the shoulder presents with a capsular pattern of restriction. Which motion is MOST limited in the capsular pattern of the glenohumeral joint?", options: ["External rotation, followed by abduction, then internal rotation","Flexion is the most limited movement","Internal rotation is the most limited, followed by flexion","All movements are equally restricted"], correctIndex: 0, rationale: "The capsular pattern of the glenohumeral joint, as described by Cyriax, follows a specific restriction pattern: external rotation is most limited, followed by abduction, then internal rotation. This pattern reflects the progressive tightening of the joint capsule. In adhesive capsulitis, the inferior axillary fold tightens first (limiting external rotation), then the anterior capsule (limiting abduction), then the posterior capsule (limiting internal rotation). Knowing the capsular pattern helps distinguish capsular from non-capsular restrictions.", difficulty: 3, category: "Clinical Scenarios", topic: "Musculoskeletal Interventions" },
  { id: "pta-419", stem: "A PTA is performing manual muscle testing on a patient's hip flexors. The patient can complete full hip flexion range of motion against gravity but cannot hold against moderate resistance. This corresponds to which muscle grade?", options: ["Grade 3+/5 (Fair Plus)","Grade 2/5 (Poor)","Grade 5/5 (Normal)","Grade 1/5 (Trace)"], correctIndex: 0, rationale: "In manual muscle testing, the grades correspond to: 5/5 (full ROM against gravity + maximum resistance), 4/5 (full ROM against gravity + moderate resistance), 3+/5 (full ROM against gravity + slight resistance or hold against moderate), 3/5 (full ROM against gravity only), 2/5 (full ROM with gravity eliminated), 1/5 (visible or palpable contraction but no movement). The patient demonstrates full ROM against gravity (at least grade 3) but cannot hold against moderate resistance (less than grade 4), placing them at 3+/5.", difficulty: 2, category: "Clinical Scenarios", topic: "Musculoskeletal Interventions" },
  { id: "pta-420", stem: "A PTA is treating a patient with a posterior shoulder dislocation that has been reduced and immobilized. After the immobilization period, which motion should be restored with the MOST caution?", options: ["Horizontal adduction and internal rotation, as these positions risk re-dislocation posteriorly","External rotation, as this stretches the anterior capsule","Forward flexion above 90 degrees only","All shoulder motions equally without specific precautions"], correctIndex: 0, rationale: "After a posterior shoulder dislocation, the mechanism of injury involves horizontal adduction, internal rotation, and flexion, which forced the humeral head posteriorly. During rehabilitation, these combined motions must be progressed cautiously as they replicate the dislocation mechanism and risk recurrence. External rotation precautions apply to anterior dislocations. Forward flexion alone is not the primary concern. Treating all motions equally ignores the specific injury mechanism and risk factors.", difficulty: 3, category: "Safety", topic: "Musculoskeletal Interventions" },
  { id: "pta-421", stem: "A PTA is treating a patient with Parkinson's disease who demonstrates festinating gait (progressively faster, shorter steps). Which cueing strategy is MOST effective for regulating step length and cadence?", options: ["External auditory cues such as a metronome or rhythmic music set at the desired cadence","Verbal instruction to walk faster to match the festinating rhythm","Removing all external stimuli so the patient can focus internally","Walking on a treadmill at maximum speed"], correctIndex: 0, rationale: "Festinating gait in Parkinson's disease occurs due to impaired internal rhythm generation from basal ganglia dysfunction. External auditory cues (metronome, rhythmic music) provide an external pacemaker that bypasses the impaired internal timing system, helping to regulate cadence and step length. Research strongly supports rhythmic auditory stimulation (RAS) for PD gait. Encouraging faster walking worsens festination. Removing external cues eliminates the compensatory mechanism needed. Maximum speed treadmill walking is unsafe.", difficulty: 2, category: "Therapeutic Intervention", topic: "Neurological Rehabilitation" },
  { id: "pta-422", stem: "A PTA is treating a patient with multiple sclerosis who develops new symptoms of double vision and increased lower extremity spasticity. The patient's body temperature is elevated due to a warm treatment room. The PTA should FIRST:", options: ["Move the patient to a cooler environment and discontinue the current exercise, as heat sensitivity (Uhthoff's phenomenon) may be causing the symptom exacerbation","Continue the exercise program to push through the symptoms","Apply hot packs to the lower extremities to reduce spasticity","Increase the exercise intensity to overcome the weakness"], correctIndex: 0, rationale: "Uhthoff's phenomenon in MS causes temporary worsening of symptoms when body temperature rises, even slightly. The mechanism involves heat-induced slowing of nerve conduction in demyelinated fibers. Moving to a cooler environment often rapidly reverses the symptom exacerbation. Continuing or increasing exercise in a warm environment will further raise body temperature and worsen symptoms. Hot packs would increase temperature further. Symptom exacerbation in MS requires immediate temperature management, not exercise progression.", difficulty: 2, category: "Safety", topic: "Neurological Rehabilitation" },
  { id: "pta-423", stem: "A PTA is performing proprioceptive neuromuscular facilitation (PNF) with a patient recovering from a stroke. The PTA chooses the D2 flexion pattern for the upper extremity. Which combined movement components make up this diagonal?", options: ["Shoulder flexion, abduction, and external rotation with forearm supination and wrist and finger extension","Shoulder extension, adduction, and internal rotation with forearm pronation","Shoulder flexion, adduction, and internal rotation with forearm pronation","Shoulder abduction only in the frontal plane with no rotational component"], correctIndex: 0, rationale: "PNF D2 flexion of the upper extremity follows a diagonal pattern from the hip on the opposite side upward and outward: shoulder flexion, abduction, and external rotation. The forearm supinates, and the wrist and fingers extend (opening pattern). This mimics reaching up and out, as in a tennis backhand follow-through. D2 extension is the reverse. D1 flexion involves flexion, adduction, and external rotation. Understanding these patterns is essential for applying PNF techniques correctly.", difficulty: 3, category: "Therapeutic Intervention", topic: "Neurological Rehabilitation" },
  { id: "pta-424", stem: "A PTA is treating a patient with right hemiplegia who is in Brunnstrom stage 3 of motor recovery. At this stage, the patient demonstrates:", options: ["Spasticity is at its peak and voluntary movement occurs only in synergy patterns","Flaccidity with no voluntary movement","Near-normal voluntary control with isolated joint movements","Spasticity has resolved and full functional movement has returned"], correctIndex: 0, rationale: "Brunnstrom's stages of motor recovery describe a predictable progression: Stage 1 = flaccidity, Stage 2 = spasticity appearing with synergy patterns emerging, Stage 3 = spasticity peaks and voluntary movement is possible but only within synergy patterns (flexor or extensor synergies), Stage 4 = movements begin to deviate from synergy, Stage 5 = near-normal isolated movements, Stage 6 = near-normal motor function. At stage 3, voluntary effort produces synergy-bound movement with maximal spasticity.", difficulty: 2, category: "Clinical Scenarios", topic: "Neurological Rehabilitation" },
  { id: "pta-425", stem: "A PTA is treating a patient with complete T6 spinal cord injury. During a transfer, the patient suddenly develops a severe headache, profuse sweating above the injury level, and a blood pressure reading of 200/110 mmHg. The PTA should IMMEDIATELY:", options: ["Sit the patient upright, loosen all restrictive clothing, and check for bladder distension or other noxious stimuli below the injury level","Lay the patient flat and elevate the legs to treat suspected hypotension","Continue the transfer and address the symptoms afterward","Have the patient take deep breaths and relax for 5 minutes before continuing"], correctIndex: 0, rationale: "These symptoms indicate autonomic dysreflexia, a medical emergency occurring in SCI at T6 and above. An uncontrolled sympathetic response below the injury level (often triggered by bladder distension, skin irritation, or bowel impaction) causes dangerous hypertension. Immediate management: sit the patient upright (reduces BP through gravity), remove restrictive clothing, and identify/remove the noxious stimulus (most commonly a full bladder). Laying flat worsens hypertension. Continuing activity ignores a life-threatening emergency. Relaxation alone does not address the cause.", difficulty: 2, category: "Safety", topic: "Neurological Rehabilitation" },
  { id: "pta-426", stem: "A PTA is monitoring a cardiac rehabilitation patient during exercise. The patient's resting heart rate is 70 bpm, and the prescribed exercise intensity is 60-80% of heart rate reserve (HRR). The patient's maximum heart rate achieved on the graded exercise test was 170 bpm. Using the Karvonen formula, what is the target heart rate range?", options: ["130-150 bpm","102-136 bpm","100-130 bpm","70-100 bpm"], correctIndex: 0, rationale: "The Karvonen formula: Target HR = ((HR max - HR rest) × % intensity) + HR rest. HRR = 170 - 70 = 100. At 60%: (100 × 0.60) + 70 = 130 bpm. At 80%: (100 × 0.80) + 70 = 150 bpm. Therefore, the target range is 130-150 bpm. The Karvonen method accounts for resting heart rate, making it more individualized than the straight percentage of maximum heart rate method. This is the standard formula used in cardiac rehabilitation for exercise prescription.", difficulty: 2, category: "Clinical Scenarios", topic: "Cardiopulmonary PT" },
  { id: "pta-427", stem: "A PTA is treating a patient with COPD who desaturates to 85% SpO2 during ambulation despite using 2 L/min supplemental oxygen via nasal cannula. The PTA should FIRST:", options: ["Stop ambulation, have the patient sit and perform pursed-lip breathing, and monitor until SpO2 recovers above 90%","Continue ambulation to build endurance despite the desaturation","Remove the supplemental oxygen as it may be suppressing the patient's respiratory drive","Increase the walking speed to complete the distance faster"], correctIndex: 0, rationale: "SpO2 below 88-90% during exercise warrants stopping the activity. At 85%, the patient is significantly hypoxemic, which can lead to cardiac arrhythmias, cognitive impairment, and organ damage. Stopping ambulation reduces oxygen demand. Seated positioning reduces work of breathing. Pursed-lip breathing creates back-pressure that prevents airway collapse. Monitoring until SpO2 exceeds 90% ensures safe recovery before any further activity. Continuing activity worsens hypoxemia. Removing oxygen would further decrease SpO2. Walking faster increases oxygen demand.", difficulty: 2, category: "Safety", topic: "Cardiopulmonary PT" },
  { id: "pta-428", stem: "A PTA is performing chest physical therapy including postural drainage for a patient with pneumonia affecting the right lower lobe posterior basal segment. Which position should the patient be placed in?", options: ["Prone with the foot of the bed elevated 18-20 inches (Trendelenburg position)","Seated upright at 90 degrees","Right side-lying with the head elevated 30 degrees","Supine with the head flat"], correctIndex: 0, rationale: "Postural drainage uses gravity to assist with mobilizing secretions from specific lung segments. The right lower lobe posterior basal segment is located posteriorly and inferiorly. Positioning the patient prone with the foot of the bed elevated (Trendelenburg) places the affected segment superiorly, allowing gravity to drain secretions toward the larger airways for removal. Sitting upright positions the lower lobes at the bottom (opposite of desired drainage). Side-lying with head elevation does not target the posterior basal segment. Supine flat does not use gravity effectively.", difficulty: 3, category: "Therapeutic Intervention", topic: "Cardiopulmonary PT" },
  { id: "pta-429", stem: "A PTA is monitoring a patient during Phase II cardiac rehabilitation. The patient reports feeling lightheaded and the EKG shows frequent premature ventricular contractions (PVCs) occurring more than 6 per minute. The PTA should:", options: ["Stop exercise immediately, have the patient sit or lie down, and notify the supervising PT and medical team","Reduce the exercise intensity by 10% and continue monitoring","Increase the exercise intensity to suppress the PVCs","Continue the current exercise program as occasional PVCs are normal during exercise"], correctIndex: 0, rationale: "Frequent PVCs (>6/min) during exercise, especially when associated with symptoms (lightheadedness), are a criterion for immediate exercise termination in cardiac rehabilitation. Frequent PVCs can progress to ventricular tachycardia or fibrillation, which are life-threatening arrhythmias. The PTA must stop exercise, ensure patient safety (sitting/lying), and immediately notify the supervising PT and medical staff. Reducing intensity while continuing exercise does not adequately address the arrhythmia risk. Increasing intensity is dangerous. Isolated PVCs may be benign, but frequent symptomatic PVCs are not.", difficulty: 2, category: "Safety", topic: "Cardiopulmonary PT" },
  { id: "pta-430", stem: "A PTA is teaching a patient with heart failure the proper technique for monitoring exercise tolerance at home. Which self-monitoring method is MOST appropriate to recommend?", options: ["Use the Rate of Perceived Exertion (RPE) scale targeting 11-13 (light to somewhat hard) combined with the talk test","Exercise until unable to continue due to exhaustion","Monitor blood pressure only after exercise completion","Use maximum heart rate percentage without considering medications"], correctIndex: 0, rationale: "For patients with heart failure exercising at home, the RPE scale and talk test are the most practical and safe self-monitoring tools. An RPE of 11-13 (light to somewhat hard) corresponds to an appropriate intensity for heart failure patients. The talk test (ability to carry on a conversation during exercise) provides an additional safety check. Exercising to exhaustion is dangerous in heart failure. Post-exercise BP alone misses during-exercise problems. Heart rate targets are unreliable in heart failure patients who often take beta-blockers that blunt heart rate response.", difficulty: 2, category: "Patient Care Planning", topic: "Cardiopulmonary PT" },
  { id: "pta-431", stem: "A PTA is performing wound care on a patient with a stage 3 pressure ulcer over the sacrum. The wound bed contains 70% red granulation tissue and 30% yellow slough. Which debridement method is MOST appropriate?", options: ["Selective autolytic debridement using a moisture-retentive dressing to soften and remove the slough while protecting granulation tissue","Sharp debridement of the entire wound bed including granulation tissue","Dry gauze dressing changed twice daily to remove all tissue","No debridement needed as the wound is healing adequately"], correctIndex: 0, rationale: "The wound has both viable granulation tissue (70% red) and non-viable slough (30% yellow). Selective autolytic debridement uses the body's own enzymes, maintained by a moisture-retentive dressing (hydrogel, hydrocolloid), to soften and remove non-viable slough while preserving healthy granulation tissue. Sharp debridement of the entire bed would damage the viable granulation tissue. Dry gauze dressings are non-selective and can disrupt healing tissue (wet-to-dry). The presence of slough requires some form of debridement to prevent infection.", difficulty: 3, category: "Therapeutic Intervention", topic: "Wound Care" },
  { id: "pta-432", stem: "A PTA is assessing the lower extremity of a patient with diabetes. The patient has diminished pedal pulses, cool skin temperature distally, and a small wound on the first metatarsal head that is not healing. These findings are MOST consistent with:", options: ["Peripheral arterial disease causing ischemic wound with insufficient blood flow for healing","Venous insufficiency with venous stasis ulceration","Normal age-related skin changes","Deep vein thrombosis causing the wound"], correctIndex: 0, rationale: "Diminished pedal pulses, cool skin temperature, and non-healing wounds at pressure points (metatarsal heads) are classic signs of peripheral arterial disease (PAD). Insufficient arterial blood flow (ischemia) prevents wound healing by depriving tissues of oxygen and nutrients. Diabetic patients are at high risk for PAD. Venous insufficiency typically presents with edema, warm skin, and wounds at the medial malleolus. Cool skin with diminished pulses is not normal aging. DVT causes swelling and warmth, not cool skin and diminished pulses.", difficulty: 2, category: "Clinical Scenarios", topic: "Wound Care" },
  { id: "pta-433", stem: "A PTA is treating a patient with a venous insufficiency ulcer above the medial malleolus. The wound is granulating well. Which intervention is ESSENTIAL for preventing recurrence and promoting healing?", options: ["Compression therapy with multi-layer compression bandaging to reduce venous hypertension and edema","Elevation of the limb above heart level 24 hours per day without any compression","Aggressive debridement of the healthy granulation tissue","Heat application to improve circulation to the wound area"], correctIndex: 0, rationale: "Venous insufficiency ulcers result from venous hypertension causing edema and tissue breakdown. Compression therapy is the gold standard treatment, reducing venous pressure, controlling edema, and improving venous return. Multi-layer compression bandaging provides sustained therapeutic compression. Elevation helps but is impractical 24/7 and insufficient alone. Debriding healthy granulation tissue would delay healing. Heat application can worsen edema and is inappropriate for venous ulcers. Without compression, recurrence rates for venous ulcers exceed 70%.", difficulty: 2, category: "Therapeutic Intervention", topic: "Wound Care" },
  { id: "pta-434", stem: "A PTA is performing wound care on a patient with a full-thickness burn. The wound bed is covered with thick, leathery, brown/black tissue that is insensitive to pain. This tissue is BEST described as:", options: ["Eschar, which is devitalized tissue requiring debridement to allow wound healing","Healthy granulation tissue indicating normal healing","A superficial scab that will resolve without intervention","Epithelial tissue indicating wound closure"], correctIndex: 0, rationale: "Eschar is thick, leathery, devitalized tissue that forms after full-thickness burns. It is brown or black in color and insensitive to pain because the nerve endings have been destroyed. Eschar acts as a barrier to healing and provides a medium for bacterial growth, requiring debridement (enzymatic, autolytic, or surgical) to allow wound healing from the wound edges. Granulation tissue is red and moist. A scab is thin and forms over superficial wounds. Epithelial tissue is thin, pink/pearlescent, and indicates healing.", difficulty: 2, category: "Clinical Scenarios", topic: "Wound Care" },
  { id: "pta-435", stem: "A PTA is changing a dressing on a wound and notices purulent green drainage with a foul odor. The surrounding skin is erythematous and warm. The patient reports increased pain. The PTA should:", options: ["Document the findings, complete the dressing change with appropriate wound care, and notify the supervising PT and physician immediately of suspected wound infection","Continue with the same dressing protocol without reporting the changes","Apply antibiotic ointment and increase dressing change frequency independently","Discharge the patient from wound care services"], correctIndex: 0, rationale: "Purulent green drainage, foul odor, periwound erythema, warmth, and increased pain are classic signs of wound infection. The PTA must document these objective findings, complete the dressing change using clean technique, and immediately notify the supervising PT and physician. Wound infection may require systemic antibiotics, culture and sensitivity testing, or changes in wound management. Continuing without reporting delays treatment of a potentially serious infection. Applying antibiotics independently is outside the PTA's scope. Discharge is inappropriate.", difficulty: 1, category: "Safety", topic: "Wound Care" },
  { id: "pta-436", stem: "A PTA is performing goniometric measurement of a patient's knee flexion ROM. To ensure accuracy, the goniometer should be aligned with which landmarks?", options: ["Fulcrum over the lateral epicondyle of the femur, stationary arm aligned with the greater trochanter, moving arm aligned with the lateral malleolus","Fulcrum over the patella, both arms aligned with the tibia","Fulcrum over the medial joint line, stationary arm along the femur, moving arm along the medial tibia","Fulcrum over the popliteal fossa, both arms along the posterior aspect of the leg"], correctIndex: 0, rationale: "Standard goniometric measurement of knee flexion uses the lateral approach: the fulcrum (axis) is placed over the lateral epicondyle of the femur (the axis of knee flexion). The stationary arm is aligned with the lateral midline of the femur, pointing toward the greater trochanter. The moving arm is aligned with the lateral midline of the fibula, pointing toward the lateral malleolus. These landmarks are standardized by the American Academy of Orthopaedic Surgeons and ensure reliable, reproducible measurements.", difficulty: 1, category: "Clinical Scenarios", topic: "Data Collection & Documentation" },
  { id: "pta-437", stem: "A PTA documents the following in a patient's progress note: 'Patient appears to be in a lot of pain and seems unmotivated.' Which documentation principle does this note violate?", options: ["Objectivity — the note uses subjective interpretations rather than measurable, observable data","Timeliness — the note was not written immediately after the session","Completeness — the note does not include billing information","Legibility — the note contains grammatical errors"], correctIndex: 0, rationale: "Clinical documentation should be objective, using measurable and observable data rather than subjective interpretations. 'Appears to be in a lot of pain' should be replaced with objective measures: pain scale rating, observed behaviors (grimacing, guarding), and functional impact. 'Seems unmotivated' is a judgment that should be replaced with observable data: 'patient declined 3 of 5 exercises' or 'patient required 10 verbal cues for participation.' Objective documentation supports clinical decision-making and legal defensibility.", difficulty: 1, category: "Clinical Scenarios", topic: "Data Collection & Documentation" },
  { id: "pta-438", stem: "A PTA is performing a standardized functional assessment and the patient achieves a Berg Balance Scale score of 38 out of 56. This score indicates:", options: ["Medium fall risk, suggesting the patient needs supervised ambulation and balance interventions","No fall risk, indicating the patient is safe for independent community ambulation","High fall risk requiring the patient to remain in bed","The score has no clinical significance for predicting fall risk"], correctIndex: 0, rationale: "The Berg Balance Scale has established cut-off scores for fall risk: 0-20 indicates high fall risk (wheelchair bound), 21-40 indicates medium fall risk (requires assistance/supervision for ambulation), and 41-56 indicates low fall risk (independent). A score of 38 falls in the medium risk category, suggesting the patient needs supervised ambulation and continued balance interventions to reduce fall risk. The patient is neither safe for independent ambulation nor confined to bed.", difficulty: 2, category: "Clinical Scenarios", topic: "Data Collection & Documentation" },
  { id: "pta-439", stem: "A PTA notices a discrepancy between the patient's reported pain level (2/10) and observed pain behaviors (grimacing, guarding, decreased weight-bearing). The PTA should document:", options: ["Both the patient's verbal report and the observed objective pain behaviors, noting the discrepancy without interpretation","Only the patient's verbal report since the patient is the authority on their own pain","Only the observed behaviors since they are more reliable than patient report","An averaged pain score between the verbal report and the PTA's assessment"], correctIndex: 0, rationale: "Accurate documentation requires recording both subjective (patient report) and objective (observed behaviors) information. When discrepancies exist, documenting both provides a complete clinical picture. The PTA should note the discrepancy factually without interpreting the cause (which could be stoicism, cultural factors, fear of medication changes, or secondary gain). Recording only one source omits important clinical data. Averaging subjective and objective measures is not an accepted clinical practice.", difficulty: 2, category: "Patient Care Planning", topic: "Data Collection & Documentation" },
  { id: "pta-440", stem: "A PTA is performing a reassessment and collecting data to send to the supervising PT. Which data collection activity is OUTSIDE the PTA's scope of practice?", options: ["Interpreting test results to modify the plan of care and discharge the patient from physical therapy services","Performing goniometric ROM measurements","Administering standardized functional outcome measures","Measuring vital signs before, during, and after exercise"], correctIndex: 0, rationale: "While PTAs can collect data through measurements, standardized tests, and vital signs, interpreting those results to modify the plan of care or make discharge decisions is outside the PTA's scope of practice. Plan of care modifications and discharge decisions are the responsibility of the supervising PT. The PTA collects and reports data to the PT, who then interprets the findings and makes clinical decisions. This distinction is fundamental to the PT-PTA supervisory relationship and is defined by practice acts.", difficulty: 1, category: "Safety", topic: "Data Collection & Documentation" },
  { id: "pta-441", stem: "A PTA is educating an elderly patient with a new diabetes diagnosis about foot care and skin inspection. The patient has limited health literacy. Which teaching method would be MOST effective?", options: ["Demonstrate the foot inspection technique, have the patient practice return-demonstration, and provide a simple pictorial handout with large text","Provide a lengthy written pamphlet with medical terminology and tell the patient to read it at home","Use only verbal instructions without any demonstration or visual aids","Direct the patient to research foot care on the internet"], correctIndex: 0, rationale: "For patients with limited health literacy, the teach-back (return-demonstration) method is the most effective educational approach. Demonstrating the technique provides visual learning. Having the patient practice ensures comprehension and identifies areas needing clarification. A simple pictorial handout with large text provides a take-home reference that does not rely on reading ability. Written materials with medical terminology are inaccessible. Verbal-only instruction relies on memory. Internet research may lead to unreliable sources and requires digital literacy.", difficulty: 1, category: "Patient Care Planning", topic: "Patient Education" },
  { id: "pta-442", stem: "A PTA is educating a patient with a recent lumbar disc herniation about body mechanics for lifting. Which instruction is MOST important for preventing re-injury?", options: ["Keep the object close to the body, bend at the knees and hips while maintaining a neutral spine, and avoid twisting during the lift","Bend at the waist with straight legs to use the back muscles for lifting","Hold the breath during the entire lifting maneuver to stabilize the spine","Twist the trunk to position the object after lifting rather than moving the feet"], correctIndex: 0, rationale: "Proper lifting mechanics reduce intradiscal pressure and prevent herniation recurrence. Keeping the object close reduces the moment arm on the spine. Bending at the knees/hips while maintaining a neutral spine uses the leg muscles instead of the spinal muscles and keeps the disc in a safe position. Avoiding twisting prevents asymmetric disc loading that contributes to herniation. Bending at the waist with straight legs dramatically increases disc pressure. Breath-holding (Valsalva) increases intrathoracic and intradiscal pressure. Twisting under load is a primary injury mechanism.", difficulty: 1, category: "Patient Care Planning", topic: "Patient Education" },
  { id: "pta-443", stem: "A PTA is teaching a patient with newly diagnosed osteoporosis about fall prevention and bone health. Which combination of recommendations is MOST evidence-based?", options: ["Weight-bearing exercise, calcium and vitamin D supplementation as prescribed, home safety modifications, and balance training","Avoiding all physical activity to prevent fractures","Only taking calcium supplements without exercise or environmental modifications","Wearing high-heeled shoes to strengthen ankle muscles"], correctIndex: 0, rationale: "Evidence-based osteoporosis management combines multiple strategies: weight-bearing exercise stimulates bone formation, calcium and vitamin D support bone mineralization, home safety modifications reduce fall risk (removing rugs, improving lighting, installing grab bars), and balance training reduces the likelihood of falls. Avoiding activity accelerates bone loss. Calcium alone is insufficient without mechanical loading. High-heeled shoes increase fall risk by raising the center of gravity and narrowing the base of support.", difficulty: 1, category: "Patient Care Planning", topic: "Patient Education" },
  { id: "pta-444", stem: "A PTA is educating a patient's family about proper techniques for assisting with a sit-to-stand transfer. The patient has moderate balance impairment and requires contact guard assistance. The PTA should instruct the family to:", options: ["Stand close to the patient's weaker side with hands ready to assist at the trunk, allowing the patient to push up from the armrests independently","Pull the patient up by the arms to standing position","Stand behind the patient and push them forward to standing","Lift the patient under the arms from the front"], correctIndex: 0, rationale: "Contact guard assistance means staying close enough to provide support if needed while encouraging the patient's maximum independence. Standing on the weaker side positions the caregiver to catch or support if balance is lost. Hands at the trunk provide the most effective stabilization point. Allowing independent push-up from armrests promotes strength and self-efficacy. Pulling by the arms can cause shoulder injury. Pushing from behind is destabilizing. Lifting under the arms can cause axillary nerve damage and does not promote patient participation.", difficulty: 1, category: "Safety", topic: "Patient Education" },
  { id: "pta-445", stem: "A PTA is educating a patient on a home exercise program (HEP) following rotator cuff repair surgery. The patient asks why they need to continue the exercises even after pain has resolved. The BEST explanation is:", options: ["The repaired tissue needs progressive loading to remodel and strengthen, and muscles weakened during immobilization require ongoing rehabilitation to prevent re-injury","The exercises are optional once pain resolves","Only the exercises performed in the clinic are important for recovery","Pain resolution means the tissue is fully healed and no further exercise is needed"], correctIndex: 0, rationale: "Tissue healing follows stages (inflammation, proliferation, remodeling) that extend well beyond pain resolution. The remodeling phase can last 6-12 months, during which the tendon gradually strengthens through controlled progressive loading. Muscles weakened during the immobilization period require systematic strengthening to prevent re-tear. Stopping exercise when pain resolves often leads to re-injury because the tissue has not yet achieved sufficient strength. HEP is essential for complete functional recovery.", difficulty: 2, category: "Patient Care Planning", topic: "Patient Education" },
  { id: "pta-446", stem: "A PTA is preparing to ambulate a patient for the first time after a 2-week bed rest following surgery. The patient reports feeling dizzy when sitting at the edge of the bed. The PTA should:", options: ["Have the patient sit at the edge of the bed for several minutes, monitor blood pressure and symptoms, and progress to standing only when dizziness resolves","Proceed with ambulation immediately since some dizziness is expected","Lay the patient back down and postpone ambulation for another week","Have the patient stand quickly to overcome the dizziness through rapid adaptation"], correctIndex: 0, rationale: "Dizziness with position change after prolonged bed rest indicates orthostatic hypotension from cardiovascular deconditioning. The PTA should allow gradual accommodation by having the patient sit at the edge of the bed, monitoring blood pressure for orthostatic changes (drop >20 mmHg systolic or >10 mmHg diastolic), and waiting for symptom resolution before progressing. Proceeding with ambulation while dizzy risks a syncopal fall. Postponing for a week worsens deconditioning. Rapid standing can cause syncope.", difficulty: 1, category: "Safety", topic: "Safety & Body Mechanics" },
  { id: "pta-447", stem: "A PTA needs to perform a maximal-assist transfer of a 250-pound patient from bed to wheelchair. The PTA weighs 130 pounds. Which approach is SAFEST?", options: ["Request assistance from additional staff and use a mechanical lift or transfer board to reduce injury risk","Perform the transfer alone using proper body mechanics","Have the patient attempt the transfer independently despite requiring maximal assistance","Use the bed sheet to pull the patient from the bed to the wheelchair"], correctIndex: 0, rationale: "Safe patient handling guidelines recommend mechanical assistance and/or additional staff when the patient significantly outweighs the healthcare provider and requires maximal assistance. A 250-pound patient needing max-assist exceeds safe manual handling limits for a 130-pound PTA. Mechanical lifts and transfer boards reduce both patient and staff injury risk. Solo manual transfers of this magnitude are the leading cause of healthcare worker musculoskeletal injuries. Independent transfer attempts risk patient falls. Sheet transfers are unsafe and undignified.", difficulty: 1, category: "Safety", topic: "Safety & Body Mechanics" },
  { id: "pta-448", stem: "A PTA is ambulating a patient who suddenly begins to fall forward. The PTA should:", options: ["Use the gait belt to guide the patient's descent to the floor in a controlled manner, protecting the head","Try to catch the patient fully and return them to standing","Step away to avoid being pulled down with the patient","Grab the patient's arm to stop the fall"], correctIndex: 0, rationale: "When a fall cannot be prevented, the PTA's role is to guide a controlled descent to minimize injury. Using the gait belt provides a secure grip on the patient's center of mass, allowing the PTA to slow the descent and protect the patient's head. Attempting to fully catch and reverse a fall risks injury to both patient and PTA, especially with larger patients. Stepping away abandons the patient. Grabbing the arm can cause shoulder dislocation or injury and does not provide adequate control of the fall.", difficulty: 1, category: "Safety", topic: "Safety & Body Mechanics" },
  { id: "pta-449", stem: "A PTA is treating a patient in an outpatient clinic when the patient reports chest pain, shortness of breath, and pain radiating down the left arm. The PTA should:", options: ["Stop all treatment immediately, have the patient sit or lie down, call 911, and stay with the patient while monitoring vital signs","Continue treatment at a lower intensity and monitor symptoms","Have the patient take deep breaths and continue with stretching exercises","Send the patient home and advise them to see their doctor tomorrow"], correctIndex: 0, rationale: "Chest pain, dyspnea, and left arm radiation are classic symptoms of myocardial infarction (heart attack), a medical emergency. Immediate actions: stop all physical activity (reduces myocardial oxygen demand), position the patient comfortably (sitting or lying), activate emergency medical services (call 911), and remain with the patient monitoring vital signs until help arrives. Continuing any activity increases cardiac workload. Deep breathing exercises are inadequate for a cardiac emergency. Sending the patient home delays potentially life-saving treatment.", difficulty: 1, category: "Safety", topic: "Safety & Body Mechanics" },
  { id: "pta-450", stem: "A PTA is setting up a treatment area for patient care. According to OSHA guidelines and infection control procedures, which practice is MOST important for preventing cross-contamination between patients?", options: ["Clean all treatment surfaces with appropriate disinfectant and perform hand hygiene before and after each patient contact","Use the same treatment table sheet for multiple patients if there are no visible soils","Wear gloves for all patients but skip hand washing between glove changes","Disinfect equipment once at the end of the day rather than between patients"], correctIndex: 0, rationale: "Standard precautions for infection control require surface disinfection and hand hygiene between every patient encounter, regardless of whether contamination is visible. This prevents transmission of pathogens including MRSA, C. difficile, and other healthcare-associated infections. Reusing linens between patients allows cross-contamination. Gloves without hand washing between changes can transfer pathogens. End-of-day disinfection allows accumulation and transmission of pathogens throughout the treatment day.", difficulty: 1, category: "Safety", topic: "Safety & Body Mechanics" },
  { id: "pta-451", stem: "A PTA is designing a plyometric exercise program for an athlete recovering from a patellofemoral pain syndrome. The athlete can currently perform pain-free single-leg squats to 60 degrees. Which criteria should be met BEFORE initiating plyometric training?", options: ["Full pain-free range of motion, ability to perform single-leg squat with good mechanics, and adequate eccentric quadriceps strength","Ability to walk without pain only","No criteria needed; plyometrics can begin at any time","Ability to perform isometric exercises at 30 degrees of knee flexion"], correctIndex: 0, rationale: "Plyometric training involves high-impact, rapid stretch-shortening cycles that place significant demands on the musculoskeletal system. Prerequisites include full pain-free ROM (to allow normal landing mechanics), single-leg squat with good mechanics (demonstrating adequate strength and neuromuscular control), and eccentric quadriceps strength (the primary deceleration mechanism during landing). Pain-free walking is insufficient as plyometrics require much greater force absorption. Starting without adequate preparation risks re-injury. Isometric strength alone does not prepare for dynamic plyometric demands.", difficulty: 3, category: "Patient Care Planning", topic: "Therapeutic Exercise" },
  { id: "pta-452", stem: "A PTA is treating a patient with lateral ankle sprain in the subacute phase. The patient has restored full ROM but demonstrates poor proprioception during single-leg stance. Which exercise progression is MOST appropriate?", options: ["Single-leg stance on a stable surface, progressing to an unstable surface (foam, wobble board), then adding dynamic tasks","Immediately begin agility drills and cutting movements on the field","Only perform ankle strengthening with resistance bands in sitting position","Continue only ROM exercises until proprioception returns spontaneously"], correctIndex: 0, rationale: "Ankle sprains damage mechanoreceptors in the ligaments, impairing proprioception and increasing re-injury risk. Proprioceptive rehabilitation follows a progression: single-leg stance on stable surface (basic proprioceptive challenge), then unstable surface (increased demand), then adding dynamic tasks (catching a ball, reaching). This systematic progression restores the neuromuscular control needed for safe return to activity. Agility drills are too advanced without basic proprioception. Seated resistance does not challenge balance. Proprioception rarely returns fully without targeted training.", difficulty: 2, category: "Therapeutic Intervention", topic: "Therapeutic Exercise" },
  { id: "pta-453", stem: "A PTA is considering iontophoresis to deliver dexamethasone to treat a patient's plantar fasciitis. Which of the following is a contraindication for this treatment?", options: ["The patient has a metal implant (surgical plate) in the calcaneus of the same foot","The patient has intact skin over the treatment area","The patient reports mild tenderness with palpation of the plantar fascia","The patient has had symptoms for more than 6 months"], correctIndex: 0, rationale: "Iontophoresis uses direct electrical current to drive medication ions through the skin. Metal implants in the treatment path are a contraindication because the electrical current can be concentrated at the metal-tissue interface, causing thermal tissue damage or burns. Additionally, the metal can alter current distribution, making treatment unpredictable. Intact skin is required (not a contraindication). Tenderness indicates appropriate pathology for treatment. Chronic symptoms (>6 months) do not contraindicate iontophoresis.", difficulty: 2, category: "Safety", topic: "Physical Agents & Modalities" },
  { id: "pta-454", stem: "A PTA is selecting an assistive device for a patient who requires moderate bilateral upper extremity weight-bearing support during ambulation due to bilateral lower extremity weakness from Guillain-Barré syndrome. Which device is MOST appropriate?", options: ["Rolling walker (front-wheeled walker) to allow continuous forward progression with bilateral support","Single-point cane providing unilateral support only","Bilateral Lofstrand (forearm) crutches requiring reciprocal gait pattern","No assistive device to encourage independent ambulation"], correctIndex: 0, rationale: "A rolling walker (front-wheeled walker) provides a wide, stable base of support with bilateral upper extremity weight-bearing capability. The wheels allow continuous forward progression without the need to lift the device, reducing energy expenditure for a patient with generalized weakness. A single-point cane provides insufficient support for bilateral LE weakness. Lofstrand crutches require more upper extremity strength and coordination than a walker. No device would be unsafe given the moderate support requirement.", difficulty: 1, category: "Patient Care Planning", topic: "Gait Training & Balance" },
  { id: "pta-455", stem: "A PTA is treating a patient with cervical radiculopathy at the C6 nerve root level. Which clinical findings would MOST likely be present?", options: ["Decreased biceps reflex, weakness of wrist extension, and numbness/tingling along the lateral forearm and thumb","Decreased triceps reflex, weakness of wrist flexion, and numbness of the small finger","Decreased patellar reflex and weakness of knee extension","Decreased Achilles reflex and weakness of ankle dorsiflexion"], correctIndex: 0, rationale: "C6 radiculopathy produces a specific pattern: the C6 nerve root innervates the biceps (diminished biceps reflex), wrist extensors (weakness of wrist extension), and provides sensory innervation to the lateral forearm and thumb (numbness/tingling in this distribution). C7 radiculopathy affects the triceps and middle finger. C8 affects the small finger and hand intrinsics. Patellar reflex (L3-L4) and Achilles reflex (S1) are lower extremity findings unrelated to cervical pathology.", difficulty: 2, category: "Clinical Scenarios", topic: "Musculoskeletal Interventions" },
  { id: "pta-456", stem: "A PTA is using body-weight-supported treadmill training (BWSTT) with a patient who has an incomplete T10 spinal cord injury. The patient is classified as ASIA C. What is the PRIMARY goal of this intervention?", options: ["Activate central pattern generators in the spinal cord to promote locomotor recovery through repetitive stepping patterns","Provide cardiovascular exercise only","Replace all overground walking training","Strengthen upper extremity muscles for wheelchair propulsion"], correctIndex: 0, rationale: "BWSTT for incomplete SCI leverages the concept of central pattern generators (CPGs) — neural networks in the spinal cord that produce rhythmic stepping movements. Repetitive stepping on a treadmill with body-weight support provides the sensory input needed to activate these networks, promoting neuroplasticity and locomotor recovery. ASIA C patients have motor function preserved below the injury level, making them candidates for locomotor training. While BWSTT provides cardiovascular benefits, the primary neurological goal is CPG activation. It should complement, not replace, overground training.", difficulty: 3, category: "Therapeutic Intervention", topic: "Neurological Rehabilitation" },
  { id: "pta-457", stem: "A PTA is monitoring a patient performing the 6-Minute Walk Test (6MWT) as an outcome measure for functional endurance. Which of the following would require the PTA to STOP the test immediately?", options: ["The patient develops chest pain and SpO2 drops to 80%","The patient takes two short rest breaks during the 6 minutes","The patient's heart rate increases by 10 bpm from resting rate","The patient walks slower during the last 2 minutes compared to the first 2 minutes"], correctIndex: 0, rationale: "The 6MWT has specific termination criteria including: chest pain (potential cardiac event), oxygen desaturation below 85% (80% is dangerously low and indicates severe hypoxemia), severe dyspnea, dizziness, diaphoresis, or leg cramps limiting walking. Chest pain with significant desaturation is a medical emergency requiring immediate test termination. Rest breaks are allowed during the 6MWT without stopping the timer. Moderate heart rate increases are expected. Slowing in later minutes is a normal pacing pattern.", difficulty: 2, category: "Safety", topic: "Cardiopulmonary PT" },
  { id: "pta-458", stem: "A PTA is managing a wound using negative pressure wound therapy (wound VAC). The PTA checks the dressing and notices the suction has lost negative pressure. The foam appears saturated and the canister is full. The PTA should:", options: ["Replace the canister, check all seal connections, and re-establish negative pressure per the protocol parameters","Discontinue the wound VAC permanently and switch to wet-to-dry gauze","Increase the negative pressure to compensate for the leak","Leave the system as is until the next scheduled dressing change in 3 days"], correctIndex: 0, rationale: "Loss of negative pressure in a wound VAC system requires troubleshooting and correction. A full canister is a common cause of pressure loss. The PTA should replace the full canister, check all seal connections (adhesive drape integrity, tubing connections), and re-establish the prescribed negative pressure. Loss of suction allows bacterial proliferation and interrupts the wound healing benefits. Permanent discontinuation is premature. Increasing pressure without addressing the cause does not solve the problem. Leaving the system without suction for 3 days risks wound deterioration and infection.", difficulty: 2, category: "Clinical Scenarios", topic: "Wound Care" },
  { id: "pta-459", stem: "A PTA is measuring a patient's leg length to assess for discrepancy. True leg length should be measured from which landmarks?", options: ["Anterior superior iliac spine (ASIS) to the medial malleolus","Greater trochanter to the lateral malleolus","Umbilicus to the medial malleolus","Iliac crest to the lateral border of the foot"], correctIndex: 0, rationale: "True (structural) leg length is measured from the ASIS to the medial malleolus bilaterally. These bony landmarks provide standardized reference points that reflect actual bone length. ASIS represents the proximal end of the lower extremity kinetic chain. The medial malleolus is the distal reference point. The greater trochanter-to-lateral malleolus measurement excludes the femoral neck length. Umbilicus-to-malleolus measures apparent leg length (includes pelvic obliquity). Iliac crest-to-foot is not a standardized measurement.", difficulty: 1, category: "Clinical Scenarios", topic: "Data Collection & Documentation" },
  { id: "pta-460", stem: "A PTA is educating a patient with Type 2 diabetes about the precautions for exercising. The patient's pre-exercise blood glucose reading is 55 mg/dL. The PTA should:", options: ["Do NOT begin exercise; have the patient consume 15-20 grams of fast-acting carbohydrate and recheck blood glucose in 15 minutes","Begin exercise immediately to lower the blood glucose further","Have the patient take an extra dose of insulin before exercise","Proceed with exercise at a higher intensity than planned"], correctIndex: 0, rationale: "A blood glucose of 55 mg/dL indicates hypoglycemia (normal range 70-100 mg/dL). Exercise would further lower blood glucose, potentially causing seizures, loss of consciousness, or death. The 15-15 rule applies: consume 15-20 grams of fast-acting carbohydrate (juice, glucose tablets), wait 15 minutes, and recheck glucose. Exercise should only begin once blood glucose is above 100 mg/dL. Additional insulin would worsen hypoglycemia. Higher intensity exercise would accelerate glucose consumption and deepen the hypoglycemic crisis.", difficulty: 1, category: "Safety", topic: "Patient Education" },
  { id: "pta-461", stem: "A PTA is working in a busy outpatient clinic and is scheduled to see a patient with a known latex allergy. Which precaution is MOST important?", options: ["Ensure all gloves, resistance bands, and therapy equipment used are latex-free, and schedule the patient as the first appointment of the day","Use powder-free latex gloves instead of powdered ones","Have the patient take an antihistamine before the session","Use latex equipment but apply a barrier cream to the patient's skin first"], correctIndex: 0, rationale: "Latex allergy can cause reactions ranging from contact dermatitis to anaphylaxis. All latex-containing items must be removed: gloves (use nitrile), resistance bands (use non-latex bands), and any other latex equipment. Scheduling the patient first minimizes airborne latex particles from previous sessions. Powder-free latex still contains latex proteins that trigger allergic reactions. Antihistamines do not prevent anaphylaxis. Barrier creams do not adequately prevent latex protein absorption and are not a safe alternative to latex avoidance.", difficulty: 2, category: "Safety", topic: "Safety & Body Mechanics" },
  { id: "pta-462", stem: "A PTA is performing joint mobilization (as delegated by the PT) on a patient with frozen shoulder. Grade III mobilization has been prescribed. Grade III mobilization is characterized by:", options: ["Large-amplitude rhythmic oscillations performed up to the tissue's resistance (end range) to increase range of motion","Small-amplitude oscillations at the beginning of available range for pain relief only","Sustained stretch beyond the tissue resistance to permanently deform tissue","Quick, high-velocity thrust at end range"], correctIndex: 0, rationale: "According to Maitland's mobilization grades: Grade I = small-amplitude oscillations at the beginning of range (pain relief), Grade II = large-amplitude oscillations within the midrange (pain relief), Grade III = large-amplitude oscillations performed to the tissue resistance/end range (to increase ROM), Grade IV = small-amplitude oscillations at end range (to increase ROM), Grade V = high-velocity thrust (manipulation, typically outside PTA scope). Grade III uses rhythmic motion at end range to stretch the capsule and improve mobility.", difficulty: 3, category: "Therapeutic Intervention", topic: "Musculoskeletal Interventions" },
  { id: "pta-463", stem: "A PTA is treating a patient with a complete L1 spinal cord injury. Which functional outcome would be MOST realistic for this patient?", options: ["Independent wheelchair mobility, independent self-care, and potential for household ambulation with bilateral KAFOs and forearm crutches","Independent community ambulation without assistive devices","Full return to running and sports activities","Complete independence in all activities without any adaptive equipment"], correctIndex: 0, rationale: "A complete L1 SCI results in paralysis below L1, affecting hip flexors (partially), knee extensors, ankle muscles, and trunk muscles. Functional outcomes include: independent wheelchair mobility (primary mode of transportation), independent self-care (upper extremity function preserved), and potential for limited ambulation with bilateral KAFOs (to stabilize knees and ankles) and forearm crutches (for balance and upper extremity weight-bearing). Community ambulation and running are unrealistic. Some adaptive equipment is typically necessary for specific activities.", difficulty: 2, category: "Patient Care Planning", topic: "Neurological Rehabilitation" },
  { id: "pta-464", stem: "A PTA is using a mechanical cervical traction unit for a patient with cervical radiculopathy. Which patient position BEST opens the intervertebral foramina?", options: ["Supine with the cervical spine in slight flexion (approximately 20-30 degrees)","Seated upright with the neck in full extension","Supine with the neck in neutral position","Prone with the head turned to one side"], correctIndex: 0, rationale: "Cervical traction for radiculopathy aims to decompress nerve roots by opening the intervertebral foramina. Slight cervical flexion (20-30 degrees) widens the foramina and opens the posterior disc space, maximizing nerve root decompression. Supine positioning allows relaxation of the cervical musculature. Full extension narrows the foramina and can worsen nerve compression. Neutral position provides some opening but less than slight flexion. Prone with rotation can exacerbate cervical radiculopathy symptoms.", difficulty: 2, category: "Therapeutic Intervention", topic: "Musculoskeletal Interventions" },
  { id: "pta-465", stem: "A PTA is instructing a patient in the use of a TENS unit for chronic low back pain management at home. Which instruction is MOST important for safe home use?", options: ["Never place electrodes over the carotid sinus, anterior neck, or directly over the spinal cord; remove during bathing and sleeping","Use the TENS unit 24 hours a day without interruption for maximum benefit","Place electrodes directly over the eyes if facial pain occurs","Increase the intensity until visible muscle contractions occur for all conditions"], correctIndex: 0, rationale: "TENS safety education must include electrode placement precautions: the carotid sinus (risk of hypotension and bradycardia), anterior neck (risk of laryngospasm or pharyngeal muscle spasm), and over the spinal cord (risk of affecting autonomic function). Removing during bathing prevents electrical shock; removing during sleep prevents skin irritation and unmonitored use. Continuous 24-hour use can cause skin irritation. Electrodes near the eyes can affect vision. Visible muscle contractions indicate NMES intensity, which is not the goal of conventional TENS for pain.", difficulty: 2, category: "Patient Care Planning", topic: "Physical Agents & Modalities" },
  { id: "pta-466", stem: "A PTA is treating a 70-year-old patient who ambulates independently but demonstrates a steppage gait pattern on the left side, clearing the foot by excessively flexing the hip and knee during swing phase. Which condition is MOST likely causing this gait pattern?", options: ["Left common peroneal nerve palsy causing foot drop (weakness of ankle dorsiflexors)","Left hip flexor contracture","Right ankle sprain","Bilateral knee osteoarthritis"], correctIndex: 0, rationale: "Steppage gait is characterized by excessive hip and knee flexion during swing phase to clear the foot from the ground. This pattern occurs when ankle dorsiflexors (tibialis anterior, extensor digitorum longus) are weak or paralyzed, preventing the foot from clearing the ground with normal swing mechanics. Common peroneal nerve palsy is the most common cause of foot drop. Hip flexor contracture causes different gait deviations (increased lordosis, shortened step). Ankle sprain and knee OA produce antalgic gait patterns, not steppage gait.", difficulty: 2, category: "Clinical Scenarios", topic: "Gait Training & Balance" },
  { id: "pta-467", stem: "A PTA is treating a patient with a diagnosis of piriformis syndrome. The patient reports pain in the buttock radiating down the posterior thigh. Which test is MOST specific for this condition?", options: ["FAIR test (Flexion, Adduction, Internal Rotation of the hip) which stretches the piriformis and compresses the sciatic nerve","Straight leg raise test at 70 degrees","Thomas test for hip flexor tightness","Ober test for iliotibial band tightness"], correctIndex: 0, rationale: "The FAIR test specifically targets the piriformis muscle by placing it on stretch (hip flexion, adduction, and internal rotation) while the patient is side-lying. This position compresses the sciatic nerve under the taut piriformis muscle, reproducing the patient's symptoms. A positive test suggests piriformis involvement in the sciatic symptoms. Straight leg raise tests lumbar disc pathology. Thomas test assesses hip flexor length. Ober test evaluates ITB flexibility. None of these specifically assess the piriformis-sciatic nerve relationship.", difficulty: 2, category: "Clinical Scenarios", topic: "Musculoskeletal Interventions" },
  { id: "pta-468", stem: "A PTA is treating a patient recovering from a stroke who demonstrates shoulder subluxation on the affected side. During treatment, the PTA should:", options: ["Support the affected arm during all position changes and activities, and avoid any traction or pulling on the affected shoulder","Perform aggressive overhead pulley exercises to strengthen the shoulder","Apply traction to the affected arm during mat activities","Allow the affected arm to hang freely during all activities"], correctIndex: 0, rationale: "Shoulder subluxation post-stroke occurs when the rotator cuff and deltoid muscles are flaccid, allowing the humeral head to drop inferiorly out of the glenoid fossa. The subluxed shoulder is vulnerable to further injury. The arm must be supported during transfers, position changes, and activities to prevent stretching of the joint capsule and neurovascular structures. Overhead pulleys can worsen subluxation and cause impingement. Traction on a subluxed shoulder risks injury. Allowing the arm to hang freely increases the subluxation and may cause brachial plexus traction injury.", difficulty: 2, category: "Safety", topic: "Neurological Rehabilitation" },
  { id: "pta-469", stem: "A PTA is performing wound measurements on a healing pressure ulcer to track progress. Wound measurements should be taken consistently using which method?", options: ["Measure length (head-to-toe direction), width (side-to-side), and depth using the clock method with 12 o'clock toward the patient's head","Estimate wound size visually without any measurement tools","Measure only the longest dimension of the wound","Use a different measurement orientation each visit depending on wound shape"], correctIndex: 0, rationale: "Consistent wound measurement is essential for tracking healing progress. The standard method uses the clock orientation: 12 o'clock is toward the patient's head, 6 o'clock toward the feet. Length is measured from 12 to 6 o'clock (head-to-toe). Width is measured from 3 to 9 o'clock (side-to-side) at the widest point. Depth is measured with a sterile cotton-tipped applicator at the deepest point. Consistent orientation allows reliable comparison across visits. Visual estimation is inaccurate. Single-dimension measurement misses important size data. Changing orientation makes comparisons unreliable.", difficulty: 1, category: "Clinical Scenarios", topic: "Wound Care" },
  { id: "pta-470", stem: "A PTA is working with a patient who had a total hip arthroplasty using an anterior approach. Compared to a posterolateral approach, which precautions differ?", options: ["Anterior approach precautions restrict hip extension beyond neutral, external rotation, and combined extension with adduction; posterior precautions restrict flexion beyond 90 degrees, internal rotation, and adduction","Both approaches have identical precautions","Anterior approach has no precautions at all","Posterior approach restricts only knee flexion beyond 90 degrees"], correctIndex: 0, rationale: "Surgical approach determines which structures were disrupted and thus which movements risk dislocation. The anterior approach accesses the joint through the front, disrupting anterior structures; precautions restrict movements that stress the anterior capsule (extension beyond neutral, external rotation, combined extension with adduction). The posterolateral approach disrupts posterior structures; precautions restrict posterior dislocation movements (flexion >90°, internal rotation, adduction past midline). Understanding approach-specific precautions is essential for safe rehabilitation.", difficulty: 3, category: "Safety", topic: "Musculoskeletal Interventions" },
  { id: "pta-471", stem: "A PTA is using neurodevelopmental treatment (NDT/Bobath approach) with a patient who has hemiplegia from a stroke. The patient demonstrates increased tone in the upper extremity flexor pattern. Which handling technique is MOST appropriate?", options: ["Slow, sustained weight-bearing through the affected upper extremity in an extended position to inhibit flexor tone","Quick stretching of the flexor muscles to reduce spasticity","Rapid shaking of the affected arm to normalize tone","Passive flexion of the affected arm into the pattern of spasticity"], correctIndex: 0, rationale: "NDT/Bobath approach uses specific handling techniques to normalize tone before facilitating normal movement. Slow, sustained weight-bearing through the extended upper extremity provides prolonged stretch to the flexor muscles, activating Golgi tendon organs that inhibit the stretch reflex and reduce flexor tone. The sustained nature of the input is key — quick stretches activate the stretch reflex and INCREASE spasticity. Rapid shaking provides alerting sensory input that can increase tone. Passive flexion into the spastic pattern reinforces abnormal tone.", difficulty: 3, category: "Therapeutic Intervention", topic: "Neurological Rehabilitation" },
  { id: "pta-472", stem: "A PTA is performing diaphragmatic breathing instruction for a patient post coronary artery bypass graft (CABG) surgery. The MOST important reason for this intervention is:", options: ["To prevent atelectasis and pneumonia by promoting lung expansion and secretion clearance","To reduce blood pressure through relaxation only","To strengthen the abdominal muscles for core stability","To improve digestion and appetite after surgery"], correctIndex: 0, rationale: "Post-CABG patients are at high risk for pulmonary complications including atelectasis (lung collapse) and pneumonia due to general anesthesia effects, pain limiting deep breathing, and reduced mobility. Diaphragmatic breathing promotes maximal lung expansion, improving ventilation to all lung segments and preventing alveolar collapse. It also assists in mobilizing secretions that accumulate during surgery and bed rest. While diaphragmatic breathing has relaxation benefits, the primary therapeutic goal post-CABG is pulmonary complication prevention.", difficulty: 2, category: "Clinical Scenarios", topic: "Cardiopulmonary PT" },
  { id: "pta-473", stem: "A PTA is treating a patient with a neuropathic (diabetic) foot ulcer on the plantar surface of the first metatarsal head. After wound care, which intervention is MOST critical to prevent recurrence?", options: ["Custom-molded therapeutic footwear with offloading insert to redistribute plantar pressure away from the metatarsal head","Telling the patient to walk barefoot to let the foot breathe","Standard athletic shoes without any modifications","Foot soaking in warm water twice daily to improve circulation"], correctIndex: 0, rationale: "Diabetic foot ulcers at the metatarsal heads result from excessive repetitive pressure on insensate skin. Custom-molded therapeutic footwear with offloading inserts redistributes plantar pressure, reducing peak forces on the vulnerable area. This is the single most important intervention for preventing recurrence. Walking barefoot exposes the insensate foot to injury and uncontrolled pressure. Standard shoes do not accommodate or protect the deformity. Warm water soaking can macerate skin (softening and breakdown) and risks burns in patients with absent temperature sensation.", difficulty: 2, category: "Patient Care Planning", topic: "Wound Care" },
  { id: "pta-474", stem: "A PTA is instructing a patient in self-monitoring for signs of deep vein thrombosis (DVT) following total knee arthroplasty. Which signs should the patient be instructed to report IMMEDIATELY?", options: ["Unilateral calf swelling, warmth, redness, and pain with dorsiflexion (positive Homan's sign)","Bilateral ankle swelling that decreases with elevation","Mild muscle soreness after exercise in both legs","Slight bruising around the surgical incision"], correctIndex: 0, rationale: "DVT is a serious complication following total knee arthroplasty. Warning signs include unilateral (one-sided) calf swelling (edema from obstructed venous return), warmth and redness (inflammatory response), and calf pain with dorsiflexion (Homan's sign, though not definitive, raises suspicion). Patients must report these signs immediately as DVT can progress to pulmonary embolism, which is potentially fatal. Bilateral ankle swelling is more likely positional edema. Bilateral muscle soreness after exercise is expected. Bruising near the incision is a normal surgical finding.", difficulty: 1, category: "Patient Care Planning", topic: "Patient Education" },
  { id: "pta-475", stem: "A PTA is performing a posture assessment and observes excessive thoracic kyphosis with forward head posture in a desk worker. Which muscle group is MOST likely shortened, contributing to this posture?", options: ["Pectoralis major and minor, pulling the shoulders anteriorly and reinforcing the rounded upper back","Rhomboids, retracting the scapulae posteriorly","Lower trapezius, depressing the scapulae","Cervical extensors, pulling the head into extension"], correctIndex: 0, rationale: "Forward head posture with increased thoracic kyphosis (upper crossed syndrome) involves a predictable pattern of muscle imbalances. Shortened/tight muscles include the pectoralis major and minor (pulling shoulders forward), upper trapezius, levator scapulae, and suboccipital muscles. Weak/lengthened muscles include the deep cervical flexors, lower trapezius, and rhomboids. The pectorals' shortening directly contributes to the rounded shoulder posture that drives the kyphotic position. Rhomboids and lower trapezius are typically weak in this pattern, not shortened.", difficulty: 2, category: "Clinical Scenarios", topic: "Musculoskeletal Interventions" },
  { id: "pta-476", stem: "A PTA is using aquatic therapy for a patient with fibromyalgia. The water temperature should be set at which range for OPTIMAL therapeutic benefit?", options: ["92-96°F (33-36°C) — warm enough to promote muscle relaxation and pain relief without overheating","65-70°F (18-21°C) — cold water for maximum pain numbing effect","104-110°F (40-43°C) — hot water for maximum tissue extensibility","75-80°F (24-27°C) — cool water to promote vigorous exercise"], correctIndex: 0, rationale: "For fibromyalgia, which is characterized by widespread pain, fatigue, and temperature sensitivity, water temperature of 92-96°F (33-36°C) is optimal. This thermoneutral-to-warm range promotes muscle relaxation, decreases pain perception, and improves ease of movement without causing overheating (which can exacerbate fatigue). Cold water can increase muscle guarding and pain in fibromyalgia patients. Water above 100°F can cause hypotension and excessive fatigue. Cool water is appropriate for vigorous exercise but not for pain-dominant conditions.", difficulty: 2, category: "Therapeutic Intervention", topic: "Physical Agents & Modalities" },
  { id: "pta-477", stem: "A PTA is treating a patient with Bell's palsy affecting the right side of the face. The patient has difficulty closing the right eye. Which safety concern should the PTA address with the patient?", options: ["Corneal drying and potential ulceration due to incomplete eye closure; recommend artificial tears and protective eye patch at night","Risk of jaw dislocation from facial weakness","Hearing loss on the affected side","Difficulty swallowing requiring a modified diet"], correctIndex: 0, rationale: "Bell's palsy (CN VII) causes paralysis of the facial muscles including the orbicularis oculi, which closes the eyelid. Inability to close the eye fully leads to corneal exposure, drying, and potential corneal ulceration, which can permanently damage vision. Artificial tears (during the day) and an eye patch (at night) protect the cornea. Jaw dislocation is not associated with facial nerve palsy. While Bell's palsy can occasionally cause hyperacusis, hearing loss is not the primary safety concern. Difficulty swallowing may occur but corneal protection takes priority.", difficulty: 2, category: "Safety", topic: "Neurological Rehabilitation" },
  { id: "pta-478", stem: "A PTA is assessing a patient's functional mobility and wants to use a standardized test that measures timed performance of functional tasks including sit-to-stand, walking, and turning. Which assessment tool is MOST appropriate?", options: ["Timed Up and Go (TUG) test, which measures time to stand from a chair, walk 3 meters, turn, walk back, and sit down","Manual muscle testing of lower extremity muscles","Goniometric measurement of lower extremity ROM","Visual analog scale for pain assessment"], correctIndex: 0, rationale: "The Timed Up and Go (TUG) test is a reliable, validated functional mobility assessment that measures the time to complete: rising from a standard arm chair, walking 3 meters, turning around, walking back, and sitting down. It incorporates sit-to-stand transitions, walking, and turning in a single timed test, making it efficient for measuring functional mobility and fall risk. Scores >12 seconds suggest increased fall risk. MMT and goniometry measure impairment-level constructs, not function. VAS measures pain only.", difficulty: 1, category: "Clinical Scenarios", topic: "Data Collection & Documentation" },
  { id: "pta-479", stem: "A PTA is educating a patient who takes warfarin (Coumadin) about exercise precautions. Which information is MOST important to provide?", options: ["Avoid activities with high risk of contact, collision, or falling that could cause internal bleeding, and report unusual bruising or prolonged bleeding","There are no exercise precautions with warfarin","Only aerobic exercise is safe; all resistance training must be avoided","Exercise should be performed only immediately before taking the medication"], correctIndex: 0, rationale: "Warfarin is an anticoagulant that reduces blood clotting. Patients on warfarin are at increased risk for bleeding, including internal bleeding from trauma. Exercise precautions include avoiding contact sports, high-impact activities, and exercises with significant fall risk (which could cause intracranial hemorrhage or internal bleeding). Patients should report unusual bruising, prolonged bleeding from cuts, or bloody urine/stool. Exercise is beneficial but must be modified for safety. Resistance training is generally safe with proper technique. Exercise timing relative to medication is not a relevant concern.", difficulty: 1, category: "Patient Care Planning", topic: "Patient Education" },
  { id: "pta-480", stem: "A PTA is applying moist hot pack treatment to a patient's low back. After 5 minutes, the patient reports that the heat feels 'very hot' but not painful. The PTA should:", options: ["Add additional layers of toweling between the hot pack and skin and check the skin for redness or mottling","Remove the hot pack immediately and discontinue all heat treatments","Ignore the report since the patient did not say it was painful","Reduce the treatment time to 2 minutes total"], correctIndex: 0, rationale: "A report of 'very hot' during hot pack application indicates the heat may be too intense and risks tissue damage. The PTA should add additional toweling layers to increase insulation between the pack and skin, then check the skin for signs of excessive heat (redness, mottling, blotching). This maintains the therapeutic benefit while reducing burn risk. Complete removal and discontinuation is excessive if temperature can be modulated. Ignoring the report risks burns. Reducing time to 2 minutes does not achieve therapeutic tissue temperature changes.", difficulty: 1, category: "Safety", topic: "Physical Agents & Modalities" },
  { id: "pta-481", stem: "A PTA is treating a patient with plantar fasciitis. The evidence suggests which stretching approach is MOST effective for this condition?", options: ["Sustained stretching of the plantar fascia and gastrocnemius-soleus complex, particularly the plantar fascia-specific stretch (toes in extension) before first steps in the morning","Ballistic bouncing stretches of the calf muscles only during exercise","Stretching only the quadriceps and hamstrings","Avoiding all stretching until the pain resolves completely"], correctIndex: 0, rationale: "Evidence-based treatment for plantar fasciitis includes sustained stretching of both the plantar fascia and the gastrocnemius-soleus complex. The plantar fascia-specific stretch (crossing the affected foot over the contralateral knee and pulling the toes into extension) has been shown to be particularly effective. Performing this stretch before the first steps in the morning addresses the characteristic 'first-step pain' caused by overnight fascia contracture. Ballistic stretching is less effective and risks micro-tears. Quadriceps and hamstrings are not directly involved. Avoiding stretching prolongs the condition.", difficulty: 2, category: "Therapeutic Intervention", topic: "Musculoskeletal Interventions" },
  { id: "pta-482", stem: "A PTA is performing manual lymphatic drainage (MLD) for a patient with upper extremity lymphedema following mastectomy with axillary lymph node dissection. The massage strokes should be directed:", options: ["From distal to proximal, starting at the trunk to open proximal pathways first, then moving distally before directing fluid centrally","From proximal to distal in rapid, deep strokes","In random directions with firm kneading pressure","Only over the affected arm without addressing the trunk"], correctIndex: 0, rationale: "Manual lymphatic drainage for post-mastectomy lymphedema follows a specific sequence: first, proximal lymphatic pathways are opened by working on the trunk and unaffected side, creating space for fluid to drain into. Then, gentle rhythmic strokes move from distal to proximal on the affected limb, directing fluid through collateral lymphatic pathways toward functioning lymph nodes. Deep pressure collapses fragile lymphatic vessels. Random or deep massage is counterproductive. Working only on the arm without opening proximal pathways creates a 'traffic jam' with nowhere for the fluid to drain.", difficulty: 3, category: "Therapeutic Intervention", topic: "Wound Care" },
  { id: "pta-483", stem: "A PTA is working with a pediatric patient who has Duchenne muscular dystrophy. The child currently uses a Gowers' maneuver to rise from the floor. This sign indicates weakness of which muscle groups?", options: ["Hip extensors (gluteals) and knee extensors (quadriceps), requiring the child to use the arms to 'walk up' the thighs for support during standing","Ankle dorsiflexors only","Upper extremity muscles exclusively","Cervical flexors affecting head control"], correctIndex: 0, rationale: "Gowers' sign/maneuver is a classic clinical sign of proximal lower extremity weakness in Duchenne muscular dystrophy. The child rolls to prone, pushes to hands and knees, then 'walks' the hands up the thighs (climbing up themselves) to achieve standing. This compensatory pattern is necessary because the hip extensors (gluteals) and knee extensors (quadriceps) are too weak to extend the lower extremities against gravity directly. Gowers' sign specifically indicates proximal hip and knee extensor weakness, not distal or upper extremity weakness.", difficulty: 2, category: "Clinical Scenarios", topic: "Neurological Rehabilitation" },
  { id: "pta-484", stem: "A PTA is applying electrical stimulation for muscle re-education of the quadriceps following a total knee arthroplasty. Which electrode placement is MOST appropriate?", options: ["One electrode proximal over the vastus medialis oblique (VMO) motor point and one distal on the quadriceps muscle belly, both on the anterior thigh","Both electrodes on the posterior calf over the gastrocnemius","One electrode on the quadriceps and one on the hamstrings for co-contraction","Both electrodes over the patella directly"], correctIndex: 0, rationale: "For quadriceps re-education post-TKA, electrodes are placed along the quadriceps muscle in an orientation that promotes an effective contraction. The VMO motor point (medial aspect of the distal quadriceps) is particularly targeted because VMO inhibition is common after knee surgery and contributes to patellar tracking problems. The second electrode is placed more proximally on the quadriceps belly. This arrangement produces a visible, palpable quadriceps contraction. Posterior calf placement targets the wrong muscles. Cross-muscle placement (quad/hamstring) produces co-contraction. Electrodes on bone (patella) are ineffective.", difficulty: 2, category: "Therapeutic Intervention", topic: "Physical Agents & Modalities" },
  { id: "pta-485", stem: "A PTA is teaching a patient with a lower extremity amputation to wrap the residual limb with elastic bandage. Which wrapping technique is CORRECT?", options: ["Begin distally with figure-eight wrapping pattern, applying greatest pressure distally with decreasing pressure proximally to promote shaping and prevent edema","Begin proximally and wrap distally with even pressure throughout","Use circular wrapping only around the distal end of the residual limb","Apply maximum pressure at the proximal end to prevent swelling"], correctIndex: 0, rationale: "Residual limb wrapping serves to reduce edema, promote shaping for prosthetic fitting, and desensitize the limb. The figure-eight wrapping pattern begins distally and progresses proximally, which provides a gradient compression pattern (greatest compression distally, decreasing proximally) that promotes venous return and prevents distal edema. Starting proximally or applying maximum proximal pressure creates a tourniquet effect, trapping fluid distally. Circular wrapping can also create a tourniquet effect and does not conform well to the limb's shape.", difficulty: 2, category: "Patient Care Planning", topic: "Patient Education" },
  { id: "pta-486", stem: "A PTA is assisting a patient with a right transtibial prosthesis during gait training. The patient demonstrates an excessive lateral trunk lean to the right during the right stance phase. Which factor should the PTA assess FIRST?", options: ["Whether the prosthetic limb is too short, causing the patient to lean to maintain balance over the shorter side","Whether the patient has excessive right hip abductor strength","Whether the prosthetic foot has too much dorsiflexion","Whether the patient is leaning away from a painful left lower extremity"], correctIndex: 0, rationale: "Excessive lateral trunk lean toward the prosthetic side during stance phase is commonly caused by a prosthesis that is too short. The patient compensates by leaning the trunk laterally to keep the center of gravity over the shortened base of support. Other causes include weak hip abductors (similar to compensated Trendelenburg) or prosthetic socket discomfort. The PTA should assess prosthetic length first as it is the most common prosthetic cause. Excessive abductor strength would not cause a lean. The lean is toward the right (prosthetic) side, not away from the left.", difficulty: 2, category: "Clinical Scenarios", topic: "Gait Training & Balance" },
  { id: "pta-487", stem: "A PTA is using neuromuscular electrical stimulation (NMES) for shoulder subluxation in a patient with flaccid hemiplegia. Which muscles should be targeted?", options: ["Posterior deltoid and supraspinatus to provide upward and compressive force to reseat the humeral head","Pectoralis major and latissimus dorsi to pull the arm inward","Biceps and triceps to stabilize the elbow","Upper trapezius and sternocleidomastoid to elevate the shoulder girdle"], correctIndex: 0, rationale: "Shoulder subluxation in flaccid hemiplegia occurs when the rotator cuff muscles (especially supraspinatus) and deltoid no longer provide the compressive and upward force to keep the humeral head in the glenoid fossa. NMES targeting the posterior deltoid and supraspinatus reactivates these muscles, producing a superiorly directed force that helps reseat the humeral head. This is one of the most evidence-supported uses of NMES in stroke rehabilitation. Pectoralis and latissimus do not provide the needed upward compressive force. Elbow muscles are irrelevant. Upper trapezius elevation does not address glenohumeral stability.", difficulty: 3, category: "Therapeutic Intervention", topic: "Neurological Rehabilitation" },
  { id: "pta-488", stem: "A PTA is performing incentive spirometry instruction with a patient 1 day post abdominal surgery. The patient achieves only 500 mL on the incentive spirometer. The PTA should instruct the patient to:", options: ["Perform 10 repetitions every hour while awake, slowly inhaling to maximum capacity while using a splinting pillow over the incision for pain management","Perform the exercise once daily before bed","Exhale forcefully into the device as quickly as possible","Wait until all pain resolves before attempting incentive spirometry"], correctIndex: 0, rationale: "Incentive spirometry post abdominal surgery prevents atelectasis by promoting sustained maximal inspiration. The standard protocol is 10 repetitions every 1-2 hours during waking hours. Slow, sustained inhalation (not forced exhalation) maximizes alveolar inflation. A splinting pillow held over the incision supports the surgical site and reduces pain during deep breathing, improving the patient's ability to take deeper breaths. Once daily is insufficient frequency. The device is for inhalation, not exhalation. Waiting for pain resolution delays this critical post-operative intervention.", difficulty: 1, category: "Clinical Scenarios", topic: "Cardiopulmonary PT" },
  { id: "pta-489", stem: "A PTA is performing soft tissue mobilization on a patient's IT band. The patient is taking a daily aspirin and a blood pressure medication. Which medication consideration is MOST important for the PTA to note?", options: ["Aspirin is an antiplatelet medication that increases bruising risk; the PTA should use lighter pressure and monitor for excessive bruising","Blood pressure medication requires the PTA to avoid all manual therapy","Neither medication affects soft tissue mobilization in any way","Aspirin requires the PTA to only perform joint mobilization, not soft tissue work"], correctIndex: 0, rationale: "Aspirin inhibits platelet aggregation, which increases bleeding and bruising risk. During soft tissue mobilization, which involves sustained pressure on soft tissues, patients taking antiplatelet medications (aspirin, clopidogrel) or anticoagulants are at increased risk for excessive bruising or subcutaneous hematoma. The PTA should modify treatment intensity (lighter pressure) and monitor for adverse effects. Blood pressure medication may cause orthostatic hypotension but does not contraindicate manual therapy. Both medications have relevant considerations. Aspirin does not restrict the type of manual therapy but requires modification.", difficulty: 2, category: "Safety", topic: "Data Collection & Documentation" },
  { id: "pta-490", stem: "A PTA is treating a patient who has a history of seizures. During a treatment session, the patient begins having a tonic-clonic seizure while on a treatment mat. The PTA should:", options: ["Clear the area of any objects that could cause injury, protect the patient's head, note the time, and do NOT place anything in the patient's mouth","Insert a padded tongue depressor between the teeth to prevent tongue biting","Restrain the patient's limbs to prevent injury from convulsive movements","Immediately begin CPR"], correctIndex: 0, rationale: "During a tonic-clonic seizure, the priority is preventing injury. The PTA should clear surrounding objects, cushion the head (to prevent head injury against the mat or floor), note the time (seizures >5 minutes require emergency services), and position the patient on their side after the seizure (recovery position) to prevent aspiration. Nothing should be placed in the mouth as it risks aspiration, broken teeth, or bite injury to the helper. Restraining limbs can cause fractures. CPR is not indicated unless the patient stops breathing after the seizure ends.", difficulty: 1, category: "Safety", topic: "Safety & Body Mechanics" },
  { id: "pta-491", stem: "A PTA is implementing a strengthening program for a patient with rotator cuff tendinopathy. The patient has pain at 60-120 degrees of shoulder abduction (painful arc). Which exercise modification is MOST appropriate?", options: ["Perform strengthening exercises below 60 degrees and above 120 degrees, avoiding the painful arc, and include scapular stabilization exercises","Perform all exercises exclusively within the 60-120 degree painful arc range to desensitize","Avoid all shoulder exercises until pain resolves completely","Use maximum resistance through all ranges regardless of pain"], correctIndex: 0, rationale: "The painful arc (typically 60-120 degrees of abduction) in rotator cuff tendinopathy corresponds to the range where the supraspinatus tendon is compressed under the acromion (impingement zone). Strengthening exercises performed outside this range (below 60° and above 120°) allow muscle activation without exacerbating impingement. Scapular stabilization exercises improve the dynamic stability of the scapula, optimizing subacromial space. Exercising through the painful arc worsens impingement. Complete avoidance leads to deconditioning. Maximum resistance through pain can cause further tendon damage.", difficulty: 2, category: "Therapeutic Intervention", topic: "Therapeutic Exercise" },
  { id: "pta-492", stem: "A PTA is assessing a patient's sensation using Semmes-Weinstein monofilaments. The patient cannot feel the 5.07 (10g) monofilament on the plantar surface of the foot. This finding indicates:", options: ["Loss of protective sensation, placing the patient at significant risk for pressure ulcers and undetected injury","Normal sensation for the plantar surface of the foot","Hyperesthesia requiring desensitization treatment","Only mild sensory changes with no clinical significance"], correctIndex: 0, rationale: "The Semmes-Weinstein monofilament test is the gold standard for assessing protective sensation, particularly in diabetic patients. Inability to detect the 5.07 (10g) monofilament indicates loss of protective sensation. This means the patient cannot feel pressures that could cause tissue damage, placing them at high risk for pressure injuries, cuts, burns, and other undetected trauma to the foot. This finding triggers the need for protective footwear, daily foot inspection, and patient education about foot care. It is not normal, not hypersensitivity, and has major clinical significance.", difficulty: 2, category: "Clinical Scenarios", topic: "Data Collection & Documentation" },
  { id: "pta-493", stem: "A PTA is treating a patient who recently had a pacemaker implanted. Which physical therapy modality is ABSOLUTELY contraindicated?", options: ["Therapeutic ultrasound over the pacemaker site and diathermy (shortwave or microwave) near the device","Ice pack application to the cervical spine","Hot pack application to the lumbar spine","TENS applied to the lower extremity distal to the knee"], correctIndex: 0, rationale: "Pacemakers are electronic devices that can be affected by electromagnetic energy. Therapeutic ultrasound over the pacemaker can cause heating of the device components and lead malfunction. Diathermy (shortwave or microwave) generates electromagnetic fields that can interfere with pacemaker function, potentially causing reprogramming, inhibition of pacing, or component damage. These are absolute contraindications. Ice and hot packs are safe as they do not produce electromagnetic energy. TENS applied distally and away from the pacemaker is generally considered safe, though monitoring is prudent.", difficulty: 2, category: "Safety", topic: "Physical Agents & Modalities" },
  { id: "pta-494", stem: "A PTA is working with a patient following a median nerve repair at the wrist. At 8 weeks post-surgery, the patient demonstrates a positive Tinel's sign that has migrated 3 cm distally from the repair site since the last assessment. This finding indicates:", options: ["The nerve is regenerating and axons are advancing distally at the expected rate of approximately 1 mm per day","The nerve repair has failed and requires revision surgery","The patient has developed a new carpal tunnel syndrome","The Tinel's sign is clinically meaningless and should be ignored"], correctIndex: 0, rationale: "A distally migrating Tinel's sign is a positive clinical indicator of nerve regeneration. After nerve repair, axons regenerate at approximately 1 mm/day (1 inch/month, or about 2.5 cm/month). At 8 weeks, 3 cm of distal migration is consistent with expected regeneration rates. The Tinel's sign (tingling with percussion) marks the leading edge of regenerating axons. A non-migrating or retreating Tinel's sign would suggest poor regeneration. This finding is clinically significant and indicates the repair is progressing as expected.", difficulty: 3, category: "Clinical Scenarios", topic: "Data Collection & Documentation" },
  { id: "pta-495", stem: "A PTA is treating a patient with a confirmed diagnosis of complex regional pain syndrome (CRPS) Type I of the right hand. The hand is swollen, painful to light touch, and the skin appears shiny and cool. Which treatment approach is MOST appropriate?", options: ["Gentle active range of motion, desensitization techniques using graded tactile stimulation, stress loading (scrubbing and carrying), and edema management","Aggressive passive stretching to restore full range of motion quickly","Complete immobilization of the hand in a splint until pain resolves","Deep tissue massage directly over the painful areas"], correctIndex: 0, rationale: "CRPS Type I (reflex sympathetic dystrophy) requires a delicate treatment approach. Gentle active ROM maintains mobility without worsening pain. Desensitization uses graded tactile stimulation (progressing from tolerable to less tolerable textures) to normalize the hypersensitive nervous system. Stress loading (scrubbing and carrying) provides compressive loading that has been shown to reduce CRPS symptoms. Edema management (elevation, retrograde massage) addresses the swelling component. Aggressive stretching, immobilization, and deep massage can all worsen CRPS symptoms.", difficulty: 3, category: "Therapeutic Intervention", topic: "Musculoskeletal Interventions" },
  { id: "pta-496", stem: "A PTA is performing gait training with a patient using a standard walker. The patient reports fatigue after walking 50 feet. The PTA notes the patient is lifting the walker too high with each step. Which instruction would improve energy efficiency?", options: ["Lift the walker only 1-2 inches off the ground and set it down at a comfortable arm's length distance before stepping forward","Lift the walker as high as possible for maximum clearance","Slide the walker along the floor without lifting to save energy","Take very long steps to cover more distance with fewer walker advances"], correctIndex: 0, rationale: "Excessive walker lift height wastes energy by requiring greater shoulder and arm muscle effort with each step. Lifting only 1-2 inches provides adequate clearance while minimizing upper extremity work. Setting the walker at arm's length ensures a stable base without overreaching (which shifts the center of gravity forward and increases fall risk). Lifting too high is a common error that increases fatigue. Sliding the walker changes the gait pattern and may cause tripping. Very long steps are unstable and increase fall risk.", difficulty: 1, category: "Patient Care Planning", topic: "Gait Training & Balance" },
  { id: "pta-497", stem: "A PTA is documenting a functional outcome using the FIM (Functional Independence Measure). A patient can perform bathing with setup assistance only (someone needs to prepare supplies and draw the bath, but the patient completes all bathing independently). This corresponds to which FIM score?", options: ["5 — Supervision/Setup, indicating the patient needs only standby assistance, cueing, or setup to perform the task","7 — Complete Independence with no helper needed","3 — Moderate Assistance, indicating the patient performs 50-74% of the task","1 — Total Assistance, indicating the patient performs less than 25% of the task"], correctIndex: 0, rationale: "The FIM uses a 7-level scale: 7 = Complete Independence (timely, safely), 6 = Modified Independence (device needed), 5 = Supervision/Setup (standby, cue, or setup only), 4 = Minimal Assistance (patient does 75%+), 3 = Moderate Assistance (50-74%), 2 = Maximal Assistance (25-49%), 1 = Total Assistance (<25%). Setup assistance (preparing supplies, drawing bath) without physical help during the task itself is scored as level 5. The patient performs all bathing independently once set up is complete, so it is not complete independence (7) because a helper is needed for preparation.", difficulty: 2, category: "Clinical Scenarios", topic: "Data Collection & Documentation" },
  { id: "pta-498", stem: "A PTA is educating a patient about the proper use of a wheeled walker with a seat. The patient asks when it is safe to sit on the built-in seat. The PTA should instruct the patient to:", options: ["Lock both wheel brakes before sitting, ensure the walker is on a flat surface, and sit down slowly using the armrests for support","Sit on the seat at any time including while the walker is moving","Lean the walker against a wall before sitting to prevent it from rolling","Only sit on the seat when at home, never in public or on uneven surfaces"], correctIndex: 0, rationale: "The built-in seat on a wheeled walker is designed for rest breaks during ambulation. Safety requires locking both wheel brakes before sitting to prevent the walker from rolling. A flat, stable surface prevents tipping. Using the armrests provides controlled lowering. Sitting while the walker is moving or unlocked risks falls as the walker rolls away. Leaning against a wall is less stable than locking brakes. The seat can be used safely in any location as long as brakes are locked and the surface is stable.", difficulty: 1, category: "Safety", topic: "Patient Education" },
  { id: "pta-499", stem: "A PTA is working with a patient who has peripheral vestibular dysfunction causing vertigo and disequilibrium. The physician has referred the patient for canalith repositioning (Epley maneuver). After performing the maneuver, which instruction is MOST important?", options: ["Remain upright and avoid lying flat for 24-48 hours to prevent dislodged otoconia from returning to the semicircular canal","Perform rapid head movements immediately after to test whether the vertigo has resolved","Resume all activities including sports and driving immediately","Lie flat on the affected side for several hours to settle the crystals"], correctIndex: 0, rationale: "The Epley maneuver repositions displaced otoconia (calcium carbonate crystals) from the posterior semicircular canal back into the utricle. After the maneuver, remaining upright for 24-48 hours (including sleeping semi-reclined) allows the otoconia to settle in the utricle rather than re-entering the semicircular canal. Rapid head movements can dislodge the repositioned crystals. Immediate full activity is premature as vertigo may recur. Lying on the affected side reverses the repositioning effect.", difficulty: 2, category: "Patient Care Planning", topic: "Neurological Rehabilitation" },
  { id: "pta-500", stem: "A PTA is reviewing medications with a patient before beginning an exercise session. The patient takes metoprolol (a beta-blocker) for hypertension. Which exercise monitoring modification is MOST important?", options: ["Use the Rate of Perceived Exertion (RPE) scale rather than heart rate alone to monitor exercise intensity, as beta-blockers blunt the heart rate response to exercise","No modifications are needed; heart rate monitoring alone is sufficient","Increase the target heart rate by 20 bpm to compensate for the medication effect","Cancel the exercise session since patients on beta-blockers should not exercise"], correctIndex: 0, rationale: "Beta-blockers (metoprolol, atenolol, propranolol) reduce heart rate at rest and blunt the heart rate response to exercise by blocking beta-1 adrenergic receptors. This means heart rate is no longer a reliable indicator of exercise intensity — the patient may be working at a high intensity while the heart rate remains relatively low. The RPE scale provides a subjective but more accurate measure of exercise intensity for patients on beta-blockers. Target heart rate formulas are inaccurate. Increasing target HR is dangerous. Patients on beta-blockers can and should exercise with proper monitoring.", difficulty: 2, category: "Clinical Scenarios", topic: "Safety & Body Mechanics" }
];
